content:
{
  "plugins": [
    "@akashic/remark-preset-lint"
  ]
}

{
  "$schema": "./node_modules/nx/schemas/nx-schema.json",
  "defaultBase": "main",
  "targetDefaults": {
    "build": {
      "dependsOn": [
        "^build"
      ]
    },
    "test": {
      "dependsOn": [
        "^build"
      ]
    }
  }
}

{
  "private": true,
  "name": "@akashic/akashic-cli",
  "version": "0.0.1",
  "description": "Command-line utility for akashic game development",
  "type": "module",
  "scripts": {
    "postinstall": "npm run build",
    "build": "nx run-many -t build",
    "test": "npm run lint:md && npm run test:nx && node test/e2e.js --local",
    "test:nx": "nx run-many -t test",
    "test:published": "node test/e2e.js",
    "lint:md": "remark . --frail --no-stdout --quiet --rc-path ./.remarkrc",
    "changeset": "changeset",
    "version-packages": "changeset version",
    "release-packages": "changeset publish"
  },
  "author": "DWANGO Co., Ltd.",
  "license": "MIT",
  "repository": {
    "type": "git",
    "url": "https://github.com/akashic-games/akashic-cli.git"
  },
  "workspaces": {
    "packages": [
      "packages/*"
    ]
  },
  "overrides": {
    "vite": {
      "rollup": "npm:@rollup/wasm-node"
    }
  },
  "devDependencies": {
    "@akashic/remark-preset-lint": "^0.1.2",
    "@changesets/changelog-github": "^0.5.0",
    "@changesets/cli": "^2.27.5",
    "get-port": "^7.1.0",
    "nx": "^20.3.1",
    "ps-tree": "^1.2.0",
    "remark-cli": "^10.0.1",
    "shelljs": "^0.8.5"
  }
}

{
  "extends": [
    "github>akashic-games/renovate-config",
    "github>akashic-games/renovate-config:groupPatchMinor"
  ],
  "automerge": true,
  "packageRules": [
    {
      "matchUpdateTypes": ["minor", "major"],
      "matchPackagePatterns": ["^@akashic/"],
      "schedule": "at any time",
      "groupName": "akashic major/minor dependencies",
      "automerge": false
    },
    {
      "matchUpdateTypes": ["patch"],
      "matchPackagePatterns": ["^@akashic/"],
      "schedule": "at any time",
      "groupName": "akashic patch dependencies",
      "labels": ["release"]
    },
    {
      "matchUpdateTypes": ["major"],
      "matchDepTypes": ["devDependencies"],
      "excludePackagePatterns": ["^@akashic/"],
      "groupName": "dev dependencies",
      "automerge": false
    },
    {
      "matchUpdateTypes": ["major"],
      "matchDepTypes": ["dependencies"],
      "excludePackagePatterns": ["^@akashic/"],
      "draftPR": true
    },
    {
      "matchPackagePatterns": ["^@storybook/"],
      "enabled": false
    },
    {
      "matchFileNames": ["packages/akashic-cli-sandbox/package.json"],
      "matchPackageNames": ["@akashic/akashic-engine"],
      "allowedVersions": "<3.0"
    },
    {
      "matchFileNames": ["packages/akashic-cli-sandbox/package.json"],
      "matchPackageNames": ["commander"],
      "enabled": false
    }
  ],
  "ignorePaths": [
    "**/spec/**"
  ]
}

// akashic-cli 全体の動作確認スクリプト
//
// Usage:
//  node test/e2e.js          (latestタグでpublishされたものをインストールしてテスト)
//  node test/e2e.js --local  (このリポジトリの packages/akashic-cli/bin/akashic.js をテスト)

import { dirname, join, resolve } from "path";
import { mkdtemp, readdir, readFile, unlink, writeFile } from "fs/promises";
import { exec as _exec, spawn as _spawn } from "child_process";
import assert from "assert";
import { fileURLToPath } from "url";
import { promisify } from "util";
import { createRequire } from "module";
import { setTimeout } from "timers/promises";
import getPort from "get-port";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const require = createRequire(import.meta.url);
const exec = promisify(_exec);
const shell = require("shelljs");
const _psTree = require("ps-tree");
const psTree = promisify(_psTree);
const targetDir = await mkdtemp(`${join(__dirname, "..", "test-akashic-cli_")}`);

const testsPublished = (process.argv.slice(2)[0] !== "--local");

process.on("exit", () => {
	console.log("delete test-directory");
	shell.rm("-rf", `${targetDir}`);
});

function assertContains(actuals, expected) {
	assert.notStrictEqual(actuals.indexOf(expected), -1);
}

function assertNotContains(actuals, expected) {
	assert.strictEqual(actuals.indexOf(expected), -1);
}

async function loadJSON(path) {
	const json = await readFile(path, { encoding: "utf-8" });
	return JSON.parse(json);
}

function spawn(command, argv) {
	const proc = _spawn(command, argv, { shell: true, detached: true });
	// 動作確認用にコメントアウトだけしておく
	// proc.stdout.on("data", data => void console.log(`${data}`));
	// proc.stderr.on("data", data => void console.error(`${data}`));
	const pid = proc.pid;
	return async () => {
		const children = await psTree(pid);
		for (const child of children) {
			process.kill(child.PID);
		}
	};
}

async function checkHttp(url) {
	try {
		const res = await fetch(url);
		return res.ok;
	} catch (_error) {
		return false;
	}
}

async function createAkashicConfigJs() { 
	const options = {
		commandOptions: {
			export: {
				zip: {
					strip: true,
					bundle: true,
					force: true
				},
				html: {
					output: "output",
					bundle: true,
					force: true
				}
			}
		}
	};
	const content = `module.exports = ${JSON.stringify(options)};`;
	await writeFile("akashic.config.js", content);
}

try {
	console.log("Start test");

	// テストに使用するtmpディレクトリの作成
	console.log("create test-directory");
	shell.mkdir("-p", [`${targetDir}`, `${targetDir}/game`]);

	shell.cd(`${targetDir}`);

	// akashic-cliのインストール
	let akashicCliPath;
	if (testsPublished) {
		console.log("install @akashic/akashic-cli@latest");
		await exec("npm init -y");
		await exec("npm install @akashic/akashic-cli@latest");
		akashicCliPath = `${targetDir}/node_modules/.bin/akashic`;
	} else {
		akashicCliPath = resolve(__dirname, "..", "packages", "akashic-cli", "bin", "akashic.js");

		// workaround: Windows 環境は shebang を解釈しないのでそのままでは実行できない。
		// (npm i @akashic/akashic-cli した時は実行可能な .cmd ファイルが作られるが、ここでは存在しない)
		// 仕方がないので node をつけて node に実行させる。
		if (process.platform === "win32") {
			akashicCliPath = `node ${akashicCliPath}`;
		}

		console.log(`use ${akashicCliPath}`);
	}

	// 以下、akashic-cliの動作検証
	if (testsPublished) {
		// akashic -v で取得したバージョンがnpmにpublishされた最新バージョンと同じであることを確認
		console.log("check version of @akashic/akashic-cli");
		const { stdout: expectedVersion } = await exec("npm info @akashic/akashic-cli version");
		const { stdout: versionResult } = await exec(`${akashicCliPath} -V`);
		assert(versionResult, expectedVersion);
	} else {
		console.log("skip to check version");
	}

	// ゲームディレクトリを作成しつつakashic-cli-initのテスト
	{
		console.log("test @akashic/akashic-cli-init");
		shell.cd(`${targetDir}/game`);
		await exec(`${akashicCliPath} init --type typescript -y`);
		const files = await readdir(`${targetDir}/game`);
		assertContains(files, "audio");
		assertContains(files, "image");
		assertContains(files, "src");
		assertContains(files, "text");
		assertContains(files, "game.json");
		assertContains(files, "package.json");
		assertContains(files, "README.md");
		assertContains(files, "sandbox.config.js");
		assertContains(files, "eslint.config.mjs");
		assertContains(files, ".gitignore");
		assertContains(files, "jest.config.js");
		assertContains(files, "tsconfig.jest.json");
		assertContains(files, "tsconfig.json");
		await exec("npm install");
		await exec("npm run build");
		await exec("npm test");
		await exec("npm run lint");
	}

	// 各akashic-cli-xxxモジュールのテスト
	// TODO 出力確認
	{
		console.log("test @akashic/akashic-cli-stat");
		await exec(`${akashicCliPath} stat size`);
	}

	// TODO game.json の編集結果確認
	{
		console.log("test @akashic/akashic-cli-scan");
		await exec(`${akashicCliPath} scan asset`);
	}

	{
		console.log("test @akashic/akashic-cli-update");
		await exec(`${akashicCliPath} update`);
	}

	// TODO 出力結果検証
	{
		console.log("test @akashic/akashic-cli-export-html/zip");
		await exec(`${akashicCliPath} export html --output output --bundle`);
		await exec(`${akashicCliPath} export zip --strip --bundle --force`);
	}

	// TODO 出力結果検証
	{
		console.log("test @akashic/akashic-cli-export-html/zip with akashic.config.js");
		await createAkashicConfigJs();
		await exec(`${akashicCliPath} export html`);
		await exec(`${akashicCliPath} export zip`);
		await unlink("akashic.config.js");
	}

	try {
		console.log("test @akashic/akashic-cli-sandbox");
		// 通常の動作テスト
		{
			const port = await getPort();
			const finalize = spawn(`${akashicCliPath} sandbox`, ["-p", port, "--legacy"]);
			try {
				const baseUrl = `http://localhost:${port}`;
				await setTimeout(1000); // 起動するまで待機
				const engine = await (await fetch(`${baseUrl}/engine`)).json();
				assert.equal(engine.engine_configuration_version, "1.0");

				const gameJsonUrl = engine.content_url;
				const assetBaseUrl = engine.asset_base_url;
				const gameJson1 = await (await fetch(gameJsonUrl)).json();
				const gameJson2= await (await fetch(`${assetBaseUrl}game.json`)).json();

				assert.equal(gameJson1.width, 1280);
				assert.equal(gameJson1.height, 720);
				assert.equal(gameJson1.fps, 30);
				assert.deepEqual(gameJson1, gameJson2);
			} catch (error) {
				throw error;
			} finally {
				await finalize();
			}
		}

		// カスケードの動作テスト
		{
			// カスケード用の game.json を作成
			const cascadeGameJsonDir = `${targetDir}/cascadeGameJson`;
			shell.mkdir("-p", [cascadeGameJsonDir]);
			const cascadeGameJson = {
				width: 1920,
				height: 1080,
				fps: 60,
			};
			await writeFile(join(cascadeGameJsonDir, "game.json"), JSON.stringify(cascadeGameJson));

			const port = await getPort();
			const finalize = spawn(`${akashicCliPath} sandbox`, ["-p", port, "--cascade", cascadeGameJsonDir, "--legacy"]);
			try {
				const baseUrl = `http://localhost:${port}`;
				await setTimeout(1000); // 起動するまで待機
				const engine = await (await fetch(`${baseUrl}/engine`)).json();
				assert.equal(engine.engine_configuration_version, "1.0");

				const gameJson = await (await fetch(engine.content_url)).json();
				const gameJson1 = await (await fetch(`${baseUrl}${gameJson.definitions[0]}`)).json();
				const gameJson2 = await (await fetch(`${baseUrl}${gameJson.definitions[1]}`)).json();
				assert.equal(gameJson1.width, 1280);
				assert.equal(gameJson1.height, 720);
				assert.equal(gameJson1.fps, 30);
				assert.equal(gameJson2.width, 1920);
				assert.equal(gameJson2.height, 1080);
				assert.equal(gameJson2.fps, 60);
			} catch (error) {
				throw error;
			} finally {
				await finalize();
			}
		}
	} catch (error) {
		throw new Error(`akashic-cli-sandbox did not run successfully: ${error}`);
	}

	{
		console.log("test @akashic/akashic-cli-modify");
		await exec(`${akashicCliPath} modify width 816`);
		await exec(`${akashicCliPath} modify height 624`);
		await exec(`${akashicCliPath} modify fps 60`);
		const gameJson = await loadJSON(`${targetDir}/game/game.json`);
		assert(gameJson.width, 816);
		assert(gameJson.height, 624);
		assert(gameJson.fps, 60);
	}

	{
		console.log("test @akashic/akashic-cli-install");
		await exec(`${akashicCliPath} install @akashic-extension/akashic-label`);
		const packageJson = await loadJSON(`${targetDir}/game/package.json`);
		const gameJson = await loadJSON(`${targetDir}/game/game.json`);
		assertContains(Object.keys(packageJson["dependencies"]), "@akashic-extension/akashic-label");
		assertContains(Object.keys(gameJson["moduleMainScripts"]), "@akashic-extension/akashic-label");
		assertContains(gameJson["globalScripts"], "node_modules/@akashic-extension/akashic-label/lib/index.js");
	}

	{
		console.log("test @akashic/akashic-cli-uninstall");
		await exec(`${akashicCliPath} uninstall @akashic-extension/akashic-label`);
		const packageJson = await loadJSON(`${targetDir}/game/package.json`);
		const gameJson = await loadJSON(`${targetDir}/game/game.json`);
		if (packageJson["dependencies"]) {
			assertNotContains(Object.keys(packageJson["dependencies"]), "@akashic-extension/akashic-label");
		}
		assertContains(Object.keys(gameJson), "moduleMainScripts");
		assert.deepEqual(gameJson.moduleMainScripts, {});
		assertNotContains(gameJson["globalScripts"], "node_modules/@akashic-extension/akashic-label/lib/index.js");
	}

	console.log("Completed!");
	process.exitCode = 0;
} catch (e) {
	console.error(e);
	if (e.output) {
		console.error(e.output.toString());
	}
	console.error("Failed!");
	process.exitCode = 1;
}

// 各パッケージの依存関係のバージョンを固定するために `npm-shrinkwrap.json` を追加するスクリプト。(packages/*/ でのみ実行する想定)
// モノレポであることや、直前に akashic-cli の publish が行われた場合、akashic-cli-xxxxx が `npm i --before <date>` でエラーとなるため、下記の手順で `npm-shrinkwrap.json` を作成する。
// 1. ルートの `package.json`, `package-lock.json` をリネーム
// 2. 依存モジュールが publish 済みかポーリングして確認
// 3. ロックファイルを作成。ロックファイルが作成済みの場合はポーリングで待つ
// 4. 各パッケージの `package.json` の dependencies/devDependencies から `@akashic/xxxxx` を削除し `npm i --before <実行日の七日前>` を実行
// 5. 4 で削除した `@akashic/xxxxx` を npm インストール
// 6. `npm shrinkwarp` を実行
// 7. 1 でリネームした `package.json`, `package-lock.json` を戻し、ロックファイルを削除

import * as fs from "fs";
import * as path from "path";
import { execSync } from "child_process";

const POLLING_MAX_RETRY_COUNT = 180; // polling 最大試行回数(要調整)
const POLLING_WAIT_TIME = 10 * 1000; // ms, retry * time で 30min(要調整)
const BEFORE_DAYS = 7;

const rootPackageJsonPath = path.resolve(process.cwd(), "..", "..", "package.json");
const rootRenamePackageJsonPath = path.resolve(process.cwd(), "..", "..", "_package.json");
const rootPackageLockPath = path.resolve(process.cwd(), "..", "..", "package-lock.json");
const rootRenamePackageLockPath = path.resolve(process.cwd(), "..", "..", "_package-lock.json");
const packageJsonPath = path.resolve(process.cwd(), "package.json");
const lockFilePath = path.resolve(process.cwd(), "..", "..", "publish.lock");
const cliPackageJsonPath = path.resolve(process.cwd(), "..", "akashic-cli", "package.json");
const logsDirPath = path.resolve(process.cwd(), "..", "..", "logs_shrinkwrap");
const logs = [];

let fd; // filedescriptor
let isError = false;

/**
 * 各パッケージの package.json の dependencies/devDependencies から akashic 系を削除する
 */
function removeAkashicDependencies(pkgJsonPath) {
  const pkgJson = JSON.parse(fs.readFileSync(pkgJsonPath, "utf8"));
  const akashicDependencies = [];
  const devAkashicDependencies = [];

  if (pkgJson.dependencies) {
    for (const module of Object.keys(pkgJson.dependencies)) {
      if (/^@akashic\//.test(module)) {
        akashicDependencies.push({ name: module, ver: pkgJson.dependencies[module] });
        delete pkgJson.dependencies[module];
      }
    }
  }
  if (pkgJson.devDependencies) {
    for (const module of Object.keys(pkgJson.devDependencies)) {
      if (/^@akashic\//.test(module)) {
        devAkashicDependencies.push({ name: module, ver: pkgJson.devDependencies[module] });
        delete pkgJson.devDependencies[module];
      }
    }
  }
  fs.writeFileSync(pkgJsonPath, JSON.stringify(pkgJson, null, 2) + "\n");
  return { dependencies: akashicDependencies, devDependencies: devAkashicDependencies };
}

/**
 * 日付を "yyyy-mm-dd" 形式の文字列へ変換し返す。
 */
function formatDate(date) {
  const options = {
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  };
  const formatted = new Intl.DateTimeFormat("ja-JP", options).format(date);
  return formatted.replace(/\//g, "-");
}

/**
 * ロックファイルが作成可能となるまでポーリングする
 * ロックファイルを flag: "wx" で open() して成功ならポーリング終了、もしくは最大回数試行でエラー
 */
async function waitLockFile() {
  let count = 0;
  while (count < POLLING_MAX_RETRY_COUNT) {
    try {
      return fs.openSync(lockFilePath, "wx");
    } catch (_error) {
      if (count < POLLING_MAX_RETRY_COUNT) {
        count++;
        await new Promise(resolve => setTimeout(resolve, POLLING_WAIT_TIME));
      }
    }
  }
  throw new Error("waitLockFile(): The maximum number of times has been reached.");
}

/**
 * npm view で指定したパッケージのバージョンが取得できるまでポーリングする
 */
async function waitPublish(pkgName, version) {
  let count = 0;
  const npmViewCmd = `npm view ${pkgName}@${version}`;
  logs.push(`- exec: "${npmViewCmd}"`);

  while (count < POLLING_MAX_RETRY_COUNT) {
    try {
      execSync(npmViewCmd);
      return true;

    } catch (_error) {
      if (count < POLLING_MAX_RETRY_COUNT) {
        count++;
        await new Promise(resolve => setTimeout(resolve, POLLING_WAIT_TIME));
      }
    }
  }
  throw new Error("waitPublish(): The maximum number of times has been reached.");
}

/**
 * akashic-cli 以外の各 package 配下に shrinkwrap.json を生成する。
 */
async function generateShrinkwrapJson() {
  let pkgName = "";

  try {
    const pkgJson = JSON.parse(fs.readFileSync(packageJsonPath, "utf-8"));
    pkgName = pkgJson.name;
    logs.push(`--------------- ${pkgName} generateShrinkwrapJson start ---`);

    // バージョン取得用
    const cliPkgJson = JSON.parse(fs.readFileSync(cliPackageJsonPath, "utf-8"));
    // 依存モジュールが publish 済みかポーリングして確認
    // TODO: 以下の各 packages の waitPublish() を removeAkashicDependencies().dependencies から /^@akashic\/akashic-cli-/ にマッチするものを待つようにする
    if (pkgName !== "@akashic/akashic-cli-commons") {
      // commons 依存
      const version = cliPkgJson.dependencies["@akashic/akashic-cli-commons"];
      await waitPublish("@akashic/akashic-cli-commons", version);
    }
    if (pkgName === "@akashic/akashic-cli-export") {
      // extra 依存
      const version = cliPkgJson.dependencies["@akashic/akashic-cli-extra"];
      await waitPublish("@akashic/akashic-cli-extra", version);
    }
    if (pkgName === "@akashic/akashic-cli-serve") {
      // scan 依存: [serve]
      const version = cliPkgJson.dependencies["@akashic/akashic-cli-scan"];
      await waitPublish("@akashic/akashic-cli-scan", version);
    }
    if (pkgName === "@akashic/akashic-cli-init") {
      // extra 依存: [init]
      const version = cliPkgJson.dependencies["@akashic/akashic-cli-extra"];
      await waitPublish("@akashic/akashic-cli-extra", version);
    }

    fd = await waitLockFile();

    // モノレポの制御を外すため package.json, package-lock.json をリネーム
    fs.renameSync(rootPackageJsonPath, rootRenamePackageJsonPath);
    fs.renameSync(rootPackageLockPath, rootRenamePackageLockPath);

    const dt = new Date();
    dt.setDate(dt.getDate() - BEFORE_DAYS);
    const formattedDate = formatDate(dt);
    // akashic-cli-xxxxx は publish 日付が直前の可能性があり、--before <date> で引っかかるため package.json から削除し後でインストールする
    const akashicModules = removeAkashicDependencies(packageJsonPath);

    if (pkgName == "@akashic/akashic-cli-serve") {
      // serve で @akashic 系を削除してインストールした場合、`npm run setup` の処理で落ちる。環境変数の値を設定し処理をスキップさせる。 
      process.env.SKIP_SETUP = true;
    }

    const npmInstallCmd = `npm i --before ${formattedDate}`;
    logs.push(`- exec: "${npmInstallCmd}"`);
    let cmdResult = execSync(npmInstallCmd, { encoding: "utf8" });
    logs.push(cmdResult);


    if (akashicModules.dependencies.length) {
      const installList = [];
      for (const module of akashicModules.dependencies) {
        const target = `${module.name}@${module.ver}`;
        installList.push(target);
      }
      const akashicInstallCmd = `npm i --save-exact ${installList.join(" ")}`;
      logs.push(`- exec: "${akashicInstallCmd}"`);
      cmdResult = execSync(akashicInstallCmd, { encoding: "utf8" });
      logs.push(cmdResult);
    }

    if (akashicModules.devDependencies.length) {
      const installList = [];
      for (const module of akashicModules.devDependencies) {
        const target = `${module.name}@${module.ver}`;
        installList.push(target);
      }
      const akashicInstallCmd = `npm i --save-dev --save-exact ${installList.join(" ")}`;
      logs.push(`- exec: "${akashicInstallCmd}"`);
      cmdResult = execSync(akashicInstallCmd, { encoding: "utf8" });
      logs.push(cmdResult);
    }

    const npmShrinkwrapCmd = "npm shrinkwrap";
    logs.push(`- exec: "${npmShrinkwrapCmd}"`);
    cmdResult = execSync(npmShrinkwrapCmd, { encoding: "utf8" });
    logs.push(cmdResult);

  } catch (err) {
    logs.push("--- Error:", err);
    isError = true;
  } finally {
    if (fs.existsSync(rootRenamePackageJsonPath)) fs.renameSync(rootRenamePackageJsonPath, rootPackageJsonPath);
    if (fs.existsSync(rootRenamePackageLockPath)) fs.renameSync(rootRenamePackageLockPath, rootPackageLockPath);

    logs.push(`------------ ${pkgName}  end ------------`);
    if (isError) {
      if (!fs.existsSync(logsDirPath)) fs.mkdirSync(logsDirPath);
      const fileName = pkgName.replaceAll("/", "_");
      fs.writeFileSync(`${logsDirPath}/${fileName}.log`, logs.join("\n"), "utf-8");
    }
  }
}

process.on("beforeExit", () => {
  if (fd != null) {
    fs.closeSync(fd);
    fs.rmSync(lockFilePath);
  }
  if (isError) process.exit(1);
});

generateShrinkwrapJson();

