import { createRequire } from "module";
import * as path from "path";
import { serverGlobalConfig } from "../common/ServerGlobalConfig.js";
import type { EngineFilesVersions } from "./EngineFilesVersions.js";
import * as gameConfigs from "./GameConfigs.js";

const require = createRequire(import.meta.url);

export interface EngineConfig {
	engine_urls: string[];
	content_url: string;
	asset_base_url?: string;
	untrusted?: boolean;
	external?: string[];
	content_id?: string;
}

export interface GetEngineConfigParameterObject {
	baseUrl: string;
	contentId: number;
	baseDir: string;
	isRaw: boolean;
}

export const getEngineConfig = (param: GetEngineConfigParameterObject): EngineConfig => {
	const untrusted = serverGlobalConfig.untrusted;
	const gameContentDir = (param.isRaw || untrusted) ? "raw" : "content";
	const gameJson = gameConfigs.get(param.contentId.toString());
	let version = "1";
	let external: string[] = [];
	if (gameJson.environment != null) {
		if (gameJson.environment["sandbox-runtime"] != null) {
			version = gameJson.environment["sandbox-runtime"];
		}
		if (gameJson.environment.external != null) {
			external = Object.keys(gameJson.environment.external);
		}
	}
	const versionsJson: EngineFilesVersions = require("../engineFilesVersion.json");

	if (process.env.ENGINE_FILES_V3_PATH) {
		versionsJson.v3.fileName = path.basename(process.env.ENGINE_FILES_V3_PATH);
	}

	const engineUrls = [
		`${param.baseUrl}/public/external/${versionsJson[`v${version}`].fileName}`
	];

	if (param.isRaw && process.env.PLAYLOG_CLIENT_PATH) {
		engineUrls.push(`${param.baseUrl}/dynamic/${path.basename(process.env.PLAYLOG_CLIENT_PATH)}`);
		engineUrls.push(`${param.baseUrl}/socket.io/socket.io.js`); // playlogclientがsocket.ioを利用する想定なので追加しておく
	} else {
		engineUrls.push(`${param.baseUrl}/public/external/playlogClientV3_2_1.js`);
	}

	return {
		engine_urls: engineUrls,
		untrusted,
		external,
		content_url: `${param.baseUrl}/contents/${param.contentId}/${gameContentDir}/game.json`,
		asset_base_url: `${param.baseUrl}/contents/${param.contentId}/${gameContentDir}`,
		content_id: "" + param.contentId // TODO コンテンツごとに違う ID にすべき
	};
};

export interface EngineFilesVersions {
	[majorVer: string]: {
		version: string;
		fileName: string;
	};
}

import * as fs from "fs";
import * as path from "path";
import type { GameConfiguration } from "@akashic/game-configuration";
import * as chokidar from "chokidar";

const configs: { [key: string]: GameConfiguration } = {};

export const enum ModTargetFlags {
	None = 0x0,
	GameJson = 0x1,
	Assets = 0x2
}

/**
 * コンテンツの game.json  ファイルの読み込み/監視を登録。
 *
 * @param contentId コンテンツID
 * @param targetDir game.json が存在するディレクトリパス
 */
export function register(contentId: string, targetDir: string): void {
	const gameJsonPath = path.join(targetDir, "game.json");
	if (configs[contentId]) return;
	configs[contentId] = watchGameJson(gameJsonPath, config => configs[contentId] = config);
}

/**
 * コンテンツIDに紐づく game.json の取得
 *
 * @param contentId コンテンツID
 */
export function get(contentId: string): GameConfiguration {
	return configs[contentId];
}

export interface FSWatcherLike {
	on(ev: "add" | "unlink" | "change", handler: (path: string) => Promise<void>): void;
	debugNotifyPromise?(p: Promise<void>): void;
}

export async function watchContent(
	targetDir: string,
	cb: (err: any, modTargetFlag: ModTargetFlags) => void,
	watcher?: FSWatcherLike
): Promise<void> {
	watcher ??= chokidar.watch(targetDir, {
		persistent: true,
		ignoreInitial: true,
		ignored: "**/node_modules/**/*"
	});

	// akashic-cli-scanはwatchオプション指定時しか使われないので動的importする
	const scan = await import("@akashic/akashic-cli-scan/lib/scanAsset.js");

	targetDir = path.resolve(targetDir); // 相対パスで監視すると chokidar の通知してくるパスがおかしい場合があるようなのですべて絶対パスで扱う
	const assetDirs = ["assets", "audio", "image", "script", "text"].map(d => path.join(targetDir, d) + path.sep);
	const gameJsonPath = path.join(targetDir, "game.json");

	let suppressedGameJson = false;
	let suppressedScan = false;
	const watcherHandler = async (filePath: string): Promise<void> => {
		filePath = path.resolve(filePath);

		if (!suppressedScan && assetDirs.some(assetDir => filePath.startsWith(assetDir))) {
			// scanAsset() によって起こる game.json の変更を通知すると二重になってしまうので、500ms だけ無視するように。時間は仮。
			// (game.json の変更は scanAsset() 中に完了するが、それを chokidar が検出するタイミングには保証がない。
			// すなわち suppressedGameJson は suppressedScan では代用できない点に注意)
			suppressedGameJson = true;
			setTimeout(() => {
				suppressedGameJson = false;
			}, 500);

			try {
				suppressedScan = true; // scanAsset() 中に再帰的に scan しないよう抑制。
				const p = scan.scanAsset({ target: "all", cwd: targetDir });
				watcher.debugNotifyPromise?.(p);
				await p;
			} finally {
				suppressedScan = false;
			}
			cb(null, ModTargetFlags.Assets);
			return;
		}

		if (!suppressedGameJson && filePath === gameJsonPath) {
			cb(null, ModTargetFlags.GameJson);
			return;
		}
	};

	watcher.on("add", watcherHandler);
	watcher.on("unlink", watcherHandler);
	watcher.on("change", watcherHandler);
}

function watchGameJson(gameJsonPath: string, callback: (gameJson: GameConfiguration) => void): GameConfiguration {
	let gameJson: any = JSON.parse(fs.readFileSync(gameJsonPath).toString());

	const changeEventListener = (event: string, path: string): void => {
		if ( event === "change") {
			gameJson = JSON.parse(fs.readFileSync(path).toString());
			callback(gameJson);
		}
	};
	const watcher = chokidar.watch(gameJsonPath, { persistent: true });
	watcher.on("change", changeEventListener);

	return gameJson;
}

import { PromisifiedAMFlowProxy } from "@akashic/amflow-util/lib/PromisifiedAMFlowProxy.js";
import type { AMFlowClient, Play, PlayManager } from "@akashic/headless-driver";
import * as pl from "@akashic/playlog";
import { Trigger } from "@akashic/trigger";
import { calculatePlayDuration } from "../../common/playlogUtil.js";
import { TimeKeeper } from "../../common/TimeKeeper.js";
import type { DumpedPlaylog } from "../../common/types/DumpedPlaylog.js";
import type { PlayAudioState } from "../../common/types/PlayAudioState.js";
import type { Player } from "../../common/types/Player.js";
import type { PlayInfo } from "../../common/types/PlayInfo.js";
import type { PlayStatus } from "../../common/types/PlayStatus.js";
import type {
	PlayCreateTestbedEvent,
	PlayStatusChangedTestbedEvent,
	PlayDurationStateChangeTestbedEvent,
	PlayerJoinTestbedEvent,
	PlayerLeaveTestbedEvent,
	RunnerCreateTestbedEvent,
	RunnerRemoveTestbedEvent,
	ClientInstanceAppearTestbedEvent,
	ClientInstanceDisappearTestbedEvent,
	RunnerDescription,
	ClientInstanceDescription,
	PlayAudioStateChangeTestbedEvent
} from "../../common/types/TestbedEvent.js";
import type { ServerContentLocator } from "../common/ServerContentLocator.js";
import { activePermission, passivePermission, debugPermission } from "./AMFlowPermisson.js";

export interface PlayStoreParameterObject {
	playManager: PlayManager;
}

export interface CreatePlayParameterObject {
	/**
	 * 実行するコンテンツ。
	 */
	contentLocator: ServerContentLocator;

	/**
	 * 流し込むプレイログ。
	 * 指定した場合、このプレイに active instance を生成してはならない。
	 */
	playlog?: DumpedPlaylog;

	/**
	 * 初期 join プレイヤー。
	 */
	initialJoinPlayer?: Player;

	/**
	 * 直前のプレイから join 済みプレイヤー情報を引き継ぐか。
	 */
	inheritsJoinedFromLatest?: boolean;

	/**
	 * 直前のプレイから PlayAudioState を引き継ぐか。
	 */
	inheritsAudioFromLatest?: boolean;
}

/**
 * プレイ関連情報。特に headless-driver の Play では賄えない情報を補うデータ。
 */
// TODO headless-driver の Play の利用をやめるか、隠蔽してこれと統合する
export interface PlayEntity {
	/**
	 * プレイのステータス。
	 * headless-driver の Play にも同名のデータがあるが、
	 * serve ではプッシュ通知のために変更されるタイミングを完全に把握する必要があり、ここに自前で持つ。
	 */
	status: PlayStatus;

	contentLocator: ServerContentLocator;
	timeKeeper: TimeKeeper;
	clientInstances: ClientInstanceDescription[];
	runners: RunnerDescription[];
	joinedPlayers: Player[];
	audioState: PlayAudioState;
	debugAMFlow: AMFlowClient | null;
}

export class PlayStore {
	onPlayCreate: Trigger<PlayCreateTestbedEvent>;
	onPlayStatusChange: Trigger<PlayStatusChangedTestbedEvent>;
	onPlayDurationStateChange: Trigger<PlayDurationStateChangeTestbedEvent>;
	onPlayAudioStateChange: Trigger<PlayAudioStateChangeTestbedEvent>;
	onPlayerJoin: Trigger<PlayerJoinTestbedEvent>;
	onPlayerLeave: Trigger<PlayerLeaveTestbedEvent>;
	onClientInstanceAppear: Trigger<ClientInstanceAppearTestbedEvent>;
	onClientInstanceDisappear: Trigger<ClientInstanceDisappearTestbedEvent>;

	private playManager: PlayManager;

	// TODO playId ごとの情報を集約して PlayEntity を作る
	private playEntities: { [playId: string]: PlayEntity };

	constructor(params: PlayStoreParameterObject) {
		this.onPlayCreate = new Trigger<PlayCreateTestbedEvent>();
		this.onPlayStatusChange = new Trigger<PlayStatusChangedTestbedEvent>();
		this.onPlayDurationStateChange = new Trigger<PlayDurationStateChangeTestbedEvent>();
		this.onPlayAudioStateChange = new Trigger<PlayAudioStateChangeTestbedEvent>();
		this.onPlayerJoin = new Trigger<PlayerJoinTestbedEvent>();
		this.onPlayerLeave = new Trigger<PlayerLeaveTestbedEvent>();
		this.onClientInstanceAppear = new Trigger<ClientInstanceAppearTestbedEvent>();
		this.onClientInstanceDisappear = new Trigger<ClientInstanceDisappearTestbedEvent>();
		this.playManager = params.playManager;
		this.playEntities = {};
	}

	/**
	 * Playを生成するが、返すものはPlayId
	 */
	async createPlay(params: CreatePlayParameterObject): Promise<string> {
		const { contentLocator: loc, playlog, initialJoinPlayer, inheritsJoinedFromLatest, inheritsAudioFromLatest } = params;
		const latestPlay = this.getLatestPlayInfo();
		const audioState: PlayAudioState = (latestPlay && inheritsAudioFromLatest) ? { ...latestPlay.audioState } : { muteType: "none" };
		const joinedPlayers = (latestPlay && inheritsJoinedFromLatest) ? latestPlay.joinedPlayers.concat() : [];
		if (initialJoinPlayer)
			joinedPlayers.push(initialJoinPlayer);

		const playId = await this.playManager.createPlay({ contentUrl: loc.asAbsoluteUrl() }, playlog, { preservesUnhandledEvents: true });
		const status = "preparing";
		this.playEntities[playId] = {
			contentLocator: loc,
			status,
			timeKeeper: new TimeKeeper(),
			clientInstances: [],
			runners: [],
			joinedPlayers,
			audioState,
			debugAMFlow: null
		};

		if (playlog) {
			// クライアント側にdurationとしてplaylogに記録されている終了時間を渡す必要があるので、そのための設定を行う
			const timeKeeper = this.playEntities[playId].timeKeeper;
			const finishedTime = calculatePlayDuration(playlog);
			timeKeeper.setTime(finishedTime);
		}

		this.onPlayCreate.fire({playId, status, contentLocatorData: loc.asContentLocatorData(), joinedPlayers, audioState });
		this.setPlayStatus(playId, "running");

		// TODO: Join/Leave の特殊な sendEvent() をこのクラスに集約する (現状は SocketIOAMFlowManager で Join/Leave の送信をハンドリングしている)
		if (joinedPlayers.length > 0) {
			const amflow = (await this.getDebugAMFlow(playId))!;
			joinedPlayers.forEach(player => {
				amflow.sendEvent([pl.EventCode.Join, 3, player.id, player.name]);
			});
		}
		return playId;
	}

	getPlay(playId: string): Play | null {
		return this.playManager.getPlay(playId);
	}

	getPlays(): Play[] {
		return this.playManager.getAllPlays();
	}

	getLatestPlay(): Play | null {
		const plays = this.getPlays();
		return (plays.length > 0) ? plays[plays.length - 1] : null;
	}

	// プレイ関連情報を取得する。headless-driver の Play を取得する getPlay() との混同に注意。
	// TODO getPlay() の方を隠蔽する
	getPlayInfo(playId: string): PlayInfo | null {
		const play = this.getPlay(playId);
		const playEntity = this.playEntities[playId];
		if (!playEntity || !play)
			return null;
		return {
			playId,
			status: playEntity.status,
			createdAt: play.createdAt,
			lastSuspendedAt: play.lastSuspendedAt,
			contentLocatorData: playEntity.contentLocator.asContentLocatorData(),
			joinedPlayers: playEntity.joinedPlayers,
			runners: playEntity.runners,
			clientInstances: playEntity.clientInstances,
			durationState: {
				duration: playEntity.timeKeeper.now(),
				isPaused: playEntity.timeKeeper.isPausing()
			},
			audioState: playEntity.audioState
		};
	}

	getPlaysInfo(): PlayInfo[] {
		return this.getPlays().map(p => this.getPlayInfo(p.playId)!);
	}

	getLatestPlayInfo(): PlayInfo | null {
		const play = this.getLatestPlay();
		return play ? this.getPlayInfo(play.playId) : null;
	}

	getPlayIdsFromContentId(contentId: string): string[] {
		return Object.keys(this.playEntities).filter(key => contentId === this.playEntities[key].contentLocator.contentId);
	}

	async stopPlay(playId: string): Promise<void> {
		await this.playManager.deletePlay(playId);
		this.setPlayStatus(playId, "suspending");
	}

	createPlayToken(playId: string, isActive: boolean): string {
		return this.playManager.createPlayToken(playId, isActive ? activePermission : passivePermission);
	}

	createAMFlow(playId: string): AMFlowClient {
		return this.playManager.createAMFlow(playId);
	}

	/**
	 * 指定されたプレイに干渉するためのデバッグ用 AMFlow インスタンスを取得する。
	 * この AMFlow は open() され、全権限で authenticate() された状態で返される。
	 */
	async getDebugAMFlow(playId: string): Promise<AMFlowClient | null> {
		const e = this.playEntities[playId];
		if (!e)
			return null;
		if (!e.debugAMFlow) {
			const amflow = this.playManager.createAMFlow(playId);
			const token = this.playManager.createPlayToken(playId, debugPermission);
			e.debugAMFlow = amflow;
			const pamflow = new PromisifiedAMFlowProxy(amflow);
			await pamflow.open(playId);
			await pamflow.authenticate(token);
		}
		return e.debugAMFlow;
	}

	registerClientInstance(playId: string, desc: ClientInstanceDescription): void {
		this.playEntities[playId].clientInstances.push(desc);
		this.onClientInstanceAppear.fire(desc);
	}

	unregisterClientInstance(playId: string, desc: ClientInstanceDescription): void {
		this.playEntities[playId].clientInstances = this.playEntities[playId].clientInstances.filter(i => i.id !== desc.id);
		this.onClientInstanceDisappear.fire(desc);
	}

	registerRunner(param: RunnerCreateTestbedEvent): void {
		const playId = param.playId;
		this.playEntities[playId].runners.push(param);
	}

	unregisterRunner(param: RunnerRemoveTestbedEvent): void {
		const playId = param.playId;
		this.playEntities[playId].runners = this.playEntities[playId].runners.filter(i => i.runnerId !== param.runnerId);
	}

	join(playId: string, player: Player): void {
		this.playEntities[playId].joinedPlayers.push(player);
		this.onPlayerJoin.fire({playId, player});
	}

	leave(playId: string, playerId: string): void {
		this.playEntities[playId].joinedPlayers = this.playEntities[playId].joinedPlayers.filter(player => player.id !== playerId);
		this.onPlayerLeave.fire({playId, playerId});
	}

	setPlayStatus(playId: string, playStatus: PlayStatus): void {
		this.playEntities[playId].status = playStatus;
		this.onPlayStatusChange.fire({playId, playStatus});
	}

	pausePlayDuration(playId: string): void {
		this.playEntities[playId].timeKeeper.pause();
		this.onPlayDurationStateChange.fire({playId, isPaused: true});
	}

	resumePlayDuration(playId: string): void {
		const timeKeeper = this.playEntities[playId].timeKeeper;
		timeKeeper.start();
		this.onPlayDurationStateChange.fire({playId, isPaused: false, duration: timeKeeper.now()});
	}

	stepPlayDuration(playId: string): void {
		const timeKeeper = this.playEntities[playId].timeKeeper;
		this.onPlayDurationStateChange.fire({playId, isPaused: false, duration: timeKeeper.now() + 1000 / 60});
	}

	setPlayAudioState(playId: string, audioState: PlayAudioState): void {
		this.playEntities[playId].audioState = audioState;
		this.onPlayAudioStateChange.fire({playId, audioState});
	}
}

import { createHash } from "crypto";

export interface PlayerIdRegisterResult {
	/**
	 * 既に登録済みだったか。
	 */
	isDuplicated: boolean;
	/**
	 * プレイヤー ID をハッシュ化した値。
	 */
	hashedPlayerId: string;
}

export interface PlayerIdCreateResult {
	/**
	 * 生成されたプレイヤー ID 。
	 */
	playerId: string;
	/**
	 * プレイヤー ID をハッシュ化した値。
	 */
	hashedPlayerId: string;
}

export class PlayerIdStore {
	private hashedIdTable: { [playerId: string]: string };
	private knownMaxPlayerId: number; // playerId生成時に既存のものと被ることが無いようにplayerIdの中で最大値のものを記録しておく

	constructor() {
		this.hashedIdTable = {};
		this.knownMaxPlayerId = 0;
	}

	registerPlayerId(playerId: string): PlayerIdRegisterResult {
		const { hashedIdTable } = this;
		if (hashedIdTable.hasOwnProperty(playerId)) {
			return { isDuplicated: true, hashedPlayerId: hashedIdTable[playerId] };
		}

		const playerIdInt = parseInt(playerId.replace(/^pid/, ""), 10);
		// playerIdが数値を表す文字列でない場合、NaNになってこの条件に弾かれるのでknownMaxPlayerIdに代入されることはない
		if (this.knownMaxPlayerId < playerIdInt) {
			this.knownMaxPlayerId = playerIdInt;
		}

		const hashedPlayerId = md5(playerId);
		hashedIdTable[playerId] = hashedPlayerId;
		return { isDuplicated: false, hashedPlayerId };
	}

	createPlayerId(): PlayerIdCreateResult {
		this.knownMaxPlayerId++;
		const newPlayerId = "pid" + this.knownMaxPlayerId.toString();
		const hashedPlayerId = md5(newPlayerId);
		this.hashedIdTable[newPlayerId] = hashedPlayerId;
		return { playerId: newPlayerId, hashedPlayerId };
	}
}

function md5(s: string): string {
	return createHash("md5").update(s).digest("hex");
}

import { createRequire } from "module";
import * as path from "path";
import type { AMFlowClient, RunnerManager, RunnerV1, RunnerV2, RunnerV3 } from "@akashic/headless-driver";
import { Trigger } from "@akashic/trigger";
import type { NamagameCommentEventComment } from "../../common/types/NamagameCommentPlugin.js";
import type {
	RunnerCreateTestbedEvent,
	RunnerRemoveTestbedEvent,
	RunnerPauseTestbedEvent,
	RunnerResumeTestbedEvent,
	RunnerPutStartPointTestbedEvent,
	NamagameCommentPluginStartStopTestbedEvent
} from "../../common/types/TestbedEvent.js";
import { serverGlobalConfig } from "../common/ServerGlobalConfig.js";
import * as gameConfigs from "./GameConfigs.js";
import { NamagameCommentPluginHost } from "./nicoliveComment/NamagameCommentPluginHost.js";
import * as sandboxConfigs from "./SandboxConfigs.js";

const require = createRequire(import.meta.url);

export interface RunnerStoreParameterObject {
	runnerManager: RunnerManager;
	gameExternalFactory: () => any;
}

export interface CreateAndStartRunnerParameterObject {
	playId: string;
	isActive: boolean;
	token: string;
	amflow: AMFlowClient;
	contentId: string;
	isPaused: boolean;
}

/**
 * ランナー関連情報。headless-driver の Runner で管理できないデータを保持する。
 */
export interface RunnerEntity {
	playId: string;
	namagameCommentPluginHost: NamagameCommentPluginHost | null;
}

export class RunnerStore {
	onRunnerCreate: Trigger<RunnerCreateTestbedEvent>;
	onRunnerRemove: Trigger<RunnerRemoveTestbedEvent>;
	onRunnerPause: Trigger<RunnerPauseTestbedEvent>;
	onRunnerResume: Trigger<RunnerResumeTestbedEvent>;
	onRunnerPutStartPoint: Trigger<RunnerPutStartPointTestbedEvent>;
	onNamagameCommentPluginStartStop: Trigger<NamagameCommentPluginStartStopTestbedEvent>;
	private runnerManager: RunnerManager;
	private gameExternalFactory: () => any;
	private runnerEntities: { [runnerId: string]: RunnerEntity };

	constructor(params: RunnerStoreParameterObject) {
		this.onRunnerCreate = new Trigger();
		this.onRunnerRemove = new Trigger();
		this.onRunnerPause = new Trigger();
		this.onRunnerResume = new Trigger();
		this.onRunnerPutStartPoint = new Trigger();
		this.onNamagameCommentPluginStartStop = new Trigger();
		this.runnerManager = params.runnerManager;
		this.gameExternalFactory = params.gameExternalFactory;
		this.runnerEntities = {};
	}

	async createAndStartRunner(params: CreateAndStartRunnerParameterObject): Promise<RunnerV1 | RunnerV2 | RunnerV3> {
		const { playId, amflow, contentId } = params;
		const sandboxConfig = sandboxConfigs.get(contentId);
		const gameConfig = gameConfigs.get(contentId);
		const externalAssets = (sandboxConfig ? sandboxConfig.externalAssets : undefined) === undefined ? [] : sandboxConfig.externalAssets;
		const allowedUrls = this.createAllowedUrls(contentId, externalAssets);

		let externalValue: { [name: string]: unknown } = {};
		let namagameCommentPluginHost: NamagameCommentPluginHost | null = null;
		if (gameConfig.environment?.external?.namagameComment) {
			const fps = gameConfig.fps ?? 30;
			namagameCommentPluginHost = new NamagameCommentPluginHost(sandboxConfig.external?.namagameComment ?? {}, amflow, fps);
			namagameCommentPluginHost.onStartStop.add(started => this.onNamagameCommentPluginStartStop.fire({ playId, started }));
			externalValue.namagameComment = namagameCommentPluginHost.plugin;
		}

		externalValue = { ...externalValue, ...this.gameExternalFactory() };
		const serverExternal = sandboxConfig?.server?.external;
		if (serverExternal) {
			for (const pluginName of Object.keys(serverExternal)) {
				const externalSource = require(path.resolve(serverExternal[pluginName]));
				externalValue[pluginName] = externalSource();
			}
		}

		const runnerId = await this.runnerManager.createRunner({
			playId,
			amflow,
			executionMode: params.isActive ? "active" : "passive",
			playToken: params.token,
			allowedUrls,
			externalValue: externalValue,
			trusted: !serverGlobalConfig.untrusted
		});
		if (params.isActive) {
			amflow.onPutStartPoint.add((startPoint) => {
				this.onRunnerPutStartPoint.fire({ startPoint, playId });
			});
		}

		const runner = this.runnerManager.getRunner(runnerId)!;
		await this.runnerManager.startRunner(runner.runnerId, { paused: params.isPaused });
		this.runnerEntities[runnerId] = { playId, namagameCommentPluginHost };
		this.onRunnerCreate.fire({ playId, runnerId, isActive: params.isActive });
		if (params.isPaused)
			this.onRunnerPause.fire({ playId, runnerId });
		return runner;
	}

	async stopRunner(runnerId: string): Promise<void> {
		const runner = this.runnerManager.getRunner(runnerId);
		if (runner) {
			// コンテンツがエラーの場合、runnerを取得できないので取得できる場合のみ実行
			await this.runnerManager.stopRunner(runnerId);
		}
		const playId = this.runnerEntities[runnerId]!.playId;
		this.onRunnerRemove.fire({ playId, runnerId });
		delete this.runnerEntities[runnerId];
	}

	async pauseRunner(runnerId: string): Promise<void> {
		const runner = this.runnerManager.getRunner(runnerId);
		if (runner) {
			await this.runnerManager.pauseRunner(runner.runnerId);
			this.onRunnerPause.fire({ playId: runner.playId, runnerId: runnerId });
		}
	}

	async resumeRunner(runnerId: string): Promise<void> {
		const runner = this.runnerManager.getRunner(runnerId);
		if (runner) {
			await this.runnerManager.resumeRunner(runner.runnerId);
			this.onRunnerResume.fire({ playId: runner.playId, runnerId: runnerId });
		}
	}

	async stepRunner(runnerId: string): Promise<void> {
		const runner = this.runnerManager.getRunner(runnerId);
		if (runner) {
			await this.runnerManager.stepRunner(runner.runnerId);
		}
	}

	sendCommentsByTemplate(runnerId: string, name: string): boolean {
		const commentPluginHost = this.runnerEntities[runnerId]?.namagameCommentPluginHost;
		return commentPluginHost?.planToSendByTemplate(name) ?? false;
	}

	sendComment(runnerId: string, comment: NamagameCommentEventComment): boolean {
		const commentPluginHost = this.runnerEntities[runnerId]?.namagameCommentPluginHost;
		return commentPluginHost?.planToSend(comment) ?? false;
	}

	private createAllowedUrls(contentId: string, externalAssets: (string | RegExp)[] | null): (string | RegExp)[] | null {
		let allowedUrls: (string | RegExp)[] =
			[`${serverGlobalConfig.protocol}://${serverGlobalConfig.hostname}:${serverGlobalConfig.port}/contents/${contentId}/`];
		if (serverGlobalConfig.allowExternal) {
			// null は全てのアクセスを許可するため、nullが指定された場合は他の値を参照せず null を返す
			if (externalAssets === null) return null;

			allowedUrls = allowedUrls.concat(externalAssets);
			if (process.env.AKASHIC_SERVE_ALLOW_ORIGIN) {
				if (process.env.AKASHIC_SERVE_ALLOW_ORIGIN === "null") return null;
				allowedUrls.push(process.env.AKASHIC_SERVE_ALLOW_ORIGIN);
			}
		}
		return allowedUrls;
	}
}

import * as fs from "fs";
import * as path from "path";
import type { NormalizedSandboxConfiguration, SandboxConfiguration } from "@akashic/sandbox-configuration";
import * as  sandboxConfigUtils  from "@akashic/sandbox-configuration/lib/utils/index.js";
import * as chokidar from "chokidar";
import type { SandboxConfigExternalDefinition } from "../../common/types/NamagameCommentConfig.js";
import { BadRequestError, NotFoundError } from "../common/ApiError.js";
import { dynamicRequire } from "./dynamicRequire.js";

interface ResolvedSandboxConfig extends NormalizedSandboxConfiguration, SandboxConfigExternalDefinition {
	// backgroundImage がローカルファイルの場合、クライアントからは GET /contents/:contentId/sandboxConfig/backgroundImage で取得される。その場合のローカルファイルのパスをここに保持する。
	resolvedBackgroundImagePath: string | null;
}

const configs: { [key: string]: ResolvedSandboxConfig } = {};

/**
 * コンテンツの sandbox.config.js  ファイルの読み込み/監視を登録。
 *
 * @param contentId コンテンツID
 * @param configPath sandbox.config.js のファイルパス
 */
export function register(contentId: string, configPath: string): void {
	if (configs[contentId]) return;
	configs[contentId] = watchRequire(configPath, contentId, config => configs[contentId] = config);
}

/**
 * コンテンツIDに紐づく SandboxConfig の取得
 *
 * @param contentId コンテンツID
 */
export function get(contentId: string): ResolvedSandboxConfig {
	return configs[contentId];
}

function watchRequire(configPath: string, contentId: string, callback: (content: ResolvedSandboxConfig) => void): ResolvedSandboxConfig {
	let config = dynamicRequire<SandboxConfiguration>(configPath, true) ?? {};
	let resolvedConfig = normalizeConfig(config, contentId);

	const eventListener = (event: string, path: string): void => {
		if (event === "add" || event === "change") {
			config = dynamicRequire<SandboxConfiguration>(path, true) ?? {};
			resolvedConfig = normalizeConfig(config, contentId);
		} else if (event === "unlink") {
			resolvedConfig = normalizeConfig({}, contentId);
		} else {
			return;
		}
		callback(resolvedConfig);
	};
	const watcher = chokidar.watch(configPath, { persistent: true });
	watcher.on("all", eventListener);

	return resolvedConfig;
}

export function normalizeConfig(sandboxConfig: SandboxConfiguration, contentId: string): ResolvedSandboxConfig {
	const config = sandboxConfigUtils.normalize(sandboxConfig);

	const externalAssets = config.externalAssets === undefined ? [] : config.externalAssets;
	if (externalAssets) {
		// sandbox.config.js の externalAssets に値がある場合は (string|regexp)[] でなければエラーとする
		if (!(externalAssets instanceof Array)) {
			throw new BadRequestError({ errorMessage: "Invalid externalAssets, Not Array" });
		}

		if ( externalAssets.length > 0) {
			const found = externalAssets.find((url: any) => typeof url !== "string" && !(url instanceof RegExp));
			if (found) {
				throw new BadRequestError(
					{errorMessage: `Invalid externalAssets, The value is neither a string or regexp. value:${ found }` }
				);
			}
		}
	}

	const bgImage = config.displayOptions.backgroundImage;
	let resolvedBackgroundImagePath = null;
	if (bgImage) {
		if (!/\.(jpg|jpeg|png|webp)$/.test(bgImage)) {
			throw new BadRequestError({ errorMessage: "Invalid backgroundImage, Please specify a png/jpg/webp file." });
		}

		if (/^\/contents\//.test(bgImage)) {
			console.warn("Please use the local path for the value of sandboxConfig.backgroundImage");
		} else if (!/^https?:\/\//.test(bgImage)) {
			config.displayOptions.backgroundImage = `/contents/${contentId}/sandboxConfig/backgroundImage` ;
			resolvedBackgroundImagePath = bgImage;
		}
	}

	const serverExternal = config.server?.external;
	if (serverExternal) {
		for (const pluginName of Object.keys(serverExternal)) {
			const pluginPath = path.resolve(serverExternal[pluginName]);
			if (!fs.existsSync(pluginPath)) {
				throw new NotFoundError({
					errorMessage: `${pluginName} in sandboxConfig.server.external not found. path:${serverExternal[pluginName]}`
				});
			}
		}
	}

	return { ...config, resolvedBackgroundImagePath };
}

import type * as amf from "@akashic/amflow";
import { getSystemLogger } from "@akashic/headless-driver";
import * as pl from "@akashic/playlog";
import type { Socket } from "socket.io";
import type { ClientInstanceDescription } from "../../common/types/TestbedEvent.js";
import type { PlayStore } from "../domain/PlayStore.js";

export interface SocketIOAMFlowManagerParameterObject {
	playStore: PlayStore;
}

export interface Connection {
	playId: string;
	amflow: amf.AMFlow;
	socket: Socket;
	lastToken: string | null;
	emitTick: (tick: pl.Tick) => void;
	emitEvent: (ev: pl.Event) => void;
}

export class SocketIOAMFlowManager {
	private playStore: PlayStore;
	private descMap: { [token: string]: ClientInstanceDescription };
	private idCounter: number;

	private connectionMap: { [connId: string]: Connection };
	private connectionIdCounter: number;

	constructor(params: SocketIOAMFlowManagerParameterObject) {
		this.playStore = params.playStore;
		this.descMap = {};
		this.idCounter = 0;
		this.connectionMap = {};
		this.connectionIdCounter = 0;
	}

	createPlayToken(playId: string, playerId: string, name: string, isActive: boolean, envInfo: any): string {
		const token = this.playStore.createPlayToken(playId, isActive);
		const desc = { id: ++this.idCounter, playId, playerId, name, isActive, envInfo };
		this.descMap[token] = desc;
		return token;
	}

	deletePlayToken(token: string): void {
		const desc = this.descMap[token];
		if (!desc)
			return;
		this.playStore.unregisterClientInstance(desc.playId, desc);
		delete this.descMap[token];
	}

	setupSocketIOAMFlow(socket: Socket): void {
		socket.on("amflow:open", (playId: string, callback?: (e: Error | null, connectionId?: string) => void) => {
			getSystemLogger().info("a user connected. playId: " + playId);
			const amflow = this.playStore.createAMFlow(playId);
			const connId = "con" + (++this.connectionIdCounter);
			this.connectionMap[connId] = {
				playId,
				amflow,
				socket,
				lastToken: null,
				emitTick: (tick: pl.Tick) => {
					socket.emit("amflow:[tick]", connId, tick);
				},
				emitEvent: (event: pl.Event) => {
					socket.emit("amflow:[event]", connId, event);
				}
			};
			amflow.open(playId, callback ? (e => callback(e, connId)) : undefined);
		});

		socket.on(
			"amflow:authenticate",
			(connectionId: string, token: string, callback: (error: Error | null, permission: amf.Permission | undefined) => void) => {
				const conn = this.getConncetion(connectionId);
				if (!conn) {
					callback(this.makeConnectionError(connectionId), undefined);
					return;
				}
				conn.amflow.authenticate(token, (err, permission) => {
					if (err) {
						callback(err, undefined);
						return;
					}
					this.playStore.registerClientInstance(conn.playId, this.descMap[token]);
					conn.lastToken = token;
					callback(null, permission);
				});
			});

		socket.on("amflow:onTick", (connectionId: string) => {
			const conn = this.getConncetion(connectionId);
			if (!conn)
				return;
			conn.amflow.onTick(conn.emitTick);
		});

		socket.on("amflow:offTick", (connectionId: string) => {
			const conn = this.getConncetion(connectionId);
			if (!conn)
				return;
			conn.amflow.offTick(conn.emitTick);
		});

		socket.on("amflow:onEvent", (connectionId: string) => {
			const conn = this.getConncetion(connectionId);
			if (!conn)
				return;
			conn.amflow.onEvent(conn.emitEvent);
		});

		socket.on("amflow:offEvent", (connectionId: string) => {
			const conn = this.getConncetion(connectionId);
			if (!conn)
				return;
			conn.amflow.offEvent(conn.emitEvent);
		});

		socket.on("amflow:sendTick", (connectionId: string, tick: pl.Tick) => {
			const conn = this.getConncetion(connectionId);
			if (!conn)
				return;
			conn.amflow.sendTick(tick);
		});

		socket.on("amflow:sendEvent", (connectionId: string, event: pl.Event) => {
			const conn = this.getConncetion(connectionId);
			if (!conn)
				return;
			if (event[pl.EventIndex.Code] === pl.EventCode.Join) {
				const player = { id: event[pl.JoinEventIndex.PlayerId]!, name: event[pl.JoinEventIndex.PlayerName] };
				this.playStore.join(conn.playId, player);
			} else if (event[pl.EventIndex.Code] === pl.EventCode.Leave) {
				this.playStore.leave(conn.playId, event[pl.EventIndex.PlayerId]!);
			}
			conn.amflow.sendEvent(event);
		});

		socket.on(
			"amflow:getTickList",
			(connectionId: string, opts: amf.GetTickListOptions, callback: (error: Error | null, tickList?: pl.TickList) => void) => {
				const conn = this.getConncetion(connectionId);
				if (!conn)
					return callback(this.makeConnectionError(connectionId));
				conn.amflow.getTickList(opts, callback);
			}
		);

		socket.on("amflow:putStartPoint", (connectionId: string, startPoint: amf.StartPoint, callback: (error: Error | null) => void) => {
			const conn = this.getConncetion(connectionId);
			if (!conn)
				return callback(this.makeConnectionError(connectionId));
			conn.amflow.putStartPoint(startPoint, callback);
		});

		socket.on(
			"amflow:getStartPoint",
			(
				connectionId: string,
				opts: amf.GetStartPointOptions,
				callback: (error: Error | null, startPoint?: amf.StartPoint) => void
			) => {
				const conn = this.getConncetion(connectionId);
				if (!conn)
					return callback(this.makeConnectionError(connectionId));
				conn.amflow.getStartPoint(opts, callback);
			}
		);

		socket.on(
			"amflow:putStorageData",
			(connectionId: string, key: pl.StorageKey, value: pl.StorageValue, options: any, callback: (err: Error | null) => void) => {
				const conn = this.getConncetion(connectionId);
				if (!conn)
					return callback(this.makeConnectionError(connectionId));
				conn.amflow.putStorageData(key, value, options, callback);
			}
		);

		socket.on(
			"amflow:getStorageData",
			(connectionId: string, keys: pl.StorageReadKey[], callback: (error: Error | null, values?: pl.StorageData[]) => void) => {
				const conn = this.getConncetion(connectionId);
				if (!conn)
					return callback(this.makeConnectionError(connectionId));
				conn.amflow.getStorageData(keys, callback);
			}
		);

		socket.on("amflow:close", (connectionId: string, callback: () => void) => {
			const conn = this.getConncetion(connectionId);
			if (!conn)
				return callback();
			conn.amflow.close(callback);

			delete this.connectionMap[connectionId];
			getSystemLogger().info("user disconnected. playId: " + conn.playId + " connectionId: " + connectionId);
		});

		socket.on("disconnect", () => {
			const doNothing = (): void => {}; // eslint-disable-line @typescript-eslint/no-empty-function
			Object.keys(this.connectionMap).forEach(connId => {
				const conn = this.connectionMap[connId];
				if (conn.socket === socket) {
					this.deletePlayToken(conn.lastToken!);
					conn.amflow.close(doNothing);
					delete this.connectionMap[connId];
				}
			});
		});
	}

	private getConncetion(connectionId: string): Connection | null {
		const conn = this.connectionMap[connectionId];
		if (!conn)
			return null;
		if (!this.playStore.getPlay(conn.playId))
			return null;
		return conn;
	}

	private makeConnectionError(connectionId: string): Error {
		const conn = this.connectionMap[connectionId];
		if (!conn)
			return new Error(`Invalid connectionId: ${connectionId}`);
		if (!this.playStore.getPlay(conn.playId))
			return new Error(`Already closed play. play: ${connectionId}`);
		return Error("Unknown Error on SocketIOAMFlowManager");
	}
}

import { createRequire } from "module";

const require = createRequire(import.meta.url);

export function dynamicRequire<T>(path: string, isDeleteCache?: boolean): T | null {
	let ret: T | null = null;
	try {
		if (isDeleteCache) delete require.cache[path];
		ret = require(path) as T;
	} catch (e) {
		if (e.code !== "MODULE_NOT_FOUND")
			throw e;
	}
	return ret;
}

import type { AMFlow } from "@akashic/amflow";
import { TickIndex, type Tick } from "@akashic/playlog";
import { Trigger } from "@akashic/trigger";
import { createNamagameCommentEvent } from "../../../common/PlaylogShim.js";
import type { NamagameCommentConfig, NamagameCommentConfigComment } from "../../../common/types/NamagameCommentConfig.js";
import type { NamagameCommentEventComment, NamagameCommentPlugin } from "../../../common/types/NamagameCommentPlugin.js";

export class NamagameCommentPluginHost {
	onStartStop: Trigger<boolean> = new Trigger();
	readonly plugin: NamagameCommentPlugin;

	protected config: NamagameCommentConfig;
	protected amflow: AMFlow;
	protected fps: number;

	protected started: boolean = false;
	protected planned: boolean = false;
	protected plan: Map<number, NamagameCommentEventComment[]> = new Map();

	constructor(config: NamagameCommentConfig, amflow: AMFlow, fps: number) {
		this.config = config;
		this.amflow = amflow;
		this.fps = fps;

		this.plugin = {
			start: (_opts, callback) => {
				if (this.started) {
					callOrThrow(callback, new Error("NamagameCommentPlugin already started."));
					return;
				}

				amflow.onTick(this._handleTick);
				if (callback)
					setImmediate(callback);
				this.started = true;
				this.planned = false;
				this.onStartStop.fire(true);
			},

			stop: () => {
				amflow.offTick(this._handleTick);
				this.started = false;
				this.onStartStop.fire(false);
			}
		};
	}

	planToSendByTemplate(name: string): boolean {
		const comments = this.config.templates?.[name]?.comments;
		if (!Array.isArray(comments) || comments.length === 0) {
			console.warn(`NamagameCommentPluginHost: no template named '${name}'`);
			return false;
		}
		return this._planToSendImpl(comments);
	}

	planToSend(c: NamagameCommentEventComment): boolean {
		return this._planToSendImpl([c]);
	}

	protected _planToSendImpl(comments: NamagameCommentConfigComment[]): boolean {
		const { amflow } = this;

		if (!this.started) {
			console.warn("NamagameCommentPluginHost: plugin not started.");
			return false;
		}

		const replan = (tick: Tick): void => {
			amflow.offTick(replan);

			const age = tick[TickIndex.Frame];
			if (!this.planned)
				this._setupPlan(age);

			const base = age + 1; // age は今既に来ている tick なので次の tick から送る
			let lastFrame = base;
			comments.forEach(c => {
				const frame = lastFrame = (c.frame != null) ? base + c.frame : lastFrame;
				// 実環境においては、放送者コメント (userID がないコメント) の場合 vpos は存在しないが、指定されていればそれを尊重する。
				// sandbox.config.js のコメントテンプレート機能で、vpos だけ「無視される場合がある」のも直感に反するためだが、
				// これが却ってトラブルの元になるなら再考する。
				const vpos = c.vpos ?? ((c.userID != null) ? frameToVpos(frame, this.fps) : null);
				const comment = (vpos != null) ?
					{ ...c, isAnonymous: !!c.isAnonymous, vpos } :
					{ ...c, isAnonymous: !!c.isAnonymous };
				arrayMapAdd(this.plan, frame, comment);
			});
		};

		amflow.onTick(replan);
		return true;
	}

	protected _setupPlan(startAge: number): void {
		if (this.planned) return;
		this.planned = true;

		const { plan, config } = this;
		const { templates } = config;
		plan.clear();

		if (!templates)
			return;

		objectForEach(templates, (templ) => {
			const { startBy, comments } = templ;
			if (!startBy || startBy === "manual") return;

			const base = startBy === "pluginStart" ? startAge : 0;
			let lastFrame = base;
			comments.forEach(c => {
				const frame = lastFrame = (c.frame != null) ? base + c.frame : lastFrame;
				if (frame >= startAge) {
					const comment = { ...c, isAnonymous: !!c.isAnonymous, vpos: c.vpos ?? frameToVpos(frame, this.fps) };
					arrayMapAdd(plan, frame, comment);
				}
			});
		});
	}

	protected _handleTick: (tick: Tick) => void = tick => {
		const age = tick[TickIndex.Frame];
		if (!this.planned)
			this._setupPlan(age);

		const comments = this.plan.get(age);
		if (comments?.length) {
			this.amflow.sendEvent(createNamagameCommentEvent(comments));
		}
	};
}

function frameToVpos(frame: number, fps: number): number {
	return Math.floor(frame * (1000 / fps) * 0.1); // 0.1 倍してミリ秒をセンチ秒に
}

function objectForEach<T extends object>(obj: T, fun: (val: T[keyof T], key: keyof T) => void): void {
	(Object.keys(obj) as (keyof T)[]).forEach(key => fun(obj[key], key));
}

function arrayMapAdd<K, V>(map: Map<K, V[]>, k: K, v: V): void {
	if (map.has(k))
		map.get(k)?.push(v);
	else
		map.set(k, [v]);
}

/**
 * callback が関数であるなら err を与えて呼び出す。でなければ err を throw する。
 *
 * 以下すべてを満たす時に利用すること。
 * (a) エラー通知用のコールバックが省略可能で、必ずしもそれでエラー通知ができない
 * (b) err がロジックエラー (コンテンツ開発者の対応が必要) であり、serve としてはゲーム開発者が確実に気づける形が望ましい
 * (c) 通知したいエラーが同期的に発生している
 */
export function callOrThrow(callback: ((err?: Error) => void) | null | undefined, err: Error): void {
	if (callback) {
		callback(err);
	} else {
		throw err;
	}
}

