export const createHandlerToGetSandboxConfig = (dirPaths: string[]): express.RequestHandler => {
	return async (req, res, next) => {
		try {
			const contentId = Number(req.params.contentId);
			if (!dirPaths[contentId]) {
				throw new NotFoundError({ errorMessage: `contentId:${contentId} is not found.` });
			}
			const confDirPath = dirPaths[contentId];
			const configPath = serverGlobalConfig.sandboxConfig ?? path.resolve(confDirPath, "sandbox.config.js");
			// TODO ファイル監視。内容に変化がなければ直前の値を返せばよい
			const config = dynamicRequire(configPath) ?? {};
			const normalizedConfig = sandboxConfigs.normalizeConfig(config, req.params.contentId);
			responseSuccess<SandboxConfigApiResponseData>(res, 200, normalizedConfig);
		} catch (e) {
			next(e);
		}
	};
};

export const createHandlerToGetSandboxConfigPluginCode = (): express.RequestHandler => {
	return async (req, res, next) => {
		try {
			const contentId = req.params.contentId;
			const pluginName = req.params.pluginName;
			const config = sandboxConfigs.get(contentId);

			if (!config.client.external?.[pluginName]) {
				throw new NotFoundError({ errorMessage: `pluginName:${pluginName} is not found.` });
			}

			const pluginPath = path.resolve(config.client.external[pluginName]);
			if (!fs.existsSync(pluginPath)) {
				throw new NotFoundError({ errorMessage: `${pluginName} is not found. path:${config.client.external[pluginName]}` });
			}

			const content = fs.readFileSync(pluginPath);
			// `/contents/${contentId}/sandboxConfig/plugins/${pluginName}` にアクセスで plugin を取得できるようにする
			const responseBody = `window.__testbed.pluginFuncs["${pluginName}"] = function () {
				var module = { exports: {} };
				var exports = module.exports;
				(function () {
    				${ content };
				})();
				return module.exports;
			};`;

			res.contentType("text/javascript");
			res.send(responseBody);
		} catch (e) {
			next(e);
		}
	};
};

export const createHandlerToGetSandboxConfigBgImage = (): express.RequestHandler => {
	return async (req, res, next) => {
		try {
			const contentId = req.params.contentId;
			const config = sandboxConfigs.get(contentId);
			if (config.resolvedBackgroundImagePath) {
				const imgPath = path.resolve(config.resolvedBackgroundImagePath);

				if (!fs.existsSync(imgPath)) {
					throw new NotFoundError({ errorMessage: `backgroundImage is not found. path:${config.resolvedBackgroundImagePath}` });
				}

				// SandboxConfigs#normalizeConfig() で PNG/WEBP/JPEG 以外のファイルはエラーとしている
				const extname = path.extname(imgPath);
				const type = extname === ".png" ? "image/png" : extname === "webp" ? "image/webp" : "image/jpeg";
				res.contentType(type);
				res.sendFile(imgPath);
			} else {
				throw new BadRequestError({
					errorMessage: `Invalid backgroundImage, The value is not local path. value:${config.displayOptions.backgroundImage}`
				});
			}
		} catch (e) {
			next(e);
		}
	};
};

import * as fs from "fs";
import * as path from "path";
import type { GameConfiguration } from "@akashic/akashic-cli-commons";
import type { ScriptAssetConfigurationBase } from "@akashic/game-configuration";
import { makePathKeyObject } from "@akashic/game-configuration/lib/utils/makePathKeyObject.js";
import type * as express from "express";
import { getUrlPathname } from "../../common/urlUtil.js";
import * as gameConfigs from "../domain/GameConfigs.js";

export const createScriptAssetController = (baseDir: string, index: number): express.RequestHandler => {
	// TODO: require() のキャッシュするモジュールのインターフェース (index でアクセスする点) と register() 箇所を見直す
	gameConfigs.register(index.toString(), baseDir);

	return (req: express.Request, res: express.Response, next: Function): void => {
		const scriptName = req.params.scriptName;
		const scriptPath = path.join(baseDir, scriptName);
		if (!fs.existsSync(scriptPath)) {
			const err: any = new Error("Not Found");
			err.status = 404;
			next(err);
			return;
		}

		const content = fs.readFileSync(scriptPath);
		// クエリ部分を無視したいので、URL#pathname を key とする
		const key = getUrlPathname(`${req.protocol}://${req.get("host") + req.originalUrl}`);

		// TODO: game.json の内容に変化が無い限りキャッシュから読み込むように修正
		const gameJson: GameConfiguration = JSON.parse(fs.readFileSync(path.join(baseDir, "game.json"), { encoding: "utf-8" }));
		const assetMap = makePathKeyObject(gameJson.assets);
		const scriptAssetConfig = assetMap[scriptName] as (ScriptAssetConfigurationBase | undefined); // global asset の場合 undefined
		const exports = scriptAssetConfig?.exports ?? [];

		let postContent = "";
		for (const variableName of exports) {
			postContent += `exports["${variableName}"] = typeof ${variableName} !== "undefined" ? ${variableName} : undefined;\n`;
		}

		const responseBody = `"use strict";
			if (! ("gScriptContainer" in window)) {
				window.gScriptContainer = {};
			}
			gScriptContainer["${key}"] = function(g) {
				var Math = window.akashicServe.scriptHelper.overrides.MeddlingMath;

				(function(exports, require, module, __filename, __dirname) {
					${content}
					${postContent}
				})(g.module.exports, g.module.require, g.module, g.filename, g.dirname);
			}
		`;
		res.contentType("text/javascript");
		res.send(responseBody);
	};
};

