import type { ContentLocatorData } from "./types/ContentLocatorData.js";

export class ContentLocator {
	contentId: string | null;

	host: string | null;
	path: string | null;
	debuggablePath: string | null;

	constructor(locData: ContentLocatorData) {
		this.contentId = locData.contentId || null;
		this.host = locData.host || null;
		this.path = locData.path || null;
		this.debuggablePath = locData.debuggablePath || null;
	}

	asRootRelativeUrl(): string | null {
		if (this.contentId)
			return `/contents/${this.contentId}/content.raw.json`;
		if (this.path)
			return this.path;
		return null;
	}

	asDebuggableRootRelativeUrl(): string | null {
		if (this.contentId)
			return `/contents/${this.contentId}/content.json`;
		if (this.debuggablePath)
			return this.debuggablePath;
		return null;
	}

	asContentLocatorData(): ContentLocatorData {
		return {
			contentId: this.contentId,
			host: this.host,
			path: this.path,
			debuggablePath: this.debuggablePath
		};
	}
}

import { encode, decode } from "@msgpack/msgpack";
import { Emitter } from "@socket.io/component-emitter";
import type { Packet } from "socket.io-parser";
import { PacketType } from "socket.io-parser";
import type { MessageEncodeTestbedEvent } from "./types/TestbedEvent.js";

type EncoderEvents = { encoded: (d: MessageEncodeTestbedEvent) => void };
type DecoderEvents = { decoded: (p: Packet) => void };

class Encoder extends Emitter<EncoderEvents, EncoderEvents> {
	encode(packet: Packet): any[] {
		const encoded = encode(packet);
		this.emit("encoded", { packet, encoded } as MessageEncodeTestbedEvent);
		return [encoded];
	}
}

class Decoder extends Emitter<DecoderEvents, DecoderEvents> {
	add(chunk: any): void {
		const packet = decode(chunk) as Packet;
		// 指定の namespace への初回接続時 (PacketType === CONNECT) に `packet.data` の値が `authPayload` として利用されるが、
		// その際に `authPayload === null` だと msgpack のエンコード時にエラーとなるため暫定対応で `undefined` で上書きする。
		// @see https://github.com/socketio/socket.io-protocol#exchange-protocol
		// @see https://github.com/socketio/socket.io/blob/15af22f/lib/client.ts#L277
		//
		// FIXME: 以下の PullRequest のマージにより本暫定対応を削除できる可能性がある
		// https://github.com/socketio/socket.io/pull/4675
		if (packet.data === null) {
			packet.data = undefined;
		}
		if (this.isPacketValid(packet)) {
			this.emit("decoded", packet);
		} else {
			throw new Error("invalid format");
		}
	}

	isPacketValid({ type, data, nsp, id }: Packet): boolean {
		const isNamespaceValid = typeof nsp === "string";
		const isAckIdValid = id === undefined || Number.isInteger(id);
		if (!isNamespaceValid || !isAckIdValid) {
			return false;
		}
		switch (type) {
			case PacketType.CONNECT:
				return data === undefined || typeof data === "object";
			case PacketType.DISCONNECT:
				return data === undefined;
			case PacketType.EVENT:
				return Array.isArray(data) && data.length > 0;
			case PacketType.ACK:
				return Array.isArray(data);
			case PacketType.CONNECT_ERROR:
				return typeof data === "object";
			default:
				return false;
		}
	}

	destroy(): void {
		// do nothing
	}
}

export default {
	Encoder, Decoder
};

import type { MessageEventIndex, EventCode, EventIndex, MessageEvent, Event } from "@akashic/playlog";
import type { NamagameCommentEventComment } from "./types/NamagameCommentPlugin.js";

// serve (のクライアント側) は isolatedModules: true のため、
// const enum で定義されている EventCode は「値として」は参照できない (コンパイルエラーになる)。
// 仕方がないので必要な値だけここで定義しなおす。
// 型情報としては const enum を参照することで、値の不整合が起きないようになっていることに注意。
//
// TODO playlog 自身でこの定義を (ルート以外のパスから) 提供する？
export const EventCodeMessage: EventCode.Message = 32;
export const EventIndexCode: EventIndex.Code = 0;
export const MessageEventIndexData: MessageEventIndex.Data = 3;

export interface NamagameCommentEvent extends MessageEvent {
	[MessageEventIndexData]: {
		type: "namagame:comment";
		comments: NamagameCommentEventComment[];
	};
}

export function isNamagameCommentEvent(ev: Event): ev is NamagameCommentEvent {
	return ev[EventIndexCode] === EventCodeMessage && ev[MessageEventIndexData]?.type === "namagame:comment";
}

export function createNamagameCommentEvent(comments: NamagameCommentEventComment[]): NamagameCommentEvent {
	return [
		EventCodeMessage,
		0,
		":akashic",
		{
			type: "namagame:comment",
			comments
		}
	];
}

export class TimeKeeper {
	origin: number;
	pausedTime: number | null;
	rate: number;
	offset: number;

	constructor() {
		this.origin = Date.now();
		this.pausedTime = 0;
		this.rate = 1;
		this.offset = 0;
	}

	isPausing(): boolean {
		return this.pausedTime != null;
	}

	now(): number {
		return (this.isPausing()) ? this.pausedTime! : ((Date.now() - this.origin) * this.rate + this.offset);
	}

	setTime(time: number): void {
		if (this.isPausing()) {
			this.pausedTime = time;
		} else {
			this.origin = Date.now();
			this.offset = time;
		}
	}

	start(origin: number = Date.now()): void {
		if (!this.isPausing()) {
			return;
		}
		this.origin = origin;
		this.offset = this.pausedTime!;
		this.pausedTime = null;
	}

	pause(): void {
		if (this.isPausing()) {
			return;
		}
		this.pausedTime = this.now();
	}
}

import { calculateFinishedTime } from "@akashic/amflow-util/lib/calculateFinishedTime.js";
import type { DumpedPlaylog } from "./types/DumpedPlaylog.js";

export function calculatePlayDuration(playlog: DumpedPlaylog): number {
	let duration = calculateFinishedTime(
		playlog.tickList,
		playlog.startPoints[0].data.fps,
		playlog.startPoints[0].timestamp
	);

	if (playlog.__serve) {
		duration = Math.max(duration, playlog.__serve.duration ?? 0);
	} else {
		duration += 1; // 最終ティックを消化できるよう 1ms だけ余分に追加する
	}

	return duration;
}

export function isServiceTypeNicoliveLike(targetService: string): boolean {
	return /^nicolive.*/.test(targetService);
}

// URLのパス名を取得するユーティリティ関数
export function getUrlPathname(url: string): string {
	if (!URL.canParse(url)) {
		throw new Error(`Invalid URL: ${url}`);
	}
	return new URL(url).pathname;
}

