import { observer } from "mobx-react";
import * as React from "react";
import styles from "./TopResizable.module.css";

export interface TopResizableProps {
	height: number;
	minHeight: number;
	children?: React.ReactNode;
	onResize: (height: number) => void;
}

export const TopResizable = observer(class TopResizable extends React.Component<TopResizableProps, {}> {
	private lastPageY: number | null;

	constructor(props: TopResizableProps) {
		super(props);
		this.lastPageY = null;
	}

	render(): React.ReactNode {
		return <div className={styles["top-resizable"]} style={{ height: this.props.height }} >
			<div className={styles.content}>
				{ this.props.children }
			</div>
			<div className={styles["h-resizer"]} onMouseDown={this._onMouseDownResizer} />
		</div>;
	}

	private _onMouseDownResizer = (ev: React.MouseEvent<HTMLDivElement>): void => {
		window.addEventListener("mousemove", this._onMouseMoveWindow);
		window.addEventListener("mouseup", this._onMouseUpWindow);
		this.lastPageY = ev.nativeEvent.pageY;
	};

	private _onMouseMoveWindow = (ev: MouseEvent): void => {
		const { onResize, height, minHeight } = this.props;
		const h = Math.max(height - (ev.pageY - this.lastPageY!), minHeight);
		if (h !== height) {
			onResize(h);
			this.lastPageY = ev.pageY;
		}
	};

	private _onMouseUpWindow = (): void => {
		window.removeEventListener("mousemove", this._onMouseMoveWindow);
		window.removeEventListener("mouseup", this._onMouseUpWindow);
	};
});

import type { GameConfiguration, NicoliveEnvironment, PreferredSessionParameters } from "@akashic/game-configuration";
import type { NormalizedSandboxConfiguration } from "@akashic/sandbox-configuration";
import { action, observable } from "mobx";
import type { ContentDesc } from "../../common/types/ContentDesc";
import { apiClient } from "../api/apiClientInstance";
import { ClientContentLocator } from "../common/ClientContentLocator";
import { DevtoolUiStore } from "./DevtoolUiStore";

export class ContentEntity {
	readonly locator: ClientContentLocator;
	gameJson: GameConfiguration | undefined; // 現状では view に反映しないので observable はつけない
	preferredSessionParameters: PreferredSessionParameters; // 現状では view に反映しないので observable はつけない
	gameLocationKey: string | undefined; // 仕様未定のため --experimental-open オプション以外で使用してはいけない
	@observable sandboxConfig: NormalizedSandboxConfiguration;
	@observable argumentsTable: { [name: string]: string };
	private _initializationWaiter: Promise<void>;

	constructor(desc: ContentDesc) {
		this.locator = ClientContentLocator.instantiate(desc.contentLocatorData);
		this.sandboxConfig = desc.sandboxConfig ?? null!;
		this.argumentsTable = {};
		const args = this.sandboxConfig?.arguments ?? {};
		this.gameJson = desc.gameJson;
		this.gameLocationKey = desc.gameLocationKey;
		this.preferredSessionParameters = {};
		this.calculatePreferredSessionParameters();
		Object.keys(args).forEach(key => {
			this.argumentsTable[key] = JSON.stringify(args[key], null, 2);
		});
		this._initializationWaiter = this._initialize();
	}

	assertInitialized(): Promise<void> {
		return this._initializationWaiter;
	}

	@action
	setSandboxConfig(config: NormalizedSandboxConfiguration): void {
		this.sandboxConfig = config;
	}

	async updateSandboxConfig(): Promise<void> {
		const res = await apiClient.getContent(this.locator.contentId!);
		this.setSandboxConfig(res.data.sandboxConfig!);
	}

	@action
	calculatePreferredSessionParameters(): void {
		const nicoliveConfig = this._getNicoLiveConfig();
		this.preferredSessionParameters = nicoliveConfig && nicoliveConfig.preferredSessionParameters || {};

		this.preferredSessionParameters.totalTimeLimit =
			!this.preferredSessionParameters || !this.preferredSessionParameters.totalTimeLimit
				? DevtoolUiStore.DEFAULT_TOTAL_TIME_LIMIT
				: this.preferredSessionParameters.totalTimeLimit;
	}

	private _getNicoLiveConfig(): NicoliveEnvironment | null {
		const environment = this.gameJson?.environment;
		if (environment === undefined) {
			return null;
		}
		// niconico は非推奨なので、nicolive の方を優先的に利用する
		return environment.nicolive ?? (environment.niconico ?? null);
	}

	private async _initialize(): Promise<void> {
		if (this.sandboxConfig != null) return;
		await this.updateSandboxConfig();
	}
}

import { observable, ObservableMap } from "mobx";
import type { ContentLocatorData } from "../../common/types/ContentLocatorData";
import { apiClient } from "../api/apiClientInstance";
import { ClientContentLocator } from "../common/ClientContentLocator";
import { ContentEntity } from "./ContentEntity";

export class ContentStore {
	@observable contents: ObservableMap<string, ContentEntity>;
	private _defaultContent: ContentEntity; // assertInitialize() がresolve されるまでの値は保証されない
	private _initializationWaiter: Promise<void>;

	constructor() {
		this.contents = new ObservableMap<string, ContentEntity>();
		this._defaultContent = null!;
		this._initializationWaiter = this._initialize();
	}

	assertInitialized(): Promise<void> {
		return this._initializationWaiter;
	}

	defaultContent(): ContentEntity {
		return this._defaultContent!;
	}

	// TODO: serve 起動後にコンテンツを登録。現状未使用のため不要なら削除。
	async register(locData: ContentLocatorData): Promise<ContentEntity> {
		const loc = ClientContentLocator.instantiate(locData);
		const url = loc.asAbsoluteUrl();

		const content = new ContentEntity({ contentLocatorData: loc });
		await content.assertInitialized();
		this.contents.set(url, content);
		return content;
	}

	find(locData: ContentLocatorData): ContentEntity {
		const loc = ClientContentLocator.instantiate(locData);
		const url = loc.asAbsoluteUrl();
		const registered = this.contents.get(url);
		if (!registered)
			throw new Error("content is not found.");

		return registered;
	}

	private async _initialize(): Promise<void> {
		const res = await apiClient.getContents();
		await Promise.all(res.data.map(async (desc) => {
			const content = new ContentEntity(desc);
			await content.assertInitialized();
			this.contents.set(content.locator.asAbsoluteUrl(), content);
			if (!this._defaultContent)
				this._defaultContent = content;
		}));
	}
}

import { observable, action } from "mobx";
import type { NamagameCommentEventComment } from "../../common/types/NamagameCommentPlugin";

/**
 * コメント送信者タイプ。
