import * as playlog from "@akashic/playlog";
import { Trigger } from "@akashic/trigger";
import type { ObservableMap } from "mobx";
import { observable, action } from "mobx";
import { TimeKeeper } from "../../common/TimeKeeper";
import type { PlayPatchApiResponse } from "../../common/types/ApiResponse";
import type { NamagameCommentEventComment } from "../../common/types/NamagameCommentPlugin";
import type { PlayAudioState } from "../../common/types/PlayAudioState";
import type { PlayDurationState } from "../../common/types/PlayDurationState";
import type { Player } from "../../common/types/Player";
import type { PlayStatus } from "../../common/types/PlayStatus";
import type { StartPointHeader } from "../../common/types/StartPointHeader";
import type { RunnerDescription, ClientInstanceDescription } from "../../common/types/TestbedEvent";
import type { GameViewManager } from "../akashic/GameViewManager";
import type { ServeMemoryAmflowClient } from "../akashic/ServeMemoryAMFlowClient";
import type { SocketIOAMFlowClient } from "../akashic/SocketIOAMFlowClient";
import { apiClient } from "../api/apiClientInstance";
import type { ScenarioEventData } from "../common/types/ScenarioEventData";
import type { ContentEntity } from "./ContentEntity";
import type { ExecutionMode } from "./ExecutionMode";
import { LocalInstanceEntity } from "./LocalInstanceEntity";
import { ServerInstanceEntity } from "./ServerInstanceEntity";

export interface CreateLocalInstanceParameterObject {
	executionMode: ExecutionMode;
	player: Player;
	playId: string;
	playToken?: string;
	playlogServerUrl?: string;
	argument?: any;
	initialEvents?: playlog.Event[];
	proxyAudio?: boolean;
	runInIframe?: boolean;
	useNonDebuggableScript?: boolean;
	resizeGameView?: boolean;
}

export interface CreateServerInstanceParameterObject {
	playToken: string;
	isPaused: boolean;
}

export interface PlayEntityParameterObject {
	gameViewManager: GameViewManager;
	amflow: SocketIOAMFlowClient | ServeMemoryAmflowClient;
	playId: string;
	status: PlayStatus;
	joinedPlayers?: Player[];
	content: ContentEntity;
	runners?: RunnerDescription[];
	clientInstances?: ClientInstanceDescription[];
	durationState?: PlayDurationState;
	audioState?: PlayAudioState;
	parent?: PlayEntity;
	startPointHeaders?: StartPointHeader[];
	disableFastForward?: boolean; // View レイヤーからの参照のために定義。将来的には名前や役割を修正すべきかもしれない。
}

export class PlayEntity {
	onTeardown: Trigger<PlayEntity>;

	readonly playId: string;
	readonly amflow: SocketIOAMFlowClient | ServeMemoryAmflowClient;
	readonly content: ContentEntity;
	readonly disableFastForward?: boolean;

	@observable activePlaybackRate: number;
	@observable isActivePausing: boolean;
	@observable duration: number;

	@observable clientInstances: ClientInstanceDescription[];
	@observable joinedPlayerTable: ObservableMap;
	@observable status: PlayStatus;
	@observable startPointHeaders: StartPointHeader[];
	@observable audioState: PlayAudioState;

	@observable localInstances: LocalInstanceEntity[];
	@observable serverInstances: ServerInstanceEntity[];

	private readonly _gameViewManager: GameViewManager;
	private readonly _timeKeeper: TimeKeeper;
	private _serverInstanceWaiters: {[key: string]: (p: ServerInstanceEntity) => void };
	private _timerId: number | null;
	private _parent?: PlayEntity;

	constructor(param: PlayEntityParameterObject) {
		this.playId = param.playId;
		this.amflow = param.amflow;
		this.disableFastForward = param.disableFastForward;
		this.activePlaybackRate = 1;
		this.isActivePausing = !!param.durationState && param.durationState.isPaused;
		this.duration = param.durationState ? param.durationState.duration : 0;
		this.clientInstances = param.clientInstances ?? [];
		this.startPointHeaders = param.startPointHeaders ?? [];
		this.joinedPlayerTable = observable.map((param.joinedPlayers || []).map(p => [p.id, p] as [string, Player]));
		this.status = param.status;
		this.audioState = param.audioState ?? { muteType: "none" };
		this.localInstances = [];
		this.serverInstances = !param.runners ? [] : param.runners.map(desc => {
			return new ServerInstanceEntity({ runnerId: desc.runnerId, play: this });
		});
		this.onTeardown = new Trigger();
		this.content = param.content;
		this._gameViewManager = param.gameViewManager;
		this._timeKeeper = new TimeKeeper();
		this._serverInstanceWaiters = {};
		this._timerId = null;

		if (param.parent) {
			this._parent = param.parent;
			this._parent.onTeardown.addOnce(this._handleParentTeardown);
		}

		if (param.durationState) {
			this._timeKeeper.setTime(param.durationState.duration);
			if (!param.durationState.isPaused) {
				this._startTimeKeeper();
			}
		}
	}

	deleteAllServerInstances(): Promise<void[]> {
		return Promise.all(this.serverInstances.map(instance => instance.stop()));
	}

	async suspend(): Promise<void> {
		await this.deleteAllServerInstances();
		await apiClient.suspendPlay(this.playId);
	}

	async createLocalInstance(param: CreateLocalInstanceParameterObject): Promise<LocalInstanceEntity> {
		const i = new LocalInstanceEntity({
			play: this,
			content: this.content,
			gameViewManager: this._gameViewManager,
			...param
		});
		i.onStop.add(this._handleLocalInstanceStopped);
		this.localInstances.push(i);
		await i.assertInitialized();
		return i;
	}

	async deleteAllLocalInstances(): Promise<void> {
		await Promise.all<void>(this.localInstances.map(i => {
			i.onStop.removeAll({ func: this._handleLocalInstanceStopped });
			return i.stop();
		}));
		this.localInstances = [];
	}

	async createServerInstance(param: CreateServerInstanceParameterObject): Promise<ServerInstanceEntity> {
		const runnerResult = await apiClient.createRunner(this.playId, true, param.playToken, param.isPaused);
		const runnerId = runnerResult.data.runnerId;

		// apiClient.createRunner() に対する onRunnerCreate 通知が先行していれば、この時点で ServerInstanceEntity が生成済みになっている
		const rs = this.serverInstances.filter(r => r.runnerId === runnerId);
		if (rs.length > 0)
			return rs[0];

		// でなければ、onRunnerCreate 通知(が来て ServerInstanceEntity が生成される)を待つ
		const instance = await (new Promise<ServerInstanceEntity>(resolve => (this._serverInstanceWaiters[runnerId] = resolve)));
		delete this._serverInstanceWaiters[runnerId];
		return instance;
	}

	join(playerId: string, name?: string): void {
		const highestPriority = 3;
		this.amflow.enqueueEvent([
			// @ts-expect-error src/clent/ は isolatedModules: true なので const enum の EventCode がエラーになるが、
			// 実際は playlog が preserveConstEnums でビルドされているため問題にならない。
			playlog.EventCode.Join,
			highestPriority,
			playerId,
			name
		]);
	}

	leave(playerId: string): void {
		const highestPriority = 3;
		this.amflow.enqueueEvent([
			// @ts-expect-error src/clent/ は isolatedModules: true なので const enum の EventCode がエラーになるが、
			// 実際は playlog が preserveConstEnums でビルドされているため問題にならない。
			playlog.EventCode.Leave,
			highestPriority,
			playerId
		]);
	}

	sendScenarioEvent(playerId: string, data: ScenarioEventData): void {
		this.amflow.sendEvent([
			// @ts-expect-error src/clent/ は isolatedModules: true なので const enum の EventCode がエラーになるが、
			// 実際は playlog が preserveConstEnums でビルドされているため問題にならない。
			playlog.EventCode.Message,
			0,
			playerId,
			data
		]);
	}

	pauseActive(): Promise<PlayPatchApiResponse> {
		// 手抜き実装: サーバインスタンスは全てアクティブ(つまり一つしかない)前提
		this.serverInstances.forEach(si => si.pause());
		return apiClient.pausePlayDuration(this.playId);
	}

	resumeActive(): Promise<PlayPatchApiResponse> {
		// 手抜き実装: サーバインスタンスは全てアクティブ(つまり一つしかない)前提
		this.serverInstances.forEach(si => si.resume());
		return apiClient.resumePlayDuration(this.playId);
	}

	stepActive(): Promise<PlayPatchApiResponse> {
		// 手抜き実装: サーバインスタンスは全てアクティブ(つまり一つしかない)前提
		this.serverInstances.forEach(si => si.step());
		return apiClient.stepPlayDuration(this.playId);
	}

	pauseTimekeeper(): void {
		this._timeKeeper.pause();
	}

	startTimekeeper(): void {
		this._timeKeeper.start();
	}

	muteAll(): Promise<void> {
		return apiClient.changePlayAudioState(this.playId, { muteType: "all" });
	}

	muteOthers(): Promise<void> {
		const soloPlayerId = this.localInstances[0]?.player?.id;
		return apiClient.changePlayAudioState(this.playId, { muteType: "solo", soloPlayerId });
	}

	unmuteAll(): Promise<void> {
		return apiClient.changePlayAudioState(this.playId, { muteType: "none" });
	}

	async sendNamagameCommentByTemplate(templateName: string): Promise<void> {
		await apiClient.requestToSendNamagameCommentByTemplate(this.playId, templateName);
	}

	async sendNamagameComment(comment: NamagameCommentEventComment): Promise<void> {
		await apiClient.requestToSendNamagameComment(this.playId, comment);
	}

	@action
	handlePlayerJoin(player: Player): void {
		this.joinedPlayerTable.set(player.id, player);
	}

	@action
	handlePlayerLeave(playerId: string): void {
		this.joinedPlayerTable.delete(playerId);
	}

	@action
	handleClientInstanceAppear(instanceDesc: ClientInstanceDescription): void {
		this.clientInstances.push(instanceDesc);
	}

	@action
	handleClientInstanceDisappear(instanceDesc: ClientInstanceDescription): void {
		this.clientInstances = this.clientInstances.filter(i => i.id !== instanceDesc.id);
	}

	@action
	handlePlayStatusChange(status: PlayStatus): void {
		this.status = status;
	}

	@action
	handlePlayDurationStateChange(isPaused: boolean, duration?: number): void {
		if (isPaused) {
			this._pauseTimeKeeper();
		} else {
			this._startTimeKeeper();
		}
		if (duration != null) {
			this._timeKeeper.setTime(duration);
		}
	}

	@action
	handlePlayAudioStateChange(audioState: PlayAudioState): void {
		this.audioState = audioState;
		this.localInstances.forEach(li => li.followPlayAudioStateChange());
	}

	@action
	handleRunnerCreate(runnerId: string): void {
		const instance = new ServerInstanceEntity({ runnerId, play: this });
		this.serverInstances.push(instance);
		if (this._serverInstanceWaiters[runnerId]) {
			this._serverInstanceWaiters[runnerId](instance);
		}
	}

	@action
	handleRunnerRemove(runnerId: string): void {
		this.serverInstances = this.serverInstances.filter(i => i.runnerId !== runnerId);
	}

	@action
	handleRunnerPause(): void {
		// TODO ServerInstanceEntity#isPaused を持たせる
		// 現状のこの処理は1プレイ内にサーバインスタンスがアクティブ一つしかない前提
		this.isActivePausing = true;
	}

	@action
	handleRunnerResume(): void {
		this.isActivePausing = false;
	}

	@action
	handleStartPointHeader(startPointHeader: StartPointHeader): void {
		this.startPointHeaders.push(startPointHeader);
	}

	async teardown(): Promise<void> {
		this._pauseTimeKeeper();
		await this.deleteAllLocalInstances();
		await this.deleteAllServerInstances();
		this.onTeardown.fire(this);
	}

	private _handleLocalInstanceStopped = (instance: LocalInstanceEntity): void => {
		this.localInstances = this.localInstances.filter(i => i !== instance);
	};

	private _startTimeKeeper(): void {
		this._timeKeeper.start();
		this._timerId = window.setInterval(this._handleFrame, 200);
	}

	private _pauseTimeKeeper(): void {
		this._timeKeeper.pause();
		if (this._timerId) {
			// cancelAnimationFrame(this._timerId);
			window.clearInterval(this._timerId);
			this._timerId = null;
		}
	}

	private _handleParentTeardown = (): Promise<void> => {
		return this.teardown();
	};

	@action
	private _handleFrame = (): void => {
		this.duration = this._timeKeeper.now();
		// this._timerId = setTimeout(this._handleFrame, 200);
	};
}

import { observable } from "mobx";
import type { ContentLocatorData } from "../../common/types/ContentLocatorData";
import type { Player } from "../../common/types/Player";
import type {
	PlayCreateTestbedEvent,
	PlayStatusChangedTestbedEvent,
	PlayDurationStateChangeTestbedEvent,
	PlayerJoinTestbedEvent,
	PlayerLeaveTestbedEvent,
	RunnerCreateTestbedEvent,
	RunnerRemoveTestbedEvent,
	RunnerPauseTestbedEvent,
	RunnerResumeTestbedEvent,
	ClientInstanceAppearTestbedEvent,
	ClientInstanceDisappearTestbedEvent,
	PutStartPointEvent,
	PlayAudioStateChangeTestbedEvent
} from "../../common/types/TestbedEvent";
import type { GameViewManager } from "../akashic/GameViewManager";
import { SocketIOAMFlowClient } from "../akashic/SocketIOAMFlowClient";
import { apiClient } from "../api/apiClientInstance";
import { socketInstance } from "../api/socketInstance";
import * as Subscriber from "../api/Subscriber";
import type { ClientContentLocator } from "../common/ClientContentLocator";
import type { ContentStore } from "./ContentStore";
import { PlayEntity } from "./PlayEntity";

export interface PlayStoreParameterObject {
	contentStore: ContentStore;
	gameViewManager: GameViewManager;
}

export interface CreatePlayParameterObject {
	contentLocator: ContentLocatorData;
	parent?: PlayEntity;
	initialJoinPlayer?: Player;
	inheritsJoinedFromLatest?: boolean;
	inheritsAudioFromLatest?: boolean;
}

export interface CreateStandalonePlayParameterObject {
	contentLocator: ClientContentLocator;

	// TODO xnv create が playId を引数にとるのはおかしい。sessionId の管理は Play から切り離す。
	playId: string;
	parent?: PlayEntity;
}

export class PlayStore {
	@observable plays: {[key: string]: PlayEntity};
	private _gameViewManager: GameViewManager;
	private _lastPlayId: string | null;
	private _contentStore: ContentStore;
	private _creationWaiters: {[key: string]: (p: PlayEntity) => void };
	private _initializationWaiter: Promise<void>;

	constructor(param: PlayStoreParameterObject) {
		this.plays = Object.create(null);
		this._gameViewManager = param.gameViewManager;
		this._lastPlayId = null;
		this._contentStore = param.contentStore;
		this._creationWaiters = Object.create(null);
		this._initializationWaiter = this._contentStore.assertInitialized()
			.then(() => apiClient.getPlays())
			.then((res) => {
				const playsInfo = res.data;
				return Promise.all(playsInfo.map((playInfo) => {
					return apiClient.getStartPointHeaderList(playInfo.playId)
						.then((res) => {
							return {
								playInfo,
								startPointHeaders: res.data.startPointHeaderList
							};
						});
				}));
			})
			.then(async res => {
				for (const o of res) {
					this.plays[o.playInfo.playId] = new PlayEntity({
						...o.playInfo,
						amflow: new SocketIOAMFlowClient(socketInstance),
						gameViewManager: this._gameViewManager,
						content: this._contentStore.find(o.playInfo.contentLocatorData),
						startPointHeaders: o.startPointHeaders
					});
				}
				if (res.length > 0)
					this._lastPlayId = res[res.length - 1].playInfo.playId;
				Subscriber.onPlayCreate.add(this.handlePlayCreate);
				Subscriber.onPlayStatusChange.add(this.handlePlayStatusChange);
				Subscriber.onPlayDurationStateChange.add(this.handlePlayDurationStateChange);
				Subscriber.onPlayAudioStateChange.add(this.handlePlayAudioStateChange);
				Subscriber.onPlayerJoin.add(this.handlePlayerJoin);
				Subscriber.onPlayerLeave.add(this.handlePlayerLeave);
				Subscriber.onClientInstanceAppear.add(this.handleClientInstanceAppear);
				Subscriber.onClientInstanceDisappear.add(this.handleClientInstanceDisappear);
				Subscriber.onRunnerCreate.add(this.handleRunnerCreate);
				Subscriber.onRunnerRemove.add(this.handleRunnerRemove);
				Subscriber.onRunnerPause.add(this.handleRunnerPause);
				Subscriber.onRunnerResume.add(this.handleRunnerResume);
				Subscriber.onPutStartPoint.add(this.handlePutStartPoint);
			});
	}

	assertInitialized(): Promise<void> {
		return this._initializationWaiter;
	}

	getLastPlay(): PlayEntity | null {
		return this._lastPlayId ? this.plays[this._lastPlayId] : null;
	}

	async createPlay(param: CreatePlayParameterObject): Promise<PlayEntity> {
		const playInfo = await apiClient.createPlay(
			param.contentLocator,
			param.initialJoinPlayer,
			param.inheritsJoinedFromLatest,
			param.inheritsAudioFromLatest
		);
		const playId = playInfo.data.playId;

		// apiClient.createPlay() に対する onPlayCreate 通知が先行していれば、この時点で PlayEntity が生成済みになっている
		if (this.plays[playId])
			return this.plays[playId];

		// でなければ onPlayCreate 通知(が来て PlayEntity が生成される)を待つ
		const play = await (new Promise<PlayEntity>(resolve => (this._creationWaiters[playId] = resolve)));
		delete this._creationWaiters[playId];
		return play;
	}

	/**
	 * スタンドアロンのプレーを作成する。
	 */
	async createStandalonePlay(param: CreateStandalonePlayParameterObject): Promise<PlayEntity> {
		const playId = param.playId;

		if (this.plays[playId])
			return this.plays[playId];

		const play = new PlayEntity({
			gameViewManager: this._gameViewManager,
			amflow: new SocketIOAMFlowClient(socketInstance),
			playId,
			status: "running", // 暫定。standalone プレイは running しかないものとして扱う
			content: this._contentStore.find(param.contentLocator),
			parent: param.parent
		});
		this.plays[playId] = play;

		return play;
	}

	// このメソッドは onPlayCreate の通知を受けた時の処理なので完了を待たない
	private handlePlayCreate = (e: PlayCreateTestbedEvent): Promise<void> => {
		return this.handlePlayCreateImpl(e);
	};

	private handlePlayCreateImpl = async (e: PlayCreateTestbedEvent): Promise<void> => {
		const play = new PlayEntity({
			...e,
			amflow: new SocketIOAMFlowClient(socketInstance),
			gameViewManager: this._gameViewManager,
			content: this._contentStore.find(e.contentLocatorData)
		});
		this.plays[e.playId] = play;
		this._lastPlayId = e.playId;
		if (this._creationWaiters[e.playId]) {
			this._creationWaiters[e.playId](play);
		}
	};

	private handlePlayStatusChange = async (e: PlayStatusChangedTestbedEvent): Promise<void> => {
		const play = this.plays[e.playId];
		play.handlePlayStatusChange(e.playStatus);

		// TODO LocalInstance はここで解放すべき？
		if (e.playStatus === "suspending") {
			await play.teardown();
			delete this.plays[e.playId];
		}
	};

	private handlePlayDurationStateChange = (e: PlayDurationStateChangeTestbedEvent): void => {
		this.plays[e.playId].handlePlayDurationStateChange(e.isPaused, e.duration);
	};

	private handlePlayAudioStateChange = (e: PlayAudioStateChangeTestbedEvent): void => {
		const play = this.plays[e.playId];
		play.handlePlayAudioStateChange(e.audioState);
	};

	private handlePlayerJoin = (e: PlayerJoinTestbedEvent): void => {
		this.plays[e.playId].handlePlayerJoin(e.player);
	};

	private handlePlayerLeave = (e: PlayerLeaveTestbedEvent): void => {
		this.plays[e.playId].handlePlayerLeave(e.playerId);
	};

	private handleClientInstanceAppear = (e: ClientInstanceAppearTestbedEvent): void => {
		this.plays[e.playId].handleClientInstanceAppear(e);
	};

	private handleClientInstanceDisappear = (e: ClientInstanceDisappearTestbedEvent): void => {
		this.plays[e.playId].handleClientInstanceDisappear(e);
	};

	private handleRunnerCreate = (e: RunnerCreateTestbedEvent): void => {
		this.plays[e.playId].handleRunnerCreate(e.runnerId);
	};

	private handleRunnerRemove = (e: RunnerRemoveTestbedEvent): void => {
		this.plays[e.playId].handleRunnerRemove(e.runnerId);
	};

	private handleRunnerPause = (e: RunnerPauseTestbedEvent): void => {
		this.plays[e.playId].handleRunnerPause(/* e.runnerId */);  // runnerIdを扱う処理は未実装
	};

	private handleRunnerResume = (e: RunnerResumeTestbedEvent): void => {
		this.plays[e.playId].handleRunnerResume(/* e.runnerId */);  // runnerIdを扱う処理は未実装
	};

	private handlePutStartPoint = (e: PutStartPointEvent): void => {
		this.plays[e.playId].handleStartPointHeader(e.startPointHeader);
	};
}

import { Trigger } from "@akashic/trigger";
import { observable, action, computed } from "mobx";
import type { PlayerInfoResolverResultMessage } from "../akashic/plugin/CoeLimitedPlugin";
import { storage } from "./storage";

const DEFAULT_LIMIT_MILLISECONDS = 15 * 1000;

export class PlayerInfoResolverUiStore {
	onResolve: Trigger<PlayerInfoResolverResultMessage> = new Trigger();
	@observable isDisplayingResolver: boolean = false;
	@observable remainingMilliSeconds: number = DEFAULT_LIMIT_MILLISECONDS;
	@observable name: string = "";
	@observable guestName: string = "ゲスト" + ((Math.random() * 100) | 0);
	private timerId: number | null = null;

	async assertInitialized(): Promise<void> {
		await storage.assertInitialized();
		this.name = storage.data.playerName;
	}

	@action.bound
	showDialog(limitSeconds?: number): void {
		this.isDisplayingResolver = true;
		// NOTE: この場合、ページリロード時に表示上だけ制限時間がリセットされてしまう(実際はリセットされない)ので、現在時刻ではなくゲームの起動時刻を取得した方が良さそう？
		const startingDateTime = Date.now();
		const limitMilliSeconds = limitSeconds ? (limitSeconds * 1000) : DEFAULT_LIMIT_MILLISECONDS;

		this.timerId = window.setInterval(() => {
			this.setRemainingMilliSeconds(limitMilliSeconds - (Date.now() - startingDateTime));
			if (this.remainingMilliSeconds === 0 && this.timerId != null) {
				this._clearTimerIfNeeded();
				this._fireResolve(false);
			}
		}, 200); // 1s毎だと表示と実際の時間に若干のズレが生まれそうなので、やや間隔短めに残り時間の算出を行う
	};

	@action.bound
	hideDialog(): void {
		this.isDisplayingResolver = false;
		this._clearTimerIfNeeded();
	}

	@action.bound
	finishDialog(accepted: boolean): void {
		this.hideDialog();
		this._fireResolve(accepted);
	}

	@computed
	get remainingSeconds(): number {
		return Math.ceil(this.remainingMilliSeconds / 1000);
	}

	@action
	setRemainingMilliSeconds(ms: number): void {
		this.remainingMilliSeconds = Math.max(0, ms);
	}

	private _clearTimerIfNeeded(): void {
		if (this.timerId != null) {
			window.clearInterval(this.timerId);
			this.timerId = null;
		}
	}

	private _fireResolve(accepted: boolean): void {
		this.onResolve.fire({
			result: {
				name: accepted ? this.name : this.guestName,
				userData: { accepted, premium: storage.data.premium }
			}
		});
	}
}

import type { IObservableArray } from "mobx";
import { action, observable } from "mobx";
import type { ProfilerData, ProfilerName, ProfilerStyleSetting, ProfilerValueResult } from "../common/types/Profiler";

const PROFILER_DATA_LIMIT = 100; // １つのプロファイラが保持できるデータの個数。

export class ProfilerStore {
	@observable profilerDataArray: IObservableArray<ProfilerData>;
	@observable profilerStyleSetting: ProfilerStyleSetting;
	@observable profilerWidth: number; // プロファイラ1つ分の横幅
	@observable profilerHeight: number; // プロファイラ1つ分の縦幅

	constructor() {
		this.profilerDataArray = observable.array([
			{
				name: "fps",
				data: [],
				max: 0,
				min: Number.MAX_VALUE,
				fixed: 2
			},
			{
				name: "skipped",
				data: [],
				max: 0,
				min: Number.MAX_VALUE,
				fixed: 1
			},
			{
				name: "interval",
				data: [],
				max: 0,
				min: Number.MAX_VALUE,
				fixed: 1
			},
			{
				name: "frame",
				data: [],
				max: 0,
				min: Number.MAX_VALUE,
				fixed: 1
			},
			{
				name: "rendering",
				data: [],
				max: 0,
				min: Number.MAX_VALUE,
				fixed: 1
			}
		]);
		// TODO: プロファイラーのサイズ・色等の設定値をserveに適したものにする
		this.profilerStyleSetting = {
			margin: 5,
			padding: 5,
			align: "horizontal",
			bgColor: "gray",
			fontColor: "white",
			fontSize: 17,
			fontMaxColor: "deeppink",
			fontMinColor: "dodgerblue",
			fontMinMaxColor: "black",
			graphColor: "lavender",
			graphWidth: 3,
			graphWidthMargin: 1,
			graphPadding: 5
		};
		this.profilerWidth = 150;
		this.profilerHeight = 61;
	}

	@action
	pushProfilerValueResult (
		name: ProfilerName,
		profileValueResult: ProfilerValueResult
	): void {
		const profilerData = this.profilerDataArray.find(profiler => profiler.name === name);
		if (!profilerData) {
			return;
		}
		const currentValue = profileValueResult.ave;
		profilerData.data.unshift(currentValue);
		if (profilerData.data.length > PROFILER_DATA_LIMIT) {
			profilerData.data.pop();
		}
		if (currentValue < profilerData.min) {
			profilerData.min = currentValue;
		}
		if (profilerData.max < currentValue) {
			profilerData.max = currentValue;
		}
	}
}

