import { observable } from "mobx";
import type { DumpedPlaylog } from "../../../common/types/DumpedPlaylog";
import type { PlayDurationState } from "../../../common/types/PlayDurationState";
import type { GameViewManager } from "../../akashic/GameViewManager";
import type { ServeMemoryAmflowClient } from "../../akashic/ServeMemoryAMFlowClient";
import type { ContentEntity } from "../../store/ContentEntity";
import { PlayEntity } from "../../store/PlayEntity";

export interface PlayStoreParameterObject {
	gameViewManager: GameViewManager;
}

export interface CreatePlayParameterObject {
	playId: string;
	content: ContentEntity;
	amflow: ServeMemoryAmflowClient;
	playlog?: DumpedPlaylog;
	durationState?: PlayDurationState;
}

export class PlayStore {
	@observable plays: Record<string, PlayEntity>;
	private _gameViewManager: GameViewManager;

	constructor(param: PlayStoreParameterObject) {
		this.plays = Object.create(null);
		this._gameViewManager = param.gameViewManager;
	}

	createStandalonePlay = async (param: CreatePlayParameterObject): Promise<PlayEntity> => {
		const { playId, content, amflow, playlog, durationState } = param;

		if (this.plays[playId])
			throw new Error(`Play already exists: ${playId}`);

		const playEntity = new PlayEntity({
			gameViewManager: this._gameViewManager,
			playId,
			status: "running",
			content,
			amflow,
			disableFastForward: !!playlog,
			durationState,
		});
		amflow.onPutStartPoint.add(playEntity.handleStartPointHeader, playEntity);

		this.plays[playId] = playEntity;

		return playEntity;
	};

	deletePlay = async (playId: string): Promise<void> => {
		const play = this.plays[playId];
		if (play == null)
			throw new Error("Play not found: " + playId);

		await play.teardown();
	};
}

import type { ServiceType } from "@akashic/akashic-cli-commons/lib/ServiceType";
import { observable, action, autorun } from "mobx";
import type { AppOptions } from "../../../common/types/AppOptions";
import type { Player } from "../../../common/types/Player";
import type { GameViewManager } from "../../akashic/GameViewManager";
import type { RuntimeWarning } from "../../akashic/RuntimeWarning";
import { apiClient } from "../../api/apiClientInstance";
import { ClientContentLocator } from "../../common/ClientContentLocator";
import type { ScreenSize } from "../../common/types/ScreenSize";
import { ContentStore } from "../../store/ContentStore";
import { DevtoolUiStore } from "../../store/DevtoolUiStore";
import type { LocalInstanceEntity } from "../../store/LocalInstanceEntity";
import { NotificationUiStore } from "../../store/NotificationUiStore";
import type { PlayEntity } from "../../store/PlayEntity";
import { ProfilerStore } from "../../store/ProfilerStore";
import { StartupScreenUiStore } from "../../store/StartupScreenUiStore";
import { storage } from "../../store/storage";
import { ToolBarUiStore } from "../../store/ToolBarUiStore";
import { PlayStore } from "./PlayStore";

export interface StoreParameterObject {
	contentId: string;
	gameViewManager: GameViewManager;
}

export class Store {
	@observable playStore: PlayStore;
	@observable contentStore: ContentStore;
	@observable toolBarUiStore: ToolBarUiStore;
	@observable devtoolUiStore: DevtoolUiStore;
	@observable notificationUiStore: NotificationUiStore;
	@observable startupScreenUiStore: StartupScreenUiStore;
	@observable profilerStore: ProfilerStore;
	@observable appOptions: AppOptions;
	@observable player: Player | null;
	@observable contentLocator: ClientContentLocator;

	@observable currentPlay: PlayEntity | null;
	@observable currentLocalInstance: LocalInstanceEntity | null;
	@observable gameViewSize: ScreenSize;

	private _gameViewManager: GameViewManager;
	private _initializationWaiter: Promise<void>;
	private _warnedTypes: Set<string>;

	constructor(param: StoreParameterObject) {
		this.contentLocator = new ClientContentLocator({ contentId: param.contentId });
		this.contentStore = new ContentStore();
		this.playStore = new PlayStore({ gameViewManager: param.gameViewManager });
		this.toolBarUiStore = new ToolBarUiStore();
		this.devtoolUiStore = new DevtoolUiStore();
		this.notificationUiStore = new NotificationUiStore();
		this.startupScreenUiStore = new StartupScreenUiStore();
		this.profilerStore = new ProfilerStore();
		this.appOptions = null!;
		this.player = null;
		this.currentPlay = null;
		this.currentLocalInstance = null;
		this.gameViewSize = { width: 10, height: 10 }; // ゲーム表示時に更新されるが不具合の際に現象が分かりやすいようサイズをつけておく

		this._gameViewManager = param.gameViewManager;
		this._initializationWaiter = apiClient.getOptions().then(result => {
			this.appOptions = result.data;
		});
		this._warnedTypes = new Set();

		autorun(() => {
			if (!this.toolBarUiStore.fitsToScreen && this.currentLocalInstance?.intrinsicSize) {
				this.setGameViewSize(this.currentLocalInstance.intrinsicSize);
			}
		});
	}

	async assertInitialized(): Promise<unknown> {
		return Promise.allSettled([
			this.contentStore.assertInitialized(),
			this.toolBarUiStore.assertInitialized(),
			storage.assertInitialized(),
			this._initializationWaiter,
		]).then((results) => {
			const hasError = results.some(result => result.status === "rejected");
			if (!hasError) {
				this.player = { id: storage.data.playerId, name: storage.data.playerName };
			}
		});
	}

	@action
	setCurrentLocalInstance(instance: LocalInstanceEntity | null): void {
		if (this.currentLocalInstance === instance)
			return;
		this.currentLocalInstance?.onWarn.remove(this._warn, this);
		this.currentLocalInstance = instance;
		this.currentLocalInstance?.onWarn.add(this._warn, this);
		this.devtoolUiStore.setEntityTrees([]);
		if (this.currentLocalInstance?.intrinsicSize)
			this.setGameViewSize(this.currentLocalInstance.intrinsicSize);
	}

	@action
	setCurrentPlay(play: PlayEntity): void {
		this.currentPlay = play;
	}

	@action
	setGameViewSize(size: ScreenSize): void {
		this.gameViewSize = size;
		this._gameViewManager.setViewSize(size.width, size.height);
	}

	get targetService(): ServiceType {
		return this.appOptions.targetService;
	}

	// FIXME: Store と共通化する
	private _warn(warning: RuntimeWarning): void {
		// すでに通知済みの type なら何もしない
		if (this._warnedTypes.has(warning.type)) return;

		const sandboxConfigWarn = this.currentLocalInstance!.content.sandboxConfig.warn;
		const warningTitle = "Runtime Warning";
		this._warnedTypes.add(warning.type);

		switch (warning.type) {
			case "useMathRandom":
				if (!sandboxConfigWarn || sandboxConfigWarn.useMathRandom !== false) {
					console.warn(`${warning.message}`);
					this.notificationUiStore.setActive({
						type: "error",
						title: warningTitle,
						name: warning.message, // 赤字表示のため name に message を設定
						message: "",
						referenceUrl: warning.referenceUrl,
						referenceMessage: warning.referenceMessage
					});
				}
				break;
			case "useMathSinCosTan":
				if (!sandboxConfigWarn || sandboxConfigWarn.useMathSinCosTan !== false) {
					console.warn(`${warning.message}`);
					this.notificationUiStore.setActive({
						type: "error",
						title: warningTitle,
						name: "",
						message: warning.message,
						referenceUrl: warning.referenceUrl,
						referenceMessage: warning.referenceMessage
					});
				}
				break;
			case "drawOutOfCanvas":
				if (!sandboxConfigWarn || sandboxConfigWarn.drawOutOfCanvas !== false) {
					console.warn(`${warning.message}`);
					this.notificationUiStore.setActive({type: "error", title: warningTitle, message: "", name: warning.message});
				}
				break;
			case "drawDestinationEmpty":
				if (!sandboxConfigWarn || sandboxConfigWarn.drawDestinationEmpty !== false) {
					console.warn(`${warning.message}`);
					this.notificationUiStore.setActive({type: "error", title: warningTitle, message: "", name: warning.message});
				}
				break;
			case "createNonIntegerSurface":
				if (!sandboxConfigWarn || sandboxConfigWarn.createNonIntegerSurface !== false) {
					console.warn(`${warning.message}`);
					this.notificationUiStore.setActive({type: "error", title: warningTitle, message: "", name: warning.message});
				}
				break;
		}
	}
}

import type { OnTickArguments } from "../../akashic/ServeGameContent";
import type { EDumpItem } from "../../common/types/EDumpItem";
import type { NiconicoDevtoolPageType } from "../../view/molecule/NiconicoDevtool";
import type { Store } from "../store/Store";

function consoleLog(value: any): void {
	console.log(value);

	// 暫定便利機能: ダンプついでにしれっとグローバル変数に刺しておく (c.f. Chrome/Firefox の $0)
	// (console からグローバルに格納できる Chrome などでは不要なので暫定)
	(window as any).__testbed.$0 = value;
}

export class DevtoolOperator {
	private store: Store;

	constructor(store: Store) {
		this.store = store;
	}

	toggleForceResetOnSeek = (pauses: boolean): void => {
		this.store.devtoolUiStore.toggleForceResetOnSeek(pauses);
	};

	setHoveredStartPointIndex = (index: number, hover: boolean): void => {
		this.store.devtoolUiStore.setFocusedStartPointHeaderIndex(hover ? index : null);
	};

	dumpStartPointOfIndex = (index: number): Promise<void> => {
		return new Promise((resolve, reject) => {
			const currentPlay = this.store.currentPlay!;
			const frame = currentPlay?.startPointHeaders[index]?.frame;
			if (frame == null) {
				reject();
				return;
			}
			currentPlay.amflow.getStartPoint({ frame }, (err, startPoint) => {
				if (err) {
					console.error(err);
					reject();
					return;
				}
				consoleLog(startPoint);
				resolve();
			});
		});
	};

	updateEntityTrees = (): void => {
		const dumpItems = this.store.currentLocalInstance!.gameContent.dumpEntities();
		this.store.devtoolUiStore.setEntityTrees(dumpItems);
	};

	toggleOpenEntityTreeChildren = (e: EDumpItem): void => {
		this.store.devtoolUiStore.toggleOpenEntityTreeChildren(e);
	};

	setHighlightedEntity = (e: EDumpItem): void => {
		this.store.currentLocalInstance!.gameContent.changeHighlightedEntity(e.id);
	};

	clearHighlightedEntity = (): void => {
		this.store.currentLocalInstance!.gameContent.changeHighlightedEntity(null);
	};

	toggleShowHiddenEntity = (shows: boolean): void => {
		this.store.devtoolUiStore.toggleShowHiddenEntity(shows);
	};

	selectEntityByEDumpItem = (e: EDumpItem): void => {
		this.store.devtoolUiStore.setSelectedEntityId(e.id);
	};

	selectEntityByPoint = (x: number, y: number): void => {
		const gameContent = this.store.currentLocalInstance!.gameContent;
		const eid = gameContent.getEntityIdByPoint(x, y);
		this.store.devtoolUiStore.setSelectedEntityId(eid);
		gameContent.changeHighlightedEntity(eid);
	};

	startEntitySelection = (): void => {
		this.store.devtoolUiStore.toggleIsSelectingEntity(true);
	};

	finishEntitySelection = (x: number, y: number): void => {
		const gameContent = this.store.currentLocalInstance!.gameContent;
		this.updateEntityTrees();
		this.store.devtoolUiStore.toggleIsSelectingEntity(false);
		this.store.devtoolUiStore.setSelectedEntityId(gameContent.getEntityIdByPoint(x, y));
		gameContent.changeHighlightedEntity(null);
	};

	dumpSelectedEntity = (): void => {
		const gameContent = this.store.currentLocalInstance!.gameContent;
		const e = gameContent.getRawEntity(this.store.devtoolUiStore.selectedEntityId!);
		consoleLog(e);
	};

	volumeChangeTo = (vol: number): void => {
		this.store.toolBarUiStore.setAudioVolume(vol);
		this.store.currentLocalInstance!.setMasterVolume(vol);
	};

	toggleAutoSendEvents = (isSend: boolean): void => {
		this.store.devtoolUiStore.toggleAutoSendEvents(isSend);
	};

	toggleUsePreferredTotalTimeLimit = (use: boolean): void => {
		this.store.devtoolUiStore.toggleUsePreferredTotalTimeLimit(use);
	};

	toggleUseStopGame = (use: boolean): void => {
		this.store.devtoolUiStore.toggleUseStopGame(use);
	};

	setSupportedMode = (value: string): void => {
		this.store.devtoolUiStore.setSupportedMode(value);
	};

	setTotalTimeLimitInputValue = (value: number): void => {
		this.store.devtoolUiStore.setTotalTimeLimitInputValue(value);
	};

	setupNiconicoDevtoolValueWatcher = (): void => {
		const gameContent = this.store.currentLocalInstance!.gameContent;
		if (!gameContent.onTick.contains(this.tickHandler, this))
			gameContent.onTick.add(this.tickHandler, this);
	};

	setNiconicoDevtoolActivePage = (pageType: NiconicoDevtoolPageType): void => {
		this.store.devtoolUiStore.setNiconicoToolActivePage(pageType);
	};

	setNiconicoDevtoolSelectorWidth = (w: number): void => {
		this.store.devtoolUiStore.setNiconicoToolSelectorWidth(w);
	};

	private async tickHandler({ game }: OnTickArguments): Promise<void> {
		if (this.store.devtoolUiStore.stopsGameOnTimeout)
			await this.updateRemainingTime();

		if (game.vars && game.vars.gameState) {
			this.store.devtoolUiStore.setScore(game.vars.gameState.score);
			this.store.devtoolUiStore.setPlayThreshold(game.vars.gameState.playThreshold);
			this.store.devtoolUiStore.setClearThreshold(game.vars.gameState.clearThreshold);
		}
	}

	private async updateRemainingTime(): Promise<void> {
		if (!this.store.devtoolUiStore.isAutoSendEvent
			|| this.store.devtoolUiStore.emulatingShinichibaMode !== "ranking"
			|| this.store.currentLocalInstance!.executionMode === "replay"
		) return;

		const dur = this.store.currentPlay!.duration / 1000;
		const totalTimeLimit = this.store.devtoolUiStore.totalTimeLimit;
		if (dur >= totalTimeLimit! && !this.store.currentPlay!.isActivePausing) {
			await this.store.currentPlay!.pauseActive();
		}
	}
}

import type { Store } from "../store/Store";

export class LocalInstanceOperator {
	private store: Store;

	constructor(store: Store) {
		this.store = store;
	}

	previewSeekTo = (time: number): void => {
		this.store.toolBarUiStore.previewSeekTo(time);
	};

	seekTo = async (time: number): Promise<void> => {
		this.store.toolBarUiStore.endPreviewSeek();
		this.switchToReplay(time);

		if (this.store.devtoolUiStore.isForceResetOnSeek) {
			const amflow = this.store.currentPlay!.amflow;
			const sp = await amflow.getStartPointPromise({ timestamp: time + (amflow.getStartedAt() ?? 0)});
			this.store.currentLocalInstance!.reset(sp);
		}
	};

	jumpToStartPointOfIndex = async (index: number): Promise<void> => {
		const { amflow, startPointHeaders } = this.store.currentPlay!;
		const sp = await amflow.getStartPointPromise({ frame: startPointHeaders[index].frame });
		this.store.currentLocalInstance!.reset(sp);
		this.switchToReplay(sp.timestamp - (amflow.getStartedAt() ?? 0));
	};

	togglePause = (pause: boolean): Promise<void> => {
		// NOTE: 本来この処理は PlayStore が持つべきだが、serve と共有の PlayStore は active instance がサーバ上にあることを前提にしたクラスになっている。
		// ここではやむなく PlayEntity と LocalInstanceEntity のメソッドを個別に呼んでいる。
		const executionMode = this.store.currentLocalInstance!.executionMode;
		if (pause) {
			this.store.currentPlay!.handleRunnerPause();
			if (executionMode !== "replay") {
				this.store.currentPlay!.pauseTimekeeper();
			}
		} else {
			this.store.currentPlay!.handleRunnerResume();
			if (executionMode !== "replay") {
				this.store.currentPlay!.startTimekeeper();
			}
		}

		return this.store.currentLocalInstance!.togglePause(pause);
	};

	switchToReplay = (time: number): void => {
		// NOTE: 本来この処理は PlayStore が持つべきだが、serve と共有の PlayStore は active instance がサーバ上にあることを前提にしたクラスになっている。
		// ここではやむなく PlayEntity と LocalInstanceEntity のメソッドを個別に呼んでいる。
		this.store.currentPlay!.pauseTimekeeper();
		this.store.currentPlay!.handleRunnerPause();
		this.store.currentLocalInstance!.setExecutionMode("replay");
		this.store.currentLocalInstance!.setTargetTime(time);
	};

	switchToRealtime = async (): Promise<void> => {
		// NOTE: 本来この処理は PlayStore が持つべきだが、serve と共有の PlayStore は active instance がサーバ上にあることを前提にしたクラスになっている。
		// ここではやむなく PlayEntity と LocalInstanceEntity のメソッドを個別に呼んでいる。
		this.store.currentPlay!.startTimekeeper();
		this.store.currentPlay!.handleRunnerResume();

		const localInstance = this.store.currentLocalInstance!;
		const dump = this.store.currentPlay!.amflow.dump();
		const latestAge = dump.tickList![1];
		const game = this.store.currentLocalInstance!.gameContent.agvGameContent.getGame();

		// NOTE: Replay -> Active Realtime への切り替えは現状想定されていない。
		// そのため Passive + Realtime で最新フレームまで追いついた後に Active Realtime に切り替える。
		localInstance.setExecutionMode("passive");

		await waitForCondition(() => {
			if (game.age > latestAge) {
				localInstance.setExecutionMode("active");
				return true;
			}

			if (localInstance.executionMode !== "passive") {
				// 最新まで追っかけ再生中にシークされた場合は追っかけ処理を中断する
				return true;
			}

			return false;
		});

		await localInstance.resume();
	};

	saveScreenshot = (): void => {
		const data = this.store.currentLocalInstance?.makeScreenshotData();
		downloadBase64(data!);
	};
}

// NOTE: 本来OperatorはDOM操作とは独立しているが、この関数で生成するaタグはGUIのReactと関係なくこの処理で完結する
// ほかに適切な定義場所がないため、ここで実装する
function downloadBase64(data: string): void {
	const link = document.createElement("a");
	link.setAttribute("href", data);
	link.setAttribute("download", "screen.png");
	link.click();
	link.remove();
}

async function waitForCondition(condition: () => boolean): Promise<void> {
	return new Promise((resolve, reject) => {
		const check = (): void => {
			let checked: boolean = false;
			try {
				checked = condition();
			} catch (error) {
				reject(error);
				return;
			}
			if (checked) {
				resolve();
			} else {
				setTimeout(check, 100);
			}
		};
		return check();
	});
}

