function consoleLog(value: any): void {
	console.log(value);

	// 暫定便利機能: ダンプついでにしれっとグローバル変数に刺しておく (c.f. Chrome/Firefox の $0)
	// (console からグローバルに格納できる Chrome などでは不要なので暫定)
	(window as any).__testbed.$0 = value;
}

export class DevtoolOperator {
	private store: Store;

	constructor(store: Store) {
		this.store = store;
	}

	toggleForceResetOnSeek = (pauses: boolean): void => {
		this.store.devtoolUiStore.toggleForceResetOnSeek(pauses);
	};

	setHoveredStartPointIndex = (index: number, hover: boolean): void => {
		this.store.devtoolUiStore.setFocusedStartPointHeaderIndex(hover ? index : null);
	};

	dumpStartPointOfIndex = (index: number): Promise<void> => {
		return new Promise((resolve, reject) => {
			const currentPlay = this.store.currentPlay!;
			const frame = currentPlay?.startPointHeaders[index]?.frame;
			if (frame == null) {
				reject();
				return;
			}
			currentPlay.amflow.getStartPoint({ frame }, (err, startPoint) => {
				if (err) {
					console.error(err);
					reject();
					return;
				}
				consoleLog(startPoint);
				resolve();
			});
		});
	};

	updateEntityTrees = (): void => {
		const dumpItems = this.store.currentLocalInstance!.gameContent.dumpEntities();
		this.store.devtoolUiStore.setEntityTrees(dumpItems);
	};

	toggleOpenEntityTreeChildren = (e: EDumpItem): void => {
		this.store.devtoolUiStore.toggleOpenEntityTreeChildren(e);
	};

	setHighlightedEntity = (e: EDumpItem): void => {
		this.store.currentLocalInstance!.gameContent.changeHighlightedEntity(e.id);
	};

	clearHighlightedEntity = (): void => {
		this.store.currentLocalInstance!.gameContent.changeHighlightedEntity(null);
	};

	toggleShowHiddenEntity = (shows: boolean): void => {
		this.store.devtoolUiStore.toggleShowHiddenEntity(shows);
	};

	selectEntityByEDumpItem = (e: EDumpItem): void => {
		this.store.devtoolUiStore.setSelectedEntityId(e.id);
	};

	selectEntityByPoint = (x: number, y: number): void => {
		const gameContent = this.store.currentLocalInstance!.gameContent;
		const eid = gameContent.getEntityIdByPoint(x, y);
		this.store.devtoolUiStore.setSelectedEntityId(eid);
		gameContent.changeHighlightedEntity(eid);
	};

	startEntitySelection = (): void => {
		this.store.devtoolUiStore.toggleIsSelectingEntity(true);
	};

	finishEntitySelection = (x: number, y: number): void => {
		const gameContent = this.store.currentLocalInstance!.gameContent;
		this.updateEntityTrees();
		this.store.devtoolUiStore.toggleIsSelectingEntity(false);
		this.store.devtoolUiStore.setSelectedEntityId(gameContent.getEntityIdByPoint(x, y));
		gameContent.changeHighlightedEntity(null);
	};

	dumpSelectedEntity = (): void => {
		const gameContent = this.store.currentLocalInstance!.gameContent;
		const e = gameContent.getRawEntity(this.store.devtoolUiStore.selectedEntityId!);
		consoleLog(e);
	};

	// 現在は利用していないが、将来音量調節機能をつける時に使う
	volumeChangeTo = (vol: number): void => {
		this.store.devtoolUiStore.volumeSeekTo(vol);
	};

	// 現在は利用していないが、将来音量調節機能をつける時に使う
	volumeSeekTo = (vol: number): void => {
		this.store.devtoolUiStore.endVolumeSeek(vol);
	};

	toggleAutoSendEvents = (isSend: boolean): void => {
		this.store.devtoolUiStore.toggleAutoSendEvents(isSend);
	};

	toggleUsePreferredTotalTimeLimit = (use: boolean): void => {
		this.store.devtoolUiStore.toggleUsePreferredTotalTimeLimit(use);
	};

	toggleUseStopGame = (use: boolean): void => {
		this.store.devtoolUiStore.toggleUseStopGame(use);
	};

	setSupportedMode = (value: string): void => {
		this.store.devtoolUiStore.setSupportedMode(value);
	};

	setTotalTimeLimitInputValue = (value: number): void => {
		this.store.devtoolUiStore.setTotalTimeLimitInputValue(value);
	};

	createNicoEvent = (): any => {
		const emulatingShinichibaMode = this.store.devtoolUiStore.emulatingShinichibaMode;
		const params: any = {
			"mode": emulatingShinichibaMode
		};
		if (emulatingShinichibaMode === "ranking") {
			params.totalTimeLimit = this.store.devtoolUiStore.totalTimeLimit;
		}
		const event = [[32, 0, "dummy", {
			"type": "start",
			"parameters": params
		}]];
		return event;
	};

	setupNiconicoDevtoolValueWatcher = (): void => {
		const gameContent = this.store.currentLocalInstance!.gameContent;
		if (!gameContent.onTick.contains(this.tickHandler, this))
			gameContent.onTick.add(this.tickHandler, this);
	};

	setNiconicoDevtoolActivePage = (pageType: NiconicoDevtoolPageType): void => {
		this.store.devtoolUiStore.setNiconicoToolActivePage(pageType);
	};

	setNiconicoDevtoolSelectorWidth = (w: number): void => {
		this.store.devtoolUiStore.setNiconicoToolSelectorWidth(w);
	};

	resetCommentPage = (
		templates: string[],
		senderType: NiconicoDevtoolCommentPageSenderType,
		senderLimitation: NiconicoDevtoolCommentPageSenderLimitation
	): void => {
		const commentPageStore = this.store.devtoolUiStore.commentPage;
		commentPageStore.resetComments();
		commentPageStore.setTemplates(templates);
		commentPageStore.setIsEnabled(false);
		commentPageStore.setSenderType(senderType);
		commentPageStore.setSenderLimitation(senderLimitation);
	};

	setCommentPageIsEnabled = (isEnabled: boolean): void => {
		this.store.devtoolUiStore.commentPage.setIsEnabled(isEnabled);
	};

	setCommentPageSenderType = (senderType: NiconicoDevtoolCommentPageSenderType): void => {
		this.store.devtoolUiStore.commentPage.setSenderType(senderType);
	};

	setCommentPageCommandInput = (input: string): void => {
		this.store.devtoolUiStore.commentPage.setCommandInput(input);
	};

	setCommentPageCommentInput = (input: string): void => {
		this.store.devtoolUiStore.commentPage.setCommentInput(input);
	};

	startWatchNamagameComment = (): void => {
		this.store.currentLocalInstance?.gameContent.onTick.add(this.namagameCommentWatcher);
	};

	stopWatchNamagameComment = (): void => {
		this.store.currentLocalInstance?.gameContent.onTick.remove(this.namagameCommentWatcher);
	};

	private namagameCommentWatcher = ({ events }: OnTickArguments): void => {
		if (!events) return;
		for (let i = 0; i < events.length; ++i) {
			const ev = events[i];
			if (isNamagameCommentEvent(ev))
				this.store.devtoolUiStore.commentPage.addComments(ev[MessageEventIndexData].comments);
		}
	};

	private async tickHandler({ game }: OnTickArguments): Promise<void> {
		if (this.store.devtoolUiStore.stopsGameOnTimeout)
			await this.updateRemainingTime();

		if (game.vars && game.vars.gameState) {
			this.store.devtoolUiStore.setScore(game.vars.gameState.score);
			this.store.devtoolUiStore.setPlayThreshold(game.vars.gameState.playThreshold);
			this.store.devtoolUiStore.setClearThreshold(game.vars.gameState.clearThreshold);
		}
	}

	private async updateRemainingTime(): Promise<void> {
		if (!this.store.devtoolUiStore.isAutoSendEvent
			|| this.store.devtoolUiStore.emulatingShinichibaMode !== "ranking"
			|| this.store.currentLocalInstance!.executionMode === "replay"
		) return;

		const dur = this.store.currentPlay!.duration / 1000;
		const totalTimeLimit = this.store.devtoolUiStore.totalTimeLimit;
		if (dur >= totalTimeLimit! && !this.store.currentPlay!.isActivePausing) {
			await this.store.currentPlay!.pauseActive();
		}
	}
}

import type { Store } from "../store/Store";

export class LocalInstanceOperator {
	private store: Store;

	constructor(store: Store) {
		this.store = store;
	}

	previewSeekTo = (time: number): void => {
		this.store.toolBarUiStore.previewSeekTo(time);
	};

	seekTo = async (time: number): Promise<void> => {
		this.store.toolBarUiStore.endPreviewSeek();
		this.switchToReplay(time);

		if (this.store.devtoolUiStore.isForceResetOnSeek) {
			const amflow = this.store.currentPlay!.amflow;
			const sp = await amflow.getStartPointPromise({ timestamp: time + (amflow.getStartedAt() ?? 0)});
			this.store.currentLocalInstance!.reset(sp);
		}
	};

	jumpToStartPointOfIndex = async (index: number): Promise<void> => {
		const { amflow, startPointHeaders } = this.store.currentPlay!;
		const sp = await amflow.getStartPointPromise({ frame: startPointHeaders[index].frame });
		this.store.currentLocalInstance!.reset(sp);
		this.switchToReplay(sp.timestamp - (amflow.getStartedAt() ?? 0));
	};

	resetByAge = async (age: number): Promise<void> => {
		const sp = await this.store.currentPlay!.amflow.getStartPointPromise({ frame: age });
		this.store.currentLocalInstance!.reset(sp);
	};

	togglePause = (pause: boolean): Promise<void> => {
		return this.store.currentLocalInstance!.togglePause(pause);
	};

	switchToReplay = (time: number): void => {
		this.store.currentLocalInstance!.setExecutionMode("replay");
		this.store.currentLocalInstance!.setTargetTime(time);
	};

	switchToRealtime = (): Promise<void> => {
		this.store.currentLocalInstance!.setExecutionMode("passive");
		return this.store.currentLocalInstance!.resume();
	};

	saveScreenshot = (): void => {
		const data = this.store.currentLocalInstance?.makeScreenshotData();
		downloadBase64(data!);
	};
}

// NOTE: 本来OperatorはDOM操作とは独立しているが、この関数で生成するaタグはGUIのReactと関係なくこの処理で完結する
// ほかに適切な定義場所がないため、ここで実装する
function downloadBase64(data: string): void {
	const link = document.createElement("a");
	link.setAttribute("href", data);
	link.setAttribute("download", "screen.png");
	link.click();
	link.remove();
}

import type { NormalizedSandboxConfiguration } from "@akashic/sandbox-configuration";
import { isServiceTypeNicoliveLike } from "../../common/targetServiceUtil";
import type { SandboxConfigExternalDefinition } from "../../common/types/NamagameCommentConfig";
import type { Player } from "../../common/types/Player";
import type { PlayBroadcastTestbedEvent } from "../../common/types/TestbedEvent";
import type { GameViewManager } from "../akashic/GameViewManager";
import type { PlayerInfoResolverResultMessage } from "../akashic/plugin/CoeLimitedPlugin";
import { CoeLimitedPlugin } from "../akashic/plugin/CoeLimitedPlugin";
import type { CreateCoeLocalInstanceParameterObject } from "../akashic/plugin/CoePlugin";
import { CoePlugin } from "../akashic/plugin/CoePlugin";
import { NicoPlugin } from "../akashic/plugin/NicoPlugin";
import { SendPlugin } from "../akashic/plugin/SendPlugin";
import { apiClient } from "../api/apiClientInstance";
import * as Subscriber from "../api/Subscriber";
import { ClientContentLocator } from "../common/ClientContentLocator";
import { createSessionParameter } from "../common/createSessionParameter";
import { queryParameters as query } from "../common/queryParameters";
import type { ProfilerValue } from "../common/types/Profiler";
import type { ScreenSize } from "../common/types/ScreenSize";
import type { LocalInstanceEntity } from "../store/LocalInstanceEntity";
import type { PlayEntity } from "../store/PlayEntity";
import type { Store } from "../store/Store";
import { DevtoolOperator } from "./DevtoolOperator";
import { LocalInstanceOperator } from "./LocalInstanceOperator";
import { PlayOperator } from "./PlayOperator";
import { UiOperator } from "./UiOperator";

export interface OperatorParameterObject {
	store: Store;
	gameViewManager: GameViewManager;
}

export interface StartContentParameterObject {
	joinsSelf: boolean;
	instanceArgument: any;
}

export class Operator {
	play: PlayOperator;
	localInstance: LocalInstanceOperator;
	ui: UiOperator;
	devtool: DevtoolOperator;
	private store: Store;
	private gameViewManager: GameViewManager;

	constructor(param: OperatorParameterObject) {
		const store = param.store;
		this.play = new PlayOperator(store);
		this.localInstance = new LocalInstanceOperator(store);
		this.ui = new UiOperator(store);
		this.devtool = new DevtoolOperator(store);
		this.store = param.store;
		this.gameViewManager = param.gameViewManager;

		Subscriber.onBroadcast.add(this._handleBroadcast);
	}

	assertInitialized(): Promise<unknown> {
		return this.store.assertInitialized();
	}

	async bootstrap(contentLocator?: ClientContentLocator): Promise<void> {
		await this._initializePlugins(contentLocator || this.store.contentStore.defaultContent().locator);
		const store = this.store;
		const initialJoinPlayer = (isServiceTypeNicoliveLike(store.targetService) && store.player) || undefined;
		let play: PlayEntity | null = null;
		if (query.playId != null) {
			play = store.playStore.plays[query.playId];
			if (!play) {
				throw new Error(`play(id: ${query.playId}) is not found.`);
			}
		} else if (contentLocator) {
			play = await this._createServerLoop(contentLocator, initialJoinPlayer, false, false);
		} else {
			play = store.playStore.getLastPlay();
			if (!play) {
				const loc = store.contentStore.defaultContent().locator;
				play = await this._createServerLoop(loc, initialJoinPlayer, false, false); // TODO: (起動時の最初のプレイで) audioState を指定する方法
			}
		}
		await this.setCurrentPlay(play);

		if (query.mode === "replay") {
			if (query.replayResetAge != null) {
				await this.localInstance.resetByAge(query.replayResetAge);
			}
			if (query.replayTargetTime != null) {
				this.store.currentLocalInstance!.setTargetTime(query.replayTargetTime);
			}
		}

		if (query.paused) {
			store.currentLocalInstance!.targetTimePause();
		}

		const gameJson = this.store.contentStore.defaultContent().gameJson!;
		const features = gameJson.environment?.features;
		const enableWebAssembly = features?.includes("WebAssembly") || store.appOptions.disableFeatCheck;
		if (!enableWebAssembly) {
			Object.defineProperty(window, "WebAssembly", {
				get: function() {
					throw new Error("If you use WebAssembly, please add \"environment.features:[\"WebAssembly\"]\" to game.json");
				}
			});
		}
	}

	setCurrentPlay = async (play: PlayEntity): Promise<void> => {
		const store = this.store;
		if (store.currentPlay === play)
			return;

		if (store.currentPlay) {
			await store.currentPlay.deleteAllLocalInstances();
			store.setCurrentLocalInstance(null);
		}

		// TODO play からコンテンツを引くべき？

		store.setCurrentPlay(play);

		const isServiceNicolive = isServiceTypeNicoliveLike(store.targetService);
		const isNicoliveBroadcaster = isServiceNicolive && play.joinedPlayerTable.has(store.player!.id);

		let argument = undefined;
		if (query.argumentsValue) {
			argument = JSON.parse(query.argumentsValue);
			store.startupScreenUiStore.setInstanceArgumentEditContent(query.argumentsValue, true);
		} else if (query.argumentsName && !!store.currentPlay!.content.argumentsTable[query.argumentsName]) {
			argument = JSON.parse(store.currentPlay!.content.argumentsTable[query.argumentsName]);
			this.ui.selectInstanceArguments(query.argumentsName, true);
		} else if (isServiceNicolive) {
			argument = this._createInstanceArgumentForNicolive(isNicoliveBroadcaster);
		}

		const sandboxConfig = play.content.sandboxConfig as NormalizedSandboxConfiguration & SandboxConfigExternalDefinition;
		const commentTemplateNames = Object.keys(sandboxConfig.external?.namagameComment?.templates || []);
		this.devtool.resetCommentPage(
			commentTemplateNames,
			isNicoliveBroadcaster ? "broadcaster" : "anonymous",
			isServiceNicolive ? (isNicoliveBroadcaster ? "broadcaster" : "audience") : "none",
		);

		if (store.appOptions.autoStart) {
			await this.startContent({
				joinsSelf: false,
				instanceArgument: argument
			});
		}
	};

	startContent = async (params?: StartContentParameterObject): Promise<void> => {
		const store = this.store;
		const play = store.currentPlay;
		const tokenResult = await apiClient.createPlayToken(play!.playId, store.player!.id, false, store.player!.name);
		const instance = await play!.createLocalInstance({
			playId: play!.playId,
			playToken: tokenResult.data.playToken,
			playlogServerUrl: "dummy-playlog-server-url",
			executionMode: query.mode === "replay" ? "replay" : "passive",
			player: store.player!,
			argument: params != null ? params.instanceArgument : undefined,
			proxyAudio: store.appOptions.proxyAudio,
			runInIframe: store.appOptions.runInIframe,
			resizeGameView: true
		});
		instance.onStop.addOnce(this._endPlayerInfoResolver);
		store.setCurrentLocalInstance(instance);
		await instance.start();
		instance.setMasterVolume(store.toolBarUiStore.audioVolume);
		instance.setProfilerValueTrigger((value: ProfilerValue) => {
			this.store.profilerStore.pushProfilerValueResult("fps", value.framePerSecond);
			this.store.profilerStore.pushProfilerValueResult("skipped", value.skippedFrameCount);
			this.store.profilerStore.pushProfilerValueResult("interval", value.rawFrameInterval);
			this.store.profilerStore.pushProfilerValueResult("frame", value.frameTime);
			this.store.profilerStore.pushProfilerValueResult("rendering", value.renderingTime);
		});

		this.store.devtoolUiStore.initTotalTimeLimit(play!.content.preferredSessionParameters.totalTimeLimit!);
		this.devtool.setupNiconicoDevtoolValueWatcher();

		if (instance.content.gameJson?.environment?.external?.namagameComment) {
			this.devtool.setCommentPageIsEnabled(true);
			this.devtool.startWatchNamagameComment();
		} else {
			this.devtool.setCommentPageIsEnabled(false);
		}

		if (params != null && params.joinsSelf) {
			store.currentPlay!.join(store.player!.id, store.player!.name);
		}
	};

	// TODO: このメソッドの処理は本来サーバー側で行うべき
	restartWithNewPlay = async (): Promise<void> => {
		await this.store!.currentPlay!.content.updateSandboxConfig();
		const inheritsJoined = isServiceTypeNicoliveLike(this.store.targetService);
		const play = await this._createServerLoop(this.store.currentPlay!.content.locator, undefined, inheritsJoined, true);
		await this.store.currentPlay!.deleteAllServerInstances();
		await apiClient.broadcast(this.store.currentPlay!.playId, { type: "switchPlay", nextPlayId: play.playId });
		this.ui.hideNotification();
	};

	setGameViewSize = (size: ScreenSize): void => {
		this.store.setGameViewSize(size);
	};

	private async _createServerLoop(
		contentLocator: ClientContentLocator,
		initialJoinPlayer: Player | undefined,
		inheritsJoinedFromLatest: boolean,
		inheritsAudioFromLatest: boolean
	): Promise<PlayEntity> {
		const content = this.store.contentStore.find(contentLocator);
		const play = await this.store.playStore.createPlay({
			contentLocator,
			initialJoinPlayer,
			inheritsJoinedFromLatest,
			inheritsAudioFromLatest
		});
		const tokenResult = await apiClient.createPlayToken(play.playId, "", true);  // TODO 空文字列でなくnullを使う
		const { pauseActive } = this.store.appOptions;
		await play.createServerInstance({ playToken: tokenResult.data.playToken, isPaused: pauseActive });
		if (!pauseActive)
			await apiClient.resumePlayDuration(play.playId);

		// autoSendEvents
		const sandboxConfig = content.sandboxConfig;

		const { events, autoSendEventName } = sandboxConfig;
		if (events && autoSendEventName && events[autoSendEventName] instanceof Array) {
			events[autoSendEventName].forEach((pev: any) => play.amflow.enqueueEvent(pev));
		} else if (!autoSendEventName && isServiceTypeNicoliveLike(this.store.targetService)) {
			play.amflow.enqueueEvent(createSessionParameter(this.store.targetService)); // セッションパラメータを送る
		}

		if (this.store.devtoolUiStore.isAutoSendEvent) {
			this.store.devtoolUiStore.initTotalTimeLimit(play.content.preferredSessionParameters.totalTimeLimit!);
			const nicoEvent = this.devtool.createNicoEvent();
			nicoEvent.forEach((pev: any) => play.amflow.enqueueEvent(pev));
		}

		return play;
	}

	private async _createClientLoop(contentUrl: string, playId: string): Promise<PlayEntity> {
		const play = await this.store.playStore.createStandalonePlay({
			contentLocator: new ClientContentLocator({ path: contentUrl }),
			playId
		});
		return play;
	}

	private _handleBroadcast = async (arg: PlayBroadcastTestbedEvent): Promise<void> => {
		try {
			switch (arg.message.type) {
				case "switchPlay":  // TODO typeを型づける
					if (this.store.currentPlay!.playId === arg.playId) {
						await this.setCurrentPlay(this.store.playStore.plays[arg.message.nextPlayId]);
					}
					break;
				default:
					throw new Error("invalid type: " + arg.message.type);
			}
		} catch (e) {
			console.error("_handleBroadcast()", e);
		}
	};

	private _createInstanceArgumentForNicolive(isBroadcaster: boolean): any {
		return {
			coe: {
				permission: {
					advance: false,
					advanceRequest: isBroadcaster,
					aggregation: false
				},
				roles: isBroadcaster ? ["broadcaster"] : [],
				debugMode: true
			}
		};
	};

	//  TODO: 複数のコンテンツ対応。引数の contentLocator は複数コンテンツに対応していないが暫定とする
	private async _initializePlugins(contentLocator: ClientContentLocator): Promise<void> {
		this.gameViewManager.registerExternalPlugin(new NicoPlugin());
		this.gameViewManager.registerExternalPlugin(new SendPlugin());
		this.gameViewManager.registerExternalPlugin(new CoePlugin({
			onLocalInstanceCreate: this._createLocalSessionInstance,
			onLocalInstanceDelete: this._deleteLocalSessionInstance
		}));

		if (typeof agvplugin !== "undefined") {
			this.gameViewManager.registerExternalPlugin(new agvplugin.CoeLimitedPlugin());
			this.gameViewManager.registerExternalPlugin(new agvplugin.AgvSupplementPlugin());
			this.gameViewManager.registerExternalPlugin(new agvplugin.InstanceStoragePlugin({
				storage: window.sessionStorage
			}));
			if (agvplugin.InstanceStorageLimitedPlugin)
				this.gameViewManager.registerExternalPlugin(new agvplugin.InstanceStorageLimitedPlugin());
		} else {
			this.gameViewManager.registerExternalPlugin(new CoeLimitedPlugin({
				startPlayerInfoResolver: this._startPlayerInfoResolver,
				endPlayerInfoResolver: this._endPlayerInfoResolver
			}));
			this.gameViewManager.registerExternalPlugin(new agvPublicPlugins.InstanceStoragePlugin({
				storage: window.sessionStorage,
			}));
			this.gameViewManager.registerExternalPlugin(new agvPublicPlugins.InstanceStorageLimitedPlugin());
		}

		const content = this.store.contentStore.find(contentLocator);
		const sandboxConfig = content.sandboxConfig;
		const client = sandboxConfig?.client;
		if (client?.external) {
			for (const pluginName of Object.keys(client.external)) {
				await this._loadScript(`/contents/${contentLocator.contentId}/sandboxConfig/plugins/${pluginName}`);

				const pluginObj = {
					name: pluginName,
					onload: function (game: any, _dataBus: unknown, _gameContent: agv.GameContent) {
						game.external[pluginName] = (window as any).__testbed.pluginFuncs[pluginName]()();
					}
				};
				this.gameViewManager.registerExternalPlugin(pluginObj);
			}
		}
	}

	private _createLocalSessionInstance = async (params: CreateCoeLocalInstanceParameterObject): Promise<LocalInstanceEntity> => {
		// TODO: local === true のみ対応
		if (!params.local) {
			// TODO: エラーハンドリング
			throw new Error("Not supported");
		}
		const childPlay = await this._createClientLoop(params.contentUrl!, params.playId);
		const localInstance = await childPlay.createLocalInstance({
			player: this.store.player!,
			playId: params.playId,
			executionMode: "active",
			argument: params.argument,
			initialEvents: params.initialEvents,
			proxyAudio: this.store.appOptions.proxyAudio,
			runInIframe: this.store.appOptions.runInIframe,
			useNonDebuggableScript: true,
			resizeGameView: false
		});
		await localInstance.start();
		return localInstance;
	};

	private _deleteLocalSessionInstance = async (playId: string): Promise<void> => {
		const play = this.store.playStore.plays[playId];
		if (play == null) {
			throw new Error("Play not found" + playId);
		}
		await play.teardown();
	};

	private _startPlayerInfoResolver = (limitSeconds: number | undefined, cb: (res: PlayerInfoResolverResultMessage) => void): void => {
		this.store.playerInfoResolverUiStore.showDialog(limitSeconds);
		this.store.playerInfoResolverUiStore.onResolve.addOnce(cb);
	};

	private _endPlayerInfoResolver = (): void => {
		this.store.playerInfoResolverUiStore.hideDialog();
	};

	private _loadScript(scriptPath: string): Promise<void> {
		return new Promise((resolve, reject) => {
			const script = document.createElement("script");
			script.src = scriptPath;
			script.onload = () => {
				resolve();
			};
			script.onerror = function (e) {
				reject(e);
			};
			document.body.append(script);
		});
	}
}

import { toJS as mobxToJS } from "mobx";
import type { PlayPatchApiResponse } from "../../common/types/ApiResponse";
import type { NamagameCommentEventComment } from "../../common/types/NamagameCommentPlugin";
import * as Subscriber from "../api/Subscriber";
import type { Store } from "../store/Store";

const WINDOW_HEIGHT_MARGIN = 100;
const WINDOW_WIDTH_MARGIN = 40;
const TOOL_BAR_HEIGHT = 33;  // 厳密なツールバーの高さはフォントやウィンドウ幅に依存するが、ツールバーが 1 行の場合の概ねのサイズで決め打ちとする。

export class PlayOperator {
	private store: Store;
	private screenshotCount = 0;

	constructor(store: Store) {
		this.store = store;
		Subscriber.onDisconnect.add(this.handleSocketDisconnect);
	}

	togglePauseActive = (pauses: boolean): Promise<PlayPatchApiResponse> => {
		if (pauses) {
			return this.store.currentPlay!.pauseActive();
		} else {
			return this.store.currentPlay!.resumeActive();
		}
	};

	step = (): Promise<PlayPatchApiResponse> => {
		return this.store.currentPlay!.stepActive();
	};

	toggleJoinLeaveSelf = (toJoin: boolean): void => {
		const player = this.store.player!;
		if (toJoin) {
			this.store.currentPlay!.join(player.id, player.name);
		} else {
			this.store.currentPlay!.leave(player.id);
		}
	};

	sendScreenshotEvent = (): void => {
		this.store.currentPlay!.sendScenarioEvent(
			this.store.player!.id,
			{
				type: "scenario",
				command: {
					name: "screenshot",
					options: { fileName: `screenshot_${this.screenshotCount}.png` }
				}
			}
		);
		this.screenshotCount++;
	};

	sendFinishEvent = (): void => {
		this.store.currentPlay!.sendScenarioEvent(
			this.store.player!.id,
			{
				type: "scenario",
				command: {
					name: "finish"
				}
			}
		);
	};

	openNewClientInstance = (): void => {
		this.openClientInstance();
	};

	openSameClientInstance = (): void => {
		this.openClientInstance(this.store.player!.id);
	};

	closeThisWindowIfNeeded = (): void => {
		if (this.store.appOptions.preserveDisconnected)  return;

		if (window.opener) {
			window.close();
		}
	};

	sendRegisteredEvent = (eventName: string): void => {
		const sandboxConfig = this.store.currentLocalInstance!.content.sandboxConfig;
		const pevs = sandboxConfig.events ? sandboxConfig.events[eventName] : [];
		const events = mobxToJS(pevs); // untrusted の場合 proxy オブジェクト送信でエラーとなるため js オブジェクトへ変換して送信
		this.store.currentLocalInstance!.gameContent.sendEvents(events);
	};

	sendEditorEvent = (): void => {
		// TODO: 入力された JSON が不正な値の場合に Send ボタンを disabled にし、このパスでは正常な値が取れるようにする。
		if (this.store.devtoolUiStore.eventEditContent.trim() === "")  return;
		let pevs;
		try {
			pevs = JSON.parse(this.store.devtoolUiStore.eventEditContent);
		} catch (e) {
			throw new Error(e);
		}
		this.store.currentLocalInstance!.gameContent.sendEvents(pevs);
	};

	downloadPlaylog = (): void => {
		const playId = this.store.currentPlay!.playId;
		this.downloadFile(`/api/plays/${playId}/playlog`, `playlog_${playId}.json`);
	};

	muteAll = (): Promise<void> => {
		return this.store.currentPlay!.muteAll();
	};

	muteOthers = (): Promise<void> => {
		return this.store.currentPlay!.muteOthers();
	};

	unmuteAll = (): Promise<void> => {
		return this.store.currentPlay!.unmuteAll();
	};

	sendEditorNamagameCommentEvent = async (): Promise<void> => {
		const { currentPlay } = this.store;
		const { commandInput: command, commentInput: comment, senderType } = this.store.devtoolUiStore.commentPage;
		if (!currentPlay || !comment) return;

		const vpos = Math.floor(currentPlay.duration / 10);
		const cmt: NamagameCommentEventComment =
			senderType === "broadcaster" ?
				{ command, comment, isAnonymous: false } :
			senderType === "anonymous" ?
				{ command, comment, isAnonymous: true, userID: this.store.hashedPlayerId!, vpos } :
				{ command, comment, isAnonymous: false, userID: this.store.player?.id, vpos };
		this.store.devtoolUiStore.commentPage.setCommentInput("");
		return currentPlay.sendNamagameComment(cmt);
	};

	sendRegisteredNamagameCommentEvent = async (name: string): Promise<void> => {
		return this.store.currentPlay?.sendNamagameCommentByTemplate(name);
	};

	// 指定したURLからファイルをダウンロードする
	private downloadFile = (url: string, fileName: string): void => {
		const a = document.createElement("a");
		document.body.appendChild(a);
		a.href = url;
		a.download = fileName;
		a.click();
		document.body.removeChild(a);
	};

	private openClientInstance = (playerId?: string): void => {
		const { top, left, width, height } = this.calcWindowLayout();
		// Mac Chrome で正しく動作しないのと、親ウィンドウかどうかの判別をしたいことがあるので noopener は付けない。
		// 代わりに ignoreSession を指定して自前でセッションストレージをウィンドウごとに使い分ける (ref. ../store/storage.ts)
		let url = `${window.location.pathname}?ignoreSession=1&experimentalIsChildWindow=1`;
		if (playerId) {
			url += `&playerId=${playerId}`;
		}
		window.open(url, "_blank", `width=${width},height=${height},top=${top},left=${left}`);
	};

	private calcWindowLayout(): { top: number; left: number; width: number; height: number } {
		let restoreData;
		if (this.store.appOptions.experimentalOpen) {
			// localStorage から保存した window 情報を取得し、window の位置/サイズを復元して表示。
			// 取得した情報は localStorage から除去する。
			const name = "win_" + this.store.contentStore.defaultContent().gameLocationKey;
			const saveDataStr = localStorage.getItem(name);
			const saveDataAry = saveDataStr ? JSON.parse(saveDataStr) : [];
			restoreData = saveDataAry.shift();
			localStorage.setItem(name, JSON.stringify(saveDataAry));
		}

		const top = typeof restoreData?.y === "number" ? restoreData?.y : 0;
		const left = typeof restoreData?.y === "number" ? restoreData?.x : 0;
		let width;
		let height;

		const sandboxConfig = this.store.contentStore.defaultContent().sandboxConfig;
		const windowSize = sandboxConfig.windowSize;

		const calcAutoSize = (): { width: number; height: number } => {
			const gameJson = this.store.contentStore.defaultContent().gameJson!;
			const width = gameJson.width + WINDOW_WIDTH_MARGIN;
			const height = gameJson.height + TOOL_BAR_HEIGHT + WINDOW_HEIGHT_MARGIN;
			return {width, height};
		};

		if (windowSize === "auto") {
			const autoSize = calcAutoSize();
			width = autoSize.width;
			height = autoSize.height;
		} else if (typeof windowSize === "object") {
			const autoSize = calcAutoSize();
			width = windowSize.width ?? autoSize.width;
			height = windowSize.height ?? autoSize.height;
		} else {
			width = typeof restoreData?.width === "number" ? restoreData?.width : window.innerWidth;
			height = typeof restoreData?.height === "number" ? restoreData?.height : window.innerHeight;
		}

		return { top, left, width, height };
	}

	private handleSocketDisconnect = (): void => {
		this.store.setSocketDisconnect(true);
		this.closeThisWindowIfNeeded();
	};
}

