import * as fs from "fs";

const FIRST_FEW_BYTES = 8000;

/**
 * @see https://qiita.com/okuoku/items/a21bfa68570ca67817ac
 */
export function isBinaryFile(filePath: string): boolean {
	let fd: number | null = null;
	try {
		fd = fs.openSync(filePath, "r");
		const buff = Buffer.alloc(FIRST_FEW_BYTES);
		const bytes = fs.readSync(fd, buff, 0, FIRST_FEW_BYTES, 0);
		const index = buff.indexOf(0x00);
		// ファイルが8000B以下の場合、余剰なバッファの0埋めされた箇所をindexが指すことがある。
		// そのため、実際に読んだファイルサイズの内側にindexがあることも条件とする。
		return index !== -1 && index < bytes;
	} catch (error) {
		throw error;
	} finally {
		if (fd != null) fs.closeSync(fd);

	}
}

import * as fs from "fs";
import * as path from "path";
import { ConsoleLogger } from "@akashic/akashic-cli-commons/lib/ConsoleLogger.js";
import { readJSON, writeJSON } from "@akashic/akashic-cli-commons/lib/FileSystem.js";
import type { Logger } from "@akashic/akashic-cli-commons/lib/Logger.js";
import type { AssetConfiguration, GameConfiguration } from "@akashic/game-configuration";
import { AssetModule } from "./AssetModule.js";
import { isBinaryFile } from "./isBinaryFile.js";
import { knownExtensionAssetFilter, scanAudioAssets, scanBinaryAssets, scanImageAssets, scanScriptAssets,
	scanTextAssets, scanVectorImageAssets, defaultTextAssetFilter } from "./scanUtils.js";
import type { AssetExtension, AssetScanDirectoryTable, AssetTargetType, LibConfiguration } from "./types.js";

export interface ScanAssetParameterObject {
	/**
	 * 更新する対象。
	 * `"image"`, `"audio"`, `"script"`, `"binary"`, `"text"`, `"all"` のいずれか。
	 * 省略された場合、 `"all"` 。
	 */
	target?: AssetTargetType;

	/**
	 * 作業ディレクトリ。
	 * 省略された場合、 `process.cwd()` 。
	 */
	cwd?: string;

	/**
	 * コマンドの出力を受け取るロガー。
	 * 省略された場合、akashic-cli-commons の `new ConsoleLogger()` 。
	 */
	logger?: Logger;

	/**
	 * `globalScripts` に外部モジュールの package.json のパスを含めるかどうか。
	 * 省略された場合、 `false` 。
	 */
	noOmitPackagejson?: boolean;

	/**
	 * アセットIDをアセットのパスから解決するかどうか。
	 * 省略された場合、 `false` 。
	 */
	resolveAssetIdsFromPath?: boolean;

	/**
	 * すべてのアセット定義をスキャンし直すかどうか。
	 * 省略された場合、 `false` 。
	 */
	forceUpdate?: boolean;

	/**
	 * アセットIDを強制的にスキャンし直すかどうか。
	 * 省略された場合、 `false` 。
	 */
	forceUpdateAssetIds?: boolean;

	/**
	 * アセットIDに拡張子を含めるかどうか。
	 * ただし音声アセットについては拡張子が含まれない点に注意。
	 * 省略された場合、 `false` 。
	 */
	includeExtensionToAssetId?: boolean;

	/*
	 * 各アセットを取得するパス。
	 */
	assetScanDirectoryTable?: AssetScanDirectoryTable;

	/**
	 * 各アセットとして扱う拡張子。
	 * 省略された場合、 `[]` 。
	 */
	assetExtension?: AssetExtension;
}

interface NormalizedScanAssetParameterObject extends Required<Omit<ScanAssetParameterObject, "AssetScanDirectoryTable">> {
	assetScanDirectoryTable: Required<Omit<AssetScanDirectoryTable, "binary">>;
}

export function _completeScanAssetParameterObject(param: ScanAssetParameterObject): NormalizedScanAssetParameterObject {
	const assetScanDirectoryTable = {
		audio: param.assetScanDirectoryTable?.audio ?? ["audio"],
		image: param.assetScanDirectoryTable?.image ?? ["image"],
		script: param.assetScanDirectoryTable?.script ?? ["script"],
		text: param.assetScanDirectoryTable?.text ?? ["text"]
	};
	const assetExtension = param.assetExtension ?? {};
	assetExtension.text = assetExtension.text ?? [];

	return {
		target: param.target ?? "all",
		cwd: param.cwd ?? process.cwd(),
		logger: param.logger ?? new ConsoleLogger(),
		resolveAssetIdsFromPath: !!param.resolveAssetIdsFromPath,
		forceUpdate: !!param.forceUpdate,
		forceUpdateAssetIds: !!param.forceUpdateAssetIds,
		includeExtensionToAssetId: !!param.includeExtensionToAssetId,
		noOmitPackagejson: !!param.noOmitPackagejson,
		assetScanDirectoryTable,
		assetExtension
	};
}

export async function scanAsset(p: ScanAssetParameterObject): Promise<void> {
	const param = _completeScanAssetParameterObject(p);

	try {
		const logger = param.logger;
		const target = param.target;
		const resolveAssetIdsFromPath = param.resolveAssetIdsFromPath;
		const includeExtensionToAssetId = param.includeExtensionToAssetId;
		const gamePath = path.join(param.cwd, "game.json");
		const akashicLibPath = path.join(param.cwd, "./akashic-lib.json");
		const base =  param.cwd;

		if (!fs.existsSync(gamePath) && !fs.existsSync(akashicLibPath)) {
			throw new Error("game.json or akashic-lib.json does not exists");
		}

		const audioDirs = param.assetScanDirectoryTable.audio.concat();
		const imageDirs = param.assetScanDirectoryTable.image.concat();
		const scriptDirs = param.assetScanDirectoryTable.script.concat();
		const textDirs = param.assetScanDirectoryTable.text.concat();

		const scanTargetDirsTable: Required<AssetScanDirectoryTable> = {
			audio: [],
			image: [],
			script: [],
			binary: [],
			text: []
		};

		if (target === "all") {
			// NOTE: target = all の場合のみ assets ディレクトリもスキャン対象とする
			const assetsDirs: string[] = ["assets"];
			scanTargetDirsTable.audio.push(...audioDirs, ...assetsDirs);
			scanTargetDirsTable.image.push(...imageDirs, ...assetsDirs);
			scanTargetDirsTable.script.push(...scriptDirs, ...assetsDirs);
			scanTargetDirsTable.binary.push(...assetsDirs);
			scanTargetDirsTable.text.push(...textDirs, ...assetsDirs);

			// NOTE: 重複するディレクトリを削除
			scanTargetDirsTable.audio = scanTargetDirsTable.audio.filter((dir, i, self) => self.indexOf(dir) === i);
			scanTargetDirsTable.image = scanTargetDirsTable.image.filter((dir, i, self) => self.indexOf(dir) === i);
			scanTargetDirsTable.script = scanTargetDirsTable.script.filter((dir, i, self) => self.indexOf(dir) === i);
			scanTargetDirsTable.binary = scanTargetDirsTable.binary.filter((dir, i, self) => self.indexOf(dir) === i);
			scanTargetDirsTable.text = scanTargetDirsTable.text.filter((dir, i, self) => self.indexOf(dir) === i);
		} else if (target === "audio") {
			scanTargetDirsTable.audio.push(...audioDirs);
			scanTargetDirsTable.audio = scanTargetDirsTable.audio.filter((dir, i, self) => self.indexOf(dir) === i);
		} else if (target === "image") {
			scanTargetDirsTable.image.push(...imageDirs);
			scanTargetDirsTable.image = scanTargetDirsTable.image.filter((dir, i, self) => self.indexOf(dir) === i);
		} else if (target === "script") {
			scanTargetDirsTable.script.push(...scriptDirs);
			scanTargetDirsTable.script = scanTargetDirsTable.script.filter((dir, i, self) => self.indexOf(dir) === i);
		} else if (target === "binary") {
			scanTargetDirsTable.binary = scanTargetDirsTable.binary.filter((dir, i, self) => self.indexOf(dir) === i);
		} else if (target === "text") {
			scanTargetDirsTable.text.push(...textDirs);
			scanTargetDirsTable.text = scanTargetDirsTable.text.filter((dir, i, self) => self.indexOf(dir) === i);
		} else {
			throw new Error(`Unknown target "${param.target}"`);
		}

		// スキャン結果のアセット定義の配列
		const scannedAssets: AssetConfiguration[] = [];

		const textAssetFilterRe =
			param.assetExtension.text && param.assetExtension.text.length > 0
				? new RegExp(param.assetExtension.text.join("|"), "i")
				: undefined;

		// 1. 対象のフォルダをスキャンし、各ファイルの情報をアセット定義
		for (const dir of scanTargetDirsTable.audio) {
			const assets = await scanAudioAssets(base, dir, logger);
			scannedAssets.push(...assets);
		}
		for (const dir of scanTargetDirsTable.image) {
			const assets = [
				...(await scanImageAssets(base, dir, logger)),
				...(await scanVectorImageAssets(base, dir, logger))
			];
			scannedAssets.push(...assets);
		}
		for (const dir of scanTargetDirsTable.script) {
			const assets = await scanScriptAssets(base, dir, logger);
			scannedAssets.push(...assets);
		}
		for (const dir of scanTargetDirsTable.binary) {
			const assets = await scanBinaryAssets(
				base,
				dir,
				logger,
				p => {
					if (knownExtensionAssetFilter(p)) return false;
					// NOTE: ユーザ指定の拡張子オプションが追加されたら判定に利用する
					// if (userBinaryAssetFilter(p)) return userBinaryAssetFilter(p);
					// if (defaultBinaryAssetFilter(p)) return true;
					return isBinaryFile(path.join(base, dir, p));
				}
			);
			scannedAssets.push(...assets);
		}
		for (const dir of scanTargetDirsTable.text) {
			const assets = await scanTextAssets(
				base,
				dir,
				logger,
				p => {
					if (knownExtensionAssetFilter(p)) return false; // scan が特別処理する明らかに非テキストの拡張子 (e.g. .ogg, .png) は除外する
					if (textAssetFilterRe) return textAssetFilterRe.test(p); // ユーザ指定のフィルタがあればそれで判定する
					if (defaultTextAssetFilter(p)) return true; // 高速化のため、数が多い・Akashic独自など、拡張子だけで判定できるものはそれで判定
					return !isBinaryFile(path.join(base, dir, p)); // どれでもなければ中身で判定
				}
			);
			scannedAssets.push(...assets);
		}

		if (fs.existsSync(gamePath)) {
			let configuration: GameConfiguration;

			try {
				configuration = await readJSON<GameConfiguration>(gamePath);
			} catch (e) {
				throw new Error(`Invalid game.json: ${e.message}`);
			}

			const definedAssets = (Array.isArray(configuration.assets) ? configuration.assets : AssetModule.toArray(configuration.assets));

			let newAssets: AssetConfiguration[];
			if (param.forceUpdate) {
				logger.warn("Overwriting all existing asset settings due to '--force' option");
				newAssets = scannedAssets;
			} else {
				// 既存のアセット情報と新規追加のアセット情報をマージ
				newAssets = AssetModule.merge(
					definedAssets,
					scannedAssets,
					scanTargetDirsTable,
					AssetModule.createDefaultMergeCustomizer(logger),
					logger
				);
			}

			// 上書きしてファイル書き込み
			if (Array.isArray(configuration.assets)) {
				configuration.assets = newAssets;
			} else {
				const assetIdResolver = AssetModule.createAssetIdResolver({
					resolveAssetIdsFromPath,
					includeExtensionToAssetId
				});
				configuration.assets = AssetModule.toObject(newAssets, assetIdResolver, param.forceUpdateAssetIds);
			}
			await writeJSON<GameConfiguration>(gamePath, configuration);
		}

		if (fs.existsSync(akashicLibPath)) {
			let configuration: LibConfiguration;

			try {
				configuration = await readJSON<LibConfiguration>(akashicLibPath);
			} catch (e) {
				throw new Error(`Invalid akashic-lib.json: ${e.message}`);
			}

			const definedAssets = (configuration.assetList || []);

			// 既存のアセット情報と新規追加のアセット情報をマージ
			const newAssets = AssetModule.merge(
				definedAssets,
				scannedAssets,
				scanTargetDirsTable,
				AssetModule.createDefaultMergeCustomizer(logger),
				logger
			);

			// 上書きしてファイル書き込み
			configuration.assetList = newAssets;
			await writeJSON<LibConfiguration>(akashicLibPath, configuration);
		}

		logger.info("Done!");
	} catch (e) {
		throw e;
	}
}

import * as fs from "fs";
import { readFile } from "fs/promises";
import * as path from "path";
import { Util, type LibConfiguration } from "@akashic/akashic-cli-commons";
import { ConsoleLogger } from "@akashic/akashic-cli-commons/lib/ConsoleLogger.js";
import { readJSON, writeJSON } from "@akashic/akashic-cli-commons/lib/FileSystem.js";
import type { Logger } from "@akashic/akashic-cli-commons/lib/Logger.js";
import { NodeModules } from "@akashic/akashic-cli-commons/lib/NodeModules.js";
import { PromisedNpm } from "@akashic/akashic-cli-commons/lib/PromisedNpm.js";
import { chdir } from "@akashic/akashic-cli-commons/lib/Util.js";
import type { AssetConfigurationMap, GameConfiguration } from "@akashic/game-configuration";

export interface ScanNodeModulesParameterObject {
	/**
	 * 作業ディレクトリ。
	 * 省略された場合、 `process.cwd()` 。
	 */
	cwd?: string;

	/**
	 * コマンドの出力を受け取るロガー。
	 * 省略された場合、akashic-cli-commons の `new ConsoleLogger()` 。
	 */
	logger?: Logger;

	/**
	 * エントリポイントスクリプトの内容からスキャンするようにするか否か。
	 * 省略された場合、偽。
	 * 偽である場合、 `npm ls` して得られたモジュール名一覧からスキャンする。
	 */
	fromEntryPoint?: boolean;

	/**
	 * デバッグ用のNPMを受け取る。
	 * 省略された場合、NPMを引き渡さない。
	 */
	debugNpm?: PromisedNpm | undefined;

	/**
	 * `globalScripts` に外部モジュールの package.json のパスを省くかどうか。
	 * 省略された場合、 `true` 。
	 */
	omitPackagejson?: boolean;

	/**
	 * アセットIDをアセットのパスから解決するかどうか。
	 * 省略された場合、 `false` 。
	 * 偽である場合、ファイル名から拡張子を除去した文字列がアセットIDとして利用される。
	 */
	resolveAssetIdsFromPath?: boolean;

	/**
	 * すべての外部モジュールの定義をスキャンし直すかどうか。
	 * 省略された場合、 `false` 。
	 */
	forceUpdate?: boolean;

	/**
	 * アセットIDを再度スキャンし直すかどうか。
	 * 省略された場合、 `false` 。
	 */
	forceUpdateAssetIds?: boolean;

	/**
	 * アセットIDに拡張子を含めるかどうか。
	 * ただし音声アセットについては拡張子が含まれない点に注意
	 * 省略された場合、 `false` 。
	 */
	includeExtensionToAssetId?: boolean;

	/**
	 * game.json の moduleMainPaths を優先して利用するかどうか。
	 * `useMms` の指定よりも優先される。
	 * 本値と `useMms` が `false` の場合、 game.json の内容に応じて `moduleMainPaths` と `moduleMainScripts` のどちらを利用するか判断する。
	 * 省略された場合、 `false` 。
	 */
	useMmp?: boolean;

	/**
	 * game.json の moduleMainScripts を優先して利用するかどうか。
	 * 本値と `useMmp` が `false` の場合、 game.json の内容に応じて `moduleMainPaths` と `moduleMainScripts` のどちらを利用するか判断する。
	 * 省略された場合、 `false` 。
	 */
	useMms?: boolean;
}

interface NormalizedScanNodeModulesParameterObject extends Required<Omit<ScanNodeModulesParameterObject, "debugNpm">> {
	debugNpm: PromisedNpm | undefined;
}

export function _completeScanNodeModulesParameterObject(param: ScanNodeModulesParameterObject): NormalizedScanNodeModulesParameterObject {
	return {
		cwd: param.cwd ?? process.cwd(),
		logger: param.logger ?? new ConsoleLogger(),
		fromEntryPoint: !!param.fromEntryPoint,
		resolveAssetIdsFromPath: !!param.resolveAssetIdsFromPath,
		forceUpdate: !!param.forceUpdate,
		forceUpdateAssetIds: !!param.forceUpdateAssetIds,
		omitPackagejson: param.omitPackagejson ?? true,
		debugNpm: param.debugNpm ?? undefined,
		includeExtensionToAssetId: !!param.includeExtensionToAssetId,
		useMmp: !!param.useMmp,
		useMms: !!param.useMms,
	};
}

export async function scanNodeModules(p: ScanNodeModulesParameterObject): Promise<void> {
	const param = _completeScanNodeModulesParameterObject(p);
	const restoreDirectory = chdir(param.cwd);

	try {
		const logger = param.logger;
		const gamePath = "./game.json";
		const base = ".";
		const content = await readJSON<GameConfiguration>(gamePath);
		const sandboxRuntime = content.environment?.["sandbox-runtime"] ?? "1";

		let entryPaths: string | string[];
		let useMmp: boolean = false;

		if (sandboxRuntime !== "1" && sandboxRuntime !== "2") {
			if (param.useMmp) {
				useMmp = true;
			} else if (param.useMms) {
				useMmp = false;
			} else {
				useMmp = content.moduleMainPaths != null;
			}
		} else {
			useMmp = false;
		}

		if (param.fromEntryPoint) {
			let entryPointPath: string | null = null;
			if (content.main) {
				entryPointPath = content.main;
			} else {
				if (!Array.isArray(content.assets)) {
					if (content.assets.mainScene) {
						path.join(base, content.assets.mainScene.path);
					}
				}
			}
			if (!entryPointPath) {
				throw new Error("Unable to find a valid entry point.");
			}
			entryPaths = entryPointPath;
		} else {
			const npm = param.debugNpm ?? new PromisedNpm({ logger });

			let dependencyPackageNames: string[];
			try {
				// lsResultオブジェクトは、package.jsonのdependenciesに書かれたモジュールと、それらの各依存モジュールをツリー構造で表したオブジェクトである。
				// これらのうち、dependenciesに直接書かれていない依存モジュールのファイルパスは、依存モジュールのバージョン・インストール順序によって不定である。
				// よって、依存モジュールのファイルパスを解決する方法として、
				// node_modules/直下にあるモジュール名（つまりpackage.jsonのdependenciesに書かれたモジュール）のみをNodeModules.listModuleFilesに渡す。
				// これにより、requireチェーンによって依存モジュールのファイルパスが解決される。
				const lsResult = await npm.ls();
				lsResult.dependencies = lsResult.dependencies ?? {};

				dependencyPackageNames = Object.keys(lsResult.dependencies);
			} catch (err) {
				// モジュールがない場合(npm install 未実施)は scan の前に npm install を実行するメッセージを追加表示
				if ( /missing:/.test(err.message))
					err.message += "run “npm install” before scanning globalScripts.";
				throw new Error(err);
			}

			entryPaths = dependencyPackageNames;
		}

		const listFiles = param.omitPackagejson ? NodeModules.listScriptFiles : NodeModules.listModuleFiles;
		const modulePaths = await listFiles(base, entryPaths, logger) ?? [];
		// 既に登録されている globalScripts のうち存在しているものを残した後、新規で追加されたスクリプトのみを追加している。この追加時に重複を防ぐためにSetを用いている。
		const globalScripts = Array.from(new Set([
			...(content.globalScripts ?? []).filter(f => fs.existsSync(path.resolve(base, f))),
			...modulePaths
		])).sort();

		if (globalScripts.length) {
			const packageJsonFiles = NodeModules.listPackageJsonsFromScriptsPath(base, globalScripts);

			if (useMmp) {
				const moduleMainPaths = NodeModules.listModuleMainPaths(packageJsonFiles);
				content.moduleMainPaths = Object.assign(content.moduleMainPaths || {}, moduleMainPaths);
				delete content.moduleMainScripts;
			} else {
				const moduleMainScripts = NodeModules.listModuleMainScripts(packageJsonFiles);

				if (moduleMainScripts && 0 < Object.keys(moduleMainScripts).length) {
					content.moduleMainScripts = Object.assign(content.moduleMainScripts || {}, moduleMainScripts);
				}

				delete content.moduleMainPaths;
			}
		} else {
			delete content.moduleMainPaths;
			delete content.moduleMainScripts;
		}

		content.globalScripts = globalScripts;

		// globalScripts のファイルパスはすでに解決済みのため、ここでは akashic-lib.json に関する更新のみを扱う。
		if (param.forceUpdate) {
			if (param.fromEntryPoint) {
				throw new Error("[Not Implemented] The options '--force' and '--from-entry-point' cannot be used together");
			}

			content.environment ??= {};

			const beforeExternal = content.environment.external;
			delete content.environment.external;

			for (const moduleName of entryPaths) {
				content.environment.external ??= {};
				const libPath = path.resolve(".", "node_modules", moduleName, "akashic-lib.json");
				const libJsonData = await loadLibJson(libPath);

				if (libJsonData?.gameConfigurationData) {
					const environment = libJsonData.gameConfigurationData.environment;
					if (environment?.external) {
						for (const [name, value] of Object.entries(environment.external)) {
							content.environment.external[name] = value;
						}
					}
				}

				if (libJsonData?.assetList) {
					content.assets ??= {};
					for (const asset of libJsonData.assetList) {
						const assetPath = Util.makeUnixPath(path.join("node_modules", moduleName, asset.path));
						(content.assets as AssetConfigurationMap)[assetPath] = {
							...asset,
							path: assetPath
						};
					}
				}
			}

			if (beforeExternal && Object.keys(beforeExternal).length > 0) {
				const deletedKeys = Object.keys(beforeExternal).filter(key => !(key in (content.environment?.external ?? {})));
				if (deletedKeys.length > 0) {
					logger.warn(
						"'environment.external' was overwritten due to '--force' option. " +
						`The following keys were deleted: ${deletedKeys.map(key => `environment.external["${key}"]`).join(", ")}`
					);
				}
			}
		}

		await writeJSON<GameConfiguration>(gamePath, content);

		logger.info("Done!");
	} finally {
		await restoreDirectory();
	}
}

async function loadLibJson(libPath: string): Promise<LibConfiguration | null> {
	try {
		const data = await readFile(libPath, "utf8");
		return JSON.parse(data);
	} catch (err: any) {
		// akashic-lib.json が存在しない場合エラーとせずに null を返す
		if (err.code === "ENOENT") {
			return null;
		}
		throw err;
	}
}

import * as path from "path";
import type { Logger } from "@akashic/akashic-cli-commons/lib/Logger.js";
import { invertMap, makeUnixPath, readdirRecursive } from "@akashic/akashic-cli-commons/lib/Util.js";
import type { AssetConfiguration, AudioAssetConfigurationBase } from "@akashic/game-configuration";
import { getAudioDuration } from "./getAudioDuration.js";
import { getImageSize } from "./getImageSize.js";

export type AssetFilter = (path: string) => boolean;

export function scriptAssetFilter(p: string): boolean {
	return /.*\.js$/i.test(p);
}

export function knownExtensionAssetFilter(p: string): boolean {
	return scriptAssetFilter(p) ||
		imageAssetFilter(p) ||
		vectorImageAssetFilter(p) ||
		audioAssetFilter(p) ||
		ignoreFileFilter(p);
}

export function imageAssetFilter(p: string): boolean {
	return /.*\.(png|gif|jp(?:e)?g|webp)$/i.test(p);
}

export function vectorImageAssetFilter(p: string): boolean {
	return /.*\.svg$/i.test(p);
}

export function audioAssetFilter(p: string): boolean {
	return /.*\.(ogg|aac|mp4|m4a)$/i.test(p);
}

export function defaultTextAssetFilter(p: string): boolean {
	return /.*\.(txt|json|asapj|asabn|asask|asaan)$/.test(p);
}

export function defaultBinaryAssetFilter (_: string): boolean {
	return false;
}

export function ignoreFileFilter(p: string): boolean {
	const filename = path.basename(p);
	return /^(\.gitkeep|\.DS_Store|Thumbs\.db)$/.test(filename);
}

export interface AudioDurationInfo {
	basename: string;
	ext: string;
	duration: number | undefined;
	path: string;
}

export type AudioDurationInfoMap = { [path: string]: AudioDurationInfo };

export async function scanScriptAssets(
	baseDir: string,
	dir: string,
	_logger?: Logger,
	filter: AssetFilter = scriptAssetFilter
): Promise<AssetConfiguration[]> {
	const relativeFilePaths: string[] = readdirRecursive(path.join(baseDir, dir)).filter(filter);
	return relativeFilePaths.map<AssetConfiguration>(relativeFilePath => {
		return {
			type: "script",
			path: makeUnixPath(path.join(dir, relativeFilePath)),
			global: true
		};
	});
}

export async function scanBinaryAssets(
	baseDir: string,
	dir: string,
	_logger?: Logger,
	filter: AssetFilter = defaultBinaryAssetFilter
): Promise<AssetConfiguration[]> {
	const relativeFilePaths: string[] = readdirRecursive(path.join(baseDir, dir)).filter(filter);
	return relativeFilePaths.map<AssetConfiguration>(relativeFilePath => {
		return {
			type: "binary",
			path: makeUnixPath(path.join(dir, relativeFilePath))
		};
	});
}

export async function scanTextAssets(
	baseDir: string,
	dir: string,
	_logger?: Logger,
	filter: AssetFilter = defaultTextAssetFilter
): Promise<AssetConfiguration[]> {
	const relativeFilePaths: string[] = readdirRecursive(path.join(baseDir, dir)).filter(filter);
	return relativeFilePaths.map<AssetConfiguration>(relativeFilePath => {
		return {
			type: "text",
			path: makeUnixPath(path.join(dir, relativeFilePath))
		};
	});
}

export async function scanImageAssets(
	baseDir: string,
	dir: string,
	logger?: Logger,
	filter: AssetFilter = imageAssetFilter
): Promise<AssetConfiguration[]> {
	const relativeFilePaths: string[] = readdirRecursive(path.join(baseDir, dir)).filter(filter);
	return relativeFilePaths.map(relativeFilePath => {
		const absolutePath = path.join(baseDir, dir, relativeFilePath);
		const size = getImageSize(absolutePath);
		if (!size) {
			logger?.warn(`Failed to get image size. Please check ${absolutePath}`);
			return null;
		}
		return {
			type: "image",
			path: makeUnixPath(path.join(dir, relativeFilePath)),
			width: size.width,
			height: size.height
		} as AssetConfiguration;
	})
		.filter((asset): asset is NonNullable<typeof asset> => asset != null);
}

export async function scanVectorImageAssets(
	baseDir: string,
	dir: string,
	logger?: Logger,
	filter: AssetFilter = vectorImageAssetFilter
): Promise<AssetConfiguration[]> {
	const relativeFilePaths: string[] = readdirRecursive(path.join(baseDir, dir)).filter(filter);
	return relativeFilePaths.map(relativeFilePath => {
		const absolutePath = path.join(baseDir, dir, relativeFilePath);
		const size = getImageSize(absolutePath);
		if (!size) {
			logger?.warn(
				`Failed to get vector-image size. Please check ${absolutePath}. ` +
				"Akashic Engine requires 'width' and 'height' attributes (denoted with 'px' or without units) in 'svg' element."
			);
			return null;
		}
		return {
			type: "vector-image",
			path: makeUnixPath(path.join(dir, relativeFilePath)),
			width: size.width,
			height: size.height
		} as AssetConfiguration;
	})
		.filter((asset): asset is NonNullable<typeof asset> => asset != null);
}

export async function scanAudioAssets(
	baseDir: string,
	dir: string,
	logger?: Logger,
	filter: AssetFilter = audioAssetFilter
): Promise<AssetConfiguration[]> {
	const relativeFilePaths: string[] = readdirRecursive(path.join(baseDir, dir)).filter(filter);

	const durationInfos: AudioDurationInfo[] = [];
	const extMap: {[key: string]: Set<string>} = {};
	for (const relativeFilePath of relativeFilePaths) {
		const absolutePath = path.join(baseDir, dir, relativeFilePath);
		const ext = path.extname(absolutePath);
		const basename = path.basename(absolutePath, ext);
		const nonExtRelativeFilePath = path.join(dir, path.dirname(relativeFilePath), basename);
		const duration = await getAudioDuration(absolutePath, logger);
		if (duration == null)
			console.warn(`Failed to get duration of ${relativeFilePath}`);
		const unixPath = makeUnixPath(nonExtRelativeFilePath);
		durationInfos.push({
			basename,
			ext: ext,
			duration: duration != null ? Math.ceil(duration * 1000) : undefined,
			path: unixPath
		});
		if (!extMap[unixPath]) extMap[unixPath] = new Set<string>();
		extMap[unixPath].add(ext);
	}

	const durationRevMap = invertMap(durationInfos as any, "path");
	for (const nonExtFilePath in durationRevMap) {
		// お節介機能: 拡張子が違うだけの音声ファイル間で、500ms以上長さが違ったら警告しておく。
		// (別のファイルがまぎれているかもしれない) お節介なので数値に深い意味はない。
		if (!durationRevMap.hasOwnProperty(nonExtFilePath)) continue;
		const keys = durationRevMap[nonExtFilePath];
		const durations = keys.map(k => durationInfos[Number(k)].duration).filter((v): v is number => v != null);
		const durationDiff = Math.max(...durations) - Math.min(...durations);
		if (500 < durationDiff) {
			logger?.warn(`Detected different durations between files prefixed with ${nonExtFilePath}.`);
		}
	}

	const durationMap: AudioDurationInfoMap = {};
	for (const durationInfo of durationInfos) {
		if ((durationInfo.ext === ".ogg" && durationInfo.duration != null) || !durationMap[durationInfo.basename]) {
			durationMap[durationInfo.path] = durationInfo;
		}
	}

	const audioAssets: AssetConfiguration[] = [];
	for (const filePath in durationMap) {
		if (!durationMap.hasOwnProperty(filePath)) continue;
		const duration = durationMap[filePath].duration;
		const asset: AudioAssetConfigurationBase = {
			type: "audio",
			path: filePath,
			systemId: "sound",
			duration: duration != null ? duration : null! // 歴史的に duration が必須となっているため duration が取得できない場合は明示的に null! を代入。
		};
		if (extMap[filePath].size > 0) asset.hint = { extensions: Array.from(extMap[filePath]) };
		audioAssets.push(asset);
	}

	return audioAssets;
}

