		expect(warnLogs.length).toBe(2);
		expect(warnLogs[0]).toContain("deprecated"); // mp4 形式は非推奨であることの旨
		expect(warnLogs[1]).toContain("different durations"); // 異なる拡張子間で duration に差があることの旨

		expect(
			await scanAudioAssets(
				path.join(baseDir, "./game"),
				"assets",
				nullLogger
			)
		).toEqual([
			{
				type: "audio",
				path: "assets/_",
				systemId: "sound",
				duration: 8000,
				hint: { extensions: [".ogg"] }
			}
		]);
	});
});

import { PromisedNpm, PromisedNpmParameterObject } from "@akashic/akashic-cli-commons/lib/PromisedNpm.js";

export interface MockPromisedNpmParameterObject extends PromisedNpmParameterObject {
	expectDependencies: {[key: string]: any};
	expectDevDependencies?: {[key: string]: any};
}

// テスト実行に必要な最低限のNPMメソッドをモック化します。
export class MockPromisedNpm extends PromisedNpm {
	expectDependencies: {[key: string]: any};
	expectDevDependencies: {[key: string]: any};
	constructor(param: MockPromisedNpmParameterObject) {
		super({});
		this.expectDependencies = param.expectDependencies;
		this.expectDevDependencies = param.expectDevDependencies ?? {};
	}
	_load(): Promise<void> {
		return Promise.resolve();
	}

	// モック生成時にexpectDependenciesのみが与えられた場合、暗黙的に `npm ls --production` の振る舞いを模倣します。
	// 同様に、expectDevDependenciesが与えられた場合、`npm ls` の振る舞いを模倣します。
	ls(silent?: boolean): Promise<any> {
		var result = this.expectDependencies;
		if (this.expectDevDependencies) {
			var devList = Object.keys(this.expectDevDependencies);
			devList.forEach((name) => {
				if (!result[name]) result[name] = this.expectDevDependencies[name];
			});
		}
		return new Promise((resolve) => {
			resolve({
				dependencies: result
			});
		})
	}
}

// mockfs を実際のディレクトリに展開するモックスクリプト。

import { existsSync, mkdirSync, mkdtempSync, rmSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

type FileStructure = {
	[key: string]: FileStructure | string | Buffer;
};

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const tmpBaseDir = join(__dirname, "..", "..", "tmp-expanded-fixtures");

function createFiles(baseDir: string, structure: FileStructure): void {
	for (const key in structure) {
		const targetPath = join(baseDir, key);
		const value = structure[key];

		if (typeof value === "object" && value !== null && !Buffer.isBuffer(value)) {
			// ディレクトリ
			if (!existsSync(targetPath)) {
				mkdirSync(targetPath, { recursive: true });
			}
			createFiles(targetPath, value);
		} else {
			// ファイル
			writeFileSync(targetPath, value);
		}
	}
}

export function restore(base: string): void {
	if (existsSync(join(tmpBaseDir, base))) {
		rmSync(join(tmpBaseDir, base), { recursive: true, force: true });
	}
}

export function create(base: string, structure: FileStructure): string {
	const baseDir = join(tmpBaseDir, base);
	mkdirSync(baseDir, { recursive: true });

	const tmpDir = mkdtempSync(join(baseDir, `${Date.now()}-`));
	createFiles(tmpDir, structure);

	return tmpDir;
}

#!/usr/bin/env node

import { run } from "../lib/cli.js";
run(process.argv);

import { createServer } from "http";
import { program } from "commander";
import { existsSync } from "fs";
import { createRequire } from "module";
import path from "path";
import debugLib from "debug";
import { load } from "@akashic/akashic-cli-commons/lib/FileSystem.js";
import appLib from "./lib/app.js";

const debug = debugLib("script-test:server");
const require = createRequire(import.meta.url);
const { version } = require("./package.json");

function collect(val, acc) {
	acc.push(val);
	return acc;
}

program
	.version(version)
	.usage("[options] <game path>")
	.option("--cascade <path>", "path to contents to cascade", collect, [])
	.option("-p, --port <port>", "number of listen port. default 3000", parseInt)
	.option("-s, --scenario <scenario>", "scenario file");

/**
 * @param {import('@akashic/akashic-cli-commons/lib/CliConfig/CliConfigSandbox.js').CliConfigSandbox} param
 */
async function cli(param) {
	const app = appLib({
		gameBase: param.args.length > 0 ? param.args[0] : param.cwd,
		cascadeBases: param.cascade,
		fonts: param.fonts,
	});
	const port = normalizePort(param.port ?? process.env.PORT ?? 3000);

	if (param.scenario) {
		if (!existsSync(param.scenario)) {
			console.error("could not load " + param.scenario);
			process.exitCode = 1;
			return;
		}
		app.set("scenarioPath", param.scenario);
	}

	const gameJsonPath = path.join(app.gameBase, "game.json");
	if (!param.scenario && !existsSync(gameJsonPath)) {
		console.error(`could not load ${gameJsonPath}`);
		process.exitCode = 1;
		return;
	}

	app.set("port", port);

	const server = createServer(app);

	server.listen(port);
	server.on("error", onError);
	server.on("listening", onListening);

	function normalizePort(val) {
		const port = parseInt(val, 10);

		if (isNaN(port)) {
			// named pipe
			return val;
		}

		if (port >= 0) {
			// port number
			return port;
		}

		return false;
	}

	function onError(error) {
		if (error.syscall !== "listen") {
			throw error;
		}

		const bind = typeof port === "string" ? "Pipe " + port : "Port " + port;

		// handle specific listen errors with friendly messages
		switch (error.code) {
			case "EACCES":
				console.error(bind + " requires elevated privileges");
				process.exit(1);
			case "EADDRINUSE":
				console.error(bind + " is already in use");
				process.exit(1);
			default:
				throw error;
		}
	}

	function onListening() {
		const addr = server.address();
		const bind = typeof addr === "string" ? "pipe " + addr : "port " + addr.port;
		debug("Listening on " + bind);
	}

	console.log("akashic-sandbox listen port: " + port);
	console.log("hosting game: " + gameJsonPath);
	if (app.settings.scenarioPath) {
		console.log("scenario file: " + app.settings.scenarioPath);
	}
	console.log("please access to http://localhost:%d/game/ by web-browser", port);
}

export const run = async (argv) => {
	program.parse(argv);
	const options = program.opts();

	let configuration;
	try {
		configuration = await load(options.cwd || process.cwd());
	} catch (error) {
		console.error(error);
		process.exitCode = 1;
		return;
	}

	const conf = configuration.commandOptions?.sandbox ?? {};
	await cli({
		args: program.args ?? conf.args,
		cwd: options.cwd ?? conf.cwd,
		cascade: options.cascade ?? conf.cascade,
		port: options.port ?? conf.port,
		scenario: options.scenario ?? conf.scenario,
		fonts: conf.fonts,
	});
};

