// ビルド時はnode_modules下のakashic-engineモジュールのgを参照しているが、実際に利用するgはjs下のengineFilesV*_*_*.jsのものなので、本来なら実行時に参照するgを動的に決定できるようにすべき
export class SandboxScriptAsset extends g.ScriptAsset {
	loading: boolean;
	script: string;
	path: string;
	id: string;
	constructor(id: string, path: string) {
		super(id, path);
		// いきなり読んじゃう
		const heads = document.getElementsByTagName("head");
		const container: Node = (heads.length === 0) ? document.body : heads[0];

		const script = <HTMLScriptElement>document.createElement("script");
		script.onload = () => {
			this.script = script.text; // TODO: とれない・・
			this.loading = false;
		};
		script.onerror = () => {
			this.loading = false;
		};
		this.script = undefined;
		this.loading = true;
		script.src = this.path;
		container.appendChild(script);
	}

	_load(loader: AssetLoadHandler): void {
		const waitLoader = (): void => {
			if (this.loading) {
				setTimeout(waitLoader, 100);
				return;
			}
			if (this.script !== undefined) {
				loader._onAssetLoad(this);
			} else {
				loader._onAssetError(this, g.ExceptionFactory.createAssetLoadError("can not load script"));
			}
		};
		setTimeout(waitLoader, this.loading ? 100 : 0);
	}

	execute(execEnv: ScriptAssetExecuteEnvironment): any {
		window.gScriptContainer[this.path](execEnv);
		return execEnv.module.exports;
	}
}

// 本来であればv3系のg.ScriptAssetをimplementsすべきだが、ビルド時に使用しているakashic-engineはv2系なので一からクラス定義している
export class SandboxScriptAssetV3 {
	type: string = "script";
	script: string;
	id: string;
	path: string;
	originalPath: string;
	onDestroyed: Trigger<Asset>;
	loading: boolean;
	exports: string[];

	constructor(id: string, path: string, exports: string[] = []) {
		this.id = id;
		this.originalPath = path;
		this.exports = exports;
		this.path = this._assetPathFilter(path);
		this.onDestroyed = new g.Trigger<Asset>();
		// いきなり読んじゃう
		const heads = document.getElementsByTagName("head");
		const container: Node = (heads.length === 0) ? document.body : heads[0];

		const script = <HTMLScriptElement>document.createElement("script");
		script.onload = () => {
			this.script = script.text; // TODO: とれない・・
			this.loading = false;
		};
		script.onerror = () => {
			this.loading = false;
		};
		this.script = undefined;
		this.loading = true;
		script.src = this.path;
		container.appendChild(script);
	}

	destroy(): void {
		this.onDestroyed.fire(this);
		this.id = undefined!;
		this.originalPath = undefined!;
		this.path = undefined!;
		this.onDestroyed.destroy();
		this.onDestroyed = undefined!;
	}

	destroyed(): boolean {
		return this.id === undefined;
	}

	inUse(): boolean {
		return false;
	}

	// 引数の型はg.ScriptAssetRuntimeValueだが、v2系には無いものなのでanyを指定している
	execute(execEnv: any): any {
		window.gScriptContainer[this.path](execEnv);
		return execEnv.module.exports;
	}

	_load(loader: AssetLoadHandler): void {
		const waitLoader = (): void => {
			if (this.loading) {
				setTimeout(waitLoader, 100);
				return;
			}
			if (this.script !== undefined) {
				loader._onAssetLoad(this);
			} else {
				loader._onAssetError(this, g.ExceptionFactory.createAssetLoadError("can not load script"));
			}
		};
		setTimeout(waitLoader, this.loading ? 100 : 0);
	}

	/**
	 * @private
	 */
	_assetPathFilter(path: string): string {
		// 拡張子の補完・読み替えが必要なassetはこれをオーバーライドすればよい。(対応形式が限定されるaudioなどの場合)
		return path;
	}
}

export class TimeKeeper {
	_origin: number;
	_pausedTime: number;
	_limit: number;
	_rate: number;
	_offset: number;

	constructor(limit?: number) {
		this._origin = Date.now();
		this._pausedTime = 0;
		this._limit = limit || Infinity;
		this._rate = 1;
		this._offset = 0;
	}

	now(): number {
		const time = (this.isPausing()) ? this._pausedTime : ((Date.now() - this._origin) * this._rate + this._offset);
		return Math.min(time, this._limit);
	}

	setTime(time: number): void {
		if (this.isPausing()) {
			this._pausedTime = time;
		} else {
			this._origin = Date.now();
			this._offset = time;
		}
	}

	isPausing(): boolean {
		return this._pausedTime != null;
	}

	start(): void {
		if (!this.isPausing())
			return;
		this._origin = Date.now();
		this._offset = this._pausedTime;
		this._pausedTime = null;
	}

	pause(): void {
		if (this.isPausing())
			return;
		this._pausedTime = this.now();
	}

	getRate(): number {
		return this._rate;
	}

	setRate(rate: number): void {
		if (this._rate === rate)
			return;
		this.setTime(this.now());
		this._rate = rate;
	}
}

