					console.error(
						"スナップショット " + name + " をロードできません。v2以前のコンテンツで保存されたスナップショットです。" +
						"akashic-sandbox のスナップショットツールは、v2以前とv3で保存形式に互換性がありません。");
					return;
				}

				// developerメニューの把握するカメラを全リセット
				data.cameras = [];
				cameras = [];
				// プレイヤー情報を再現 (この復元はゲームコンテンツのプレイヤー情報の復元とは関係がない)
				data.players = snapshot.players;
				props.game._restartWithSnapshot(snapshot.driverSnapshot);
			},
			previewSnapshot: function(index, name) {
				data.snapshotPreview = {
					name: name,
					data: snapshotsList[index].data
				};
			},
			savePlaylog: savePlaylog,
			reloadPlaylog: reloadPlaylog,
			rewindReplay: rewindReplay,
			playPauseReplay: playPauseReplay,
			onClickTimeProgress: onClickTimeProgress,
			accelerateReplay: accelerateReplay,
			decelerateReplay: decelerateReplay,
			playFromHere: playFromHere,
			removePlaylog: removePlaylog,
			setFocusingCamera: function(index) {
				var c = cameras[index];
				if (props.game.focusingCamera !== c) {
					props.game.focusingCamera = c;
				} else {
					props.game.focusingCamera = undefined;
				}
				props.game.modified();
			},
			updateEntityList: updateEntityList,
			consoleDump: function() {
				var e = data.targetEntity;
				if (e.local) {
					console.log(props.game._localDb.get(e.id));
				} else {
					console.log(props.game.db.get(e.id));
				}
			},
			onEventsToSendChanged: function() {
				saveConfig();
			},
			onAutoSendEventsChanged: function() {
				if (config.sendsSessionParameter && data.isIchibaContent) {
					config.sendsSessionParameter = false; //NicoNico タブのセッションパラメータを送るを無効化
					var err = {
						message: `Events タブの "ゲーム開始時にEventを自動送信" と NicoNico タブの "セッションパラメータを送る" を両方同時に有効にすることはできません。NicoNicoタブの "セッションパラメータを送る" 機能を無効にしました。`,
						isHideTitle: true,
						isHideBody: true
					}
					showErrorDialog(err);
				}
				saveConfig();
			},
			insertEventString: insertEventString,
			sendEvents: sendEvents,
			sendEventsWithValue: sendEventsWithValue,
			onAutoJoinChanged: function() {
				saveConfig();
			},
			onSendsSessionParameterChanged: function() {
				if (config.autoSendEvents && config.eventsToSend) {
					config.autoSendEvents = false; // Events タブのゲーム開始時にEventを自動送信を無効化
					var err = {
						message: `NicoNico タブの "セッションパラメータを送る" と Events タブの "ゲーム開始時にEventを自動送信" を両方同時に有効にすることはできません。Eventsタブの "ゲーム開始時にEventを自動送信" 機能を無効にしました。`,
						isHideTitle: true,
						isHideBody: true
					}
					showErrorDialog(err);
				}
				saveConfig();
			},
			onModeChanged: function() {
				saveConfig();
			},
			onTotalTimeLimitChanged: function() {
				saveConfig();
			},
			onStopGameChanged: function() {
				saveConfig();
			},
			onUsePreferredTotalTimeLimitChanged: function () {
				saveConfig();
			},
			toggleGrid: toggleGrid,
			toggleOmitInterpolatedTick: toggleOmitInterpolatedTick,
			hideErrorDialog: hideErrorDialog
		}
	});
};

window.addEventListener("load", function() {
	var devMode = !(window.location.search.indexOf("devmode=disable") >= 0);

	// copy from http://stackoverflow.com/questions/901115/how-can-i-get-query-string-values-in-javascript
	// fps=xを抽出するための適当なコード
	function getParameterByName(name) {
		name = name.replace(/[\[]/, "\\[").replace(/[\]]/, "\\]");
		var regex = new RegExp("[\\?&]" + name + "=([^&#]*)"),
			results = regex.exec(location.search);
		return results === null ? undefined : decodeURIComponent(results[1].replace(/\+/g, " "));
	}

	function getGamePath(callback) {
		// ゲームのパスからgameIdを生成する
		var xhr = new XMLHttpRequest();
		xhr.open("get", "/basepath/", true);
		xhr.onreadystatechange = function() {
			if (xhr.readyState == 4 && xhr.status == 200) {
				callback(xhr.responseText);
			}
		};
		xhr.send();
	}

	window.loadFonts().then(() => getGamePath(start));

	function fitToWindow(center) {
		var pf = window.sandboxDeveloperProps.driver._platform;
		if (!pf.containerController) return;
		// var parentView = pf.containerView.parentElement;
		var parentView = document.getElementById("container").parentElement;
		parentView.style.margin = "0px";
		parentView.style.padding = "0px";
		parentView.style.overflow = "hidden";
		var viewportSize = {
			width: window.innerWidth || document.documentElement.clientWidth,
			height: window.innerHeight || document.documentElement.clientHeight
		};
		fitToSize(viewportSize, center);
	}

	function revertViewSize() {
		var pf = window.sandboxDeveloperProps.driver._platform;
		var parentView = document.getElementById("container").parentElement;
		parentView.style.margin = window.sandboxDeveloperProps.utils.defaultStyle.margin;
		parentView.style.padding = window.sandboxDeveloperProps.utils.defaultStyle.padding;
		parentView.style.overflow = window.sandboxDeveloperProps.utils.defaultStyle.overflow;
		fitToSize(window.sandboxDeveloperProps.utils.defaultSize);
	}

	function fitToSize(viewportSize, center) {
		var pf = window.sandboxDeveloperProps.driver._platform;
		var game = window.sandboxDeveloperProps.game;
		var gameScale = Math.min(
			viewportSize.width / game.width,
			viewportSize.height / game.height
		);
		var gameSize = {
			width: Math.floor(game.width * gameScale),
			height: Math.floor(game.height * gameScale)
		};
		pf.containerController.changeScale(gameScale, gameScale);
		var gameOffset = {
			x: !!center ? Math.floor((viewportSize.width - gameSize.width) / 2) : 0 ,
			y: !!center ? Math.floor((viewportSize.height - gameSize.height) / 2) : 0
		};
		pf.containerController.inputHandlerLayer.setOffset(gameOffset);
	}

	function start(gamePath) {
		// TODO WebGL有効化
		// // webgl=1でRendererを問答無用でWebGLのみにする
		// if (getParameterByName("webgl")) {
		// 	conf.renderers = ["webgl"];
		// }

		// 本来であればgameIdはBIGINTとして扱われるので数値だけども、とりあえずmd5を使う
		var sandboxGameId = md5(gamePath);
		var sandboxPlayer = { id: "9999", name: "sandbox-player" };
		var sandboxPlayId = "sandboxDummyPlayId";
		var sandboxConfig = window.sandboxDeveloperProps.sandboxConfig;

		window.sandboxDeveloperProps = {
			game: null,
			driver: null,
			amflow: null,
			gameId: sandboxGameId,
			path: gamePath,
			sandboxPlayer: sandboxPlayer,
			sandboxConfig: sandboxConfig,
			utils: {
				fitToWindow: fitToWindow,
				revertViewSize: revertViewSize,
				defaultSize: {
					width: null,
					height: null
				},
				defaultStyle: {
					margin: null,
					padding: null,
					overflow: null
				}
			}
		};

		// preventDefaultを抑制するかを確認するためだけにLocalStorageの設定を読み込む
		var disablePreventDefault = false;
		if (devMode && ("localStorage" in window)) {
			var saved = JSON.parse(localStorage.getItem("akashic-sandbox-config"));
			if (saved) {
				disablePreventDefault = !!saved.disablePreventDefault;
			}
		}

		var pdiBrowser = engineFiles.pdiBrowser;
		var gdr = engineFiles.gameDriver;

		// var executionMode = gdr.ExecutionMode.Active;
		var playlogName = getParameterByName("playlog");

		var playlog;
		if (playlogName) {
			var playlogStr = localStorage.getItem("akpl:" + sandboxGameId + "/" + playlogName);
			if (playlogStr) {
				playlog = JSON.parse(playlogStr);
			} else {
				console.log("cannot load playlog: " + playlogName);
			}
		}

		var amflowClient = new gdr.MemoryAmflowClient({
			playId: sandboxPlayId,
			tickList:  playlog ? playlog.tickList : null,
			startPoints: playlog ? playlog.startPoints : null
		});
		var isReplay = !!playlog;
		var replayStartTime = null;
		var replayDuration = null;
		if (isReplay) {
			var fps = playlog.startPoints[0].data.fps;
			var replayLastTime = null;
			var replayLastAge = playlog.tickList[1];
			var ticksWithEvents = playlog.tickList[2];
			replayStartTime = playlog.startPoints[0].timestamp;
			loop: for (var i = ticksWithEvents.length - 1; i >= 0; --i) {
				var tick = ticksWithEvents[i];
				var pevs = tick[1] || [];
				for (var j = 0; j < pevs.length; ++j) {
					if (pevs[j][0] === 2) { // TimestampEvent
						var timestamp = (pevs[j][3] /* Timestamp */);
						// Timestamp の時刻がゲームの開始時刻より小さかった場合は相対時刻とみなす
						replayLastTime = (timestamp < replayStartTime ? timestamp + replayStartTime : timestamp) + (replayLastAge - tick[0]) * 1000 / fps;
						break loop;
					}
				}
			}
			replayDuration = (replayLastTime == null) ? (replayLastAge * 1000 / fps) : (replayLastTime - replayStartTime);
		}

		var pf = new pdiBrowser.Platform({
			amflow: amflowClient,
			containerView: document.getElementById("container"),
			audioPlugins: [pdiBrowser.WebAudioPlugin, pdiBrowser.HTMLAudioPlugin],
			disablePreventDefault: disablePreventDefault
		});

		// TODO: カスタマイズできるようにする？
		pf._resourceFactory.createScriptAsset = function(...args) {
			return new SandboxScriptAsset(...args);
		};

		// 一部のエッジケースでSafariのみ描画されないという問題が発生するので、ゲーム開発者が開発中に気づけるようにg.Renderer#drawImage()でエラーを投げる処理を差し込む
		// funcにはg.Surfaceを返す関数が渡されることを想定している
		function createMeddlingWrappedSurfaceFactory (func) {
			return function() {
				var surface = func.apply(this, arguments);
				// Safariで範囲外描画時に問題が発生するのはCanvas要素なので、surfaceがCanvasでなければ範囲外描画警告は行わない
				if (surface._drawable.constructor.name !== "HTMLCanvasElement") {
					return surface;
				}
				var originalRenderer = surface.renderer;
				var renderer = null;
				surface.renderer = function () {
					// surface.renderer() はコンテンツから描画のたびに呼び出されるが戻り値は現実的に固定なので、ここでの surface.renderer() の上書きは一度しか適用しない
					if (renderer) {
						return renderer;
					}
					renderer = originalRenderer.apply(this);
					var originalDrawImage = renderer.drawImage;
					renderer.drawImage = function (surface, offsetX, offsetY, width, height, _destOffsetX, _destOffsetY) {
						if (!sandboxConfig.warn || sandboxConfig.warn.drawOutOfCanvas !== false) {
							if (offsetX < 0 || offsetX + width > surface.width || offsetY < 0 || offsetY + height > surface.height) {
								// ref. https://github.com/akashic-games/akashic-engine/issues/349
								var message = "drawImage(): out of bounds."
									+ `The source rectangle bleeds out the source surface (${surface.width}x${surface.height}).`
									+ "This is not a bug but warned by akashic sandbox"
									+ "to prevent platform-specific rendering trouble.";
								console.warn(message);
								window.dispatchEvent(new ErrorEvent("akashicWarning", { error: { message: message } }));
							}
						}
						if (!sandboxConfig.warn || sandboxConfig.warn.drawDestinationEmpty !== false) {
							if (width <= 0 || height <= 0) {
								var message = "drawImage(): nothing to draw."
									+ "Either width or height is less than or equal to zero."
									+ "This is not a bug but warned by akashic sandbox"
									+ "to prevent platform-specific rendering trouble.";
								console.warn(message);
								window.dispatchEvent(new ErrorEvent("akashicWarning", { error: { message: message } }));
							}
						}
						originalDrawImage.apply(this, arguments);
					}
					return renderer;
				}
				return surface;
			};
		}
		pf.getPrimarySurface = createMeddlingWrappedSurfaceFactory(pf.getPrimarySurface);
		pf._resourceFactory.createSurface = createMeddlingWrappedSurfaceFactory(pf._resourceFactory.createSurface);

		driver = new gdr.GameDriver({
			platform: pf,
			player: sandboxPlayer,
			errorHandler: function (e) { console.log("ERRORHANDLER:", e); }
		});

		var timeKeeper = new TimeKeeper(replayDuration);

		driver.gameCreatedTrigger.add(function (game) {
			window.sandboxDeveloperProps.game = game;
			window.sandboxDeveloperProps.driver = driver;
			window.sandboxDeveloperProps.amflow = amflowClient;
			window.sandboxDeveloperProps.utils.defaultSize.width = pf.containerController.surface.width;
			window.sandboxDeveloperProps.utils.defaultSize.height = pf.containerController.surface.height;

			parentElement = document.getElementById("container").parentElement;
			window.sandboxDeveloperProps.utils.defaultStyle.margin = parentElement.style.margin;
			window.sandboxDeveloperProps.utils.defaultStyle.padding = parentElement.style.padding;
			window.sandboxDeveloperProps.utils.defaultStyle.overflow = parentElement.style.overflow;

			const environment = window.sandboxDeveloperProps.game._configuration.environment;
			const enableWebAssembly = environment?.features?.includes("WebAssembly");
			if (!enableWebAssembly) {
				Object.defineProperty(window, "WebAssembly", {
					get: function() {
						throw new Error("If you use WebAssembly, please add \"environment.features:[\"WebAssembly\"]\" to game.json");
					}
				});
			}

			if (getParameterByName("bg")) {
				document.body.style.backgroundColor = "black";
				pf.getPrimarySurface()._drawable.style.backgroundColor = "white";
			}
			if (getParameterByName("fit")) {
				window.sandboxDeveloperProps.utils.fitToWindow();
			}
			if (devMode) {
				setupDeveloperMenu({
					isReplay: isReplay,
					replayDuration: replayDuration,
					timeKeeper: timeKeeper
				});
			}
		});

		var profiler;
		if (devMode) {
			// todo: sandboxのリファクタリング時に getValueTrigger を与えるように修正
			profiler = new gdr.SimpleProfiler({
				interval: 200
			});
		}

		driver.initialize({
			configurationUrl: "/configuration/",
			assetBase: "/game/",
			driverConfiguration: {
				playId: sandboxPlayId,
				playToken: isReplay ? gdr.MemoryAmflowClient.TOKEN_PASSIVE : gdr.MemoryAmflowClient.TOKEN_ACTIVE,
				executionMode: isReplay ? gdr.ExecutionMode.Passive : gdr.ExecutionMode.Active
			},
			loopConfiguration: isReplay ? {
				loopMode: gdr.LoopMode.Replay,
				delayIgnoreThreshold: Number.MAX_VALUE,
				jumpTryThreshold: Number.MAX_VALUE,
				targetTimeFunc: timeKeeper.now.bind(timeKeeper),
				originDate: replayStartTime,
			} : {
				loopMode: gdr.LoopMode.Realtime
			},
			profiler: profiler
		}, function (e) {
			if (e) {
				console.log(e);
				throw e;
			}
			timeKeeper.start();
			driver.startGame();
		});
	}
});

/**
 * param.isReplay: boolean
 * param.replayDuration: number
 * param.timeKeeper: TimeKeeper
 */
function setupDeveloperMenu(param) {
	var gdr = engineFiles.gameDriver;
	var defaultTotalTimeLimit = 85; // 85秒をデフォルトの制限時間としてあつかう。

	// loocalStorageにメニューの位置、サイズを保存している
	var config = {};
	if ("localStorage" in window) {
		var saved = JSON.parse(localStorage.getItem("akashic-sandbox-config"));
		if (saved) {
			config = saved;
		}
	}
	if (config.size == null) {
		config.size = {
			right: {width: "400px", height: "100%"},
			bottom: {width: "100%", height: "300px"}
		};
	}
	if (config.isPositionRight == null) {
		config.isPositionRight = true;
	}
	if (config.showGrid == null) {
		config.showGrid = false;
	}
	if (config.omitInterpolatedTick == null) {
		config.omitInterpolatedTick = false;
	}
	if (isNaN(parseInt(config.totalTimeLimit, 10))) {
		config.totalTimeLimit = defaultTotalTimeLimit;
	}
	if (config.warningMeddlingAkashic == null) {
		config.warningMeddlingAkashic = true;
	}
	if (config.sendsSessionParameter == null) {
		config.sendsSessionParameter = false;
	}
	if (config.mode == null) {
		config.mode = "single";
	}

	var sandboxConfig = window.sandboxDeveloperProps.sandboxConfig;

	// sandbox.config.js で warn 設定が記述されていたら、対象のチェックボックスを押せないようにする
	if (sandboxConfig.warn && (sandboxConfig.warn.useDate !== undefined || sandboxConfig.warn.useMathRandom !== undefined)) {
		config.isWarnSpecifiedInConfig = true;

		if (sandboxConfig.warn.useDate !== undefined) {
			config.warnUseDate = sandboxConfig.warn.useDate;
		}
		if (sandboxConfig.warn.useMathRandom !== undefined) {
			config.warnUseMathRandom = sandboxConfig.warn.useMathRandom;
		}
	} else {
		config.isWarnSpecifiedInConfig = false;
	}

	config.autoSendEvents = config.autoSendEvents || !!sandboxConfig.autoSendEventName;
	config.eventsToSend = !!sandboxConfig.autoSendEventName ? JSON.stringify(sandboxConfig.events[sandboxConfig.autoSendEventName]) : config.eventsToSend;
	saveConfig();

	var events = {};
	if (sandboxConfig.events) {
		Object.keys(sandboxConfig.events).forEach(function (name) {
			events[name] = JSON.stringify(sandboxConfig.events[name]);
		});
	}

	var props = window.sandboxDeveloperProps;
	var amflow = props.amflow;

	// 各viewの情報
	var views = {
		'general-view': {title: "General", show: true},
		'events-view': {title: "Events", show: false},
		'camera-view': {title: "Cameras", show: false},
		'e-view': {title: "E", show: false},
		'niconico-view': {title: "Niconico", show: false},
		'playlog-view': {title: "Replay", show: false},
		'snapshot-view': {title: "Snapshot", show: false}
	};

	// game.jsonの情報
	function getNicoLiveConfig() {
		const environment = props.game._configuration.environment;
		if (environment === undefined) {
			return null;
		}
		// niconico は非推奨なので、nicolive の方を優先的に利用する
		return environment.nicolive ?? (environment.niconico ?? null);
	}
	const nicoliveConfig = getNicoLiveConfig();
	const preferredTotalTimeLimit = nicoliveConfig?.preferredSessionParameters?.totalTimeLimit ?? defaultTotalTimeLimit;

	// vue.jsにバインドするデータ
	var data = {
		showMenu: sandboxConfig.showMenu ? sandboxConfig.showMenu : false,
		players: [],
		selfId: props.sandboxPlayer.id,
		selfName: props.sandboxPlayer.name,
		path: props.path,
		gameId: props.gameId,
		events: events,
		cameras: [],
		focusingCameraIndex: undefined,
		inputPlayerName: null,
		inputPlayerId: null,
		config: config,
		entities: [], // {className: string, id: number, children: Array}
		entityRect: {
			enable: false,
			show: false,
			withChildren: false,
			rectStyle: {top: "0px", left: "0px", width: "0px", height: "0px"}
		},
		targetEntity: null,
		snapshots: null,
		snapshotPreview: null,
		profiler: {
			show: (window.location.search.indexOf("profiler=1") >= 0), // todo: リファクタリング時にクエリオプションのパースを統一する
			expand: false
		},
		isPaused: false,
		isReplay: param.isReplay,
		currentTime: 0,
		replayDuration: param.replayDuration,
		replayDone: false,
		playlog: {
			list: [] // {name: string, url: string}
		},
		views: views,
		isIchibaContent: function() {
			if (!nicoliveConfig || !nicoliveConfig.supportedModes) {
				return false;
			}
			return nicoliveConfig.supportedModes.length > 0;
		}(),
		rankingGameState: {
			score: "N/A",
			playThreshold: "N/A",
			clearThreshold: "N/A"
		},
		remainingTime: "N/A",
		preferredTotalTimeLimit: preferredTotalTimeLimit,
		isStopGame: false,
		modeList: [
			{text: "ひとりで遊ぶ(single)", value: "single"},
			{text: "ランキング(ranking)", value: "ranking"}
		],
		isShowingErrorDialog: false,
		dialogMessage: "",
		dialogTitle: "",
		dialogBody: "",
		dialogReferenceUrl: null,
		dialogReferenceMessage: null
	};

	function showErrorDialog(err) {
		data.isShowingErrorDialog = true;
		data.dialogTitle = !!err.isHideTitle ? "" : "エラーが発生しました";
		data.dialogBody = !!err.isHideBody ? "" : "Developer Tool などでエラー内容を確認の上修正してください。";
		data.dialogMessage = err.message;
	}

	function showAkashicWarnDialog(err) {
		data.isShowingErrorDialog = true;
		data.dialogTitle = "Akashic非推奨機能が使用されました";
		data.dialogMessage = err.message;
		data.dialogBody = "Developer Tool などでエラー内容を確認の上修正してください。";
		data.dialogReferenceMessage = err.referenceMessage;
		data.dialogReferenceUrl = err.referenceUrl;
	}

	function hideErrorDialog() {
		data.isShowingErrorDialog = false;
	}

	window.addEventListener("error", function(ev) {
		showErrorDialog(ev.error);
	});

	window.addEventListener("akashicWarning", function(ev) {
		showAkashicWarnDialog(ev.error);
	});

	window.addEventListener("onunhandledrejection", function(ev) {
		showErrorDialog(ev.error);
	});

	if (config.autoJoin && !param.isReplay) {
		// NOTE: この時点でgame._loadedにgame._start()がハンドルされている必要がある
		// スナップショットから復元時はloadedが発火しないのでJOINは行われない
		props.game._loaded.addOnce(function() {
			var p = props.sandboxPlayer;
			data.players.push({player: {id: p.id, name: p.name}, self: true});
			amflow.sendEvent([0 /* Join */,  3, p.id, p.name, null ]);
		});
	}

	// Events タブの "ゲーム開始時にEventを自動送信" と NicoNico タブの "セッションパラメータを送る" が両方有効になった場合
	// エラーを出力し、Eventタブの "ゲーム開始時にEventを自動送信" を無効とする。
	if (config.autoSendEvents && (config.sendsSessionParameter && data.isIchibaContent)) {
		var err = {
