import { readJSON, writeJSON } from "@akashic/akashic-cli-commons/lib/FileSystem.js";
import type { GameConfiguration } from "@akashic/akashic-cli-commons/lib/GameConfiguration.js";
import type { Logger } from "@akashic/akashic-cli-commons/lib/Logger.js";
import Prompt from "prompt";

/**
 * game.jsonの初期値として与えるパラメータ。
 */
export interface BasicParameters {
	/**
	 * ゲーム画面の幅。
	 */
	width: number;
	/**
	 * ゲーム画面の高さ。
	 */
	height: number;
	/**
	 * ゲームのFPS。
	 */
	fps: number;
}

/**
 * ユーザ入力で `BasicParameters` を取得する。
 */
function promptGetBasicParameters(current: Partial<BasicParameters>, skipAsk: boolean): Promise<BasicParameters> {

	const schema = {
		properties: {
			width: {
				type: "number",
				message: "width must be a number",
				default: current.width || 320,
				ask: () => !skipAsk
			},
			height: {
				type: "number",
				message: "height must be a number",
				default: current.height || 320,
				ask: () => !skipAsk
			},
			fps: {
				type: "number",
				message: "fps must be a number",
				default: current.fps || 30,
				ask: () => !skipAsk
			}
		}
	};
	return new Promise<BasicParameters>((resolve: (param: BasicParameters) => void, reject: (err: any) => void) => {
		Prompt.start();
		Prompt.get(schema, (err: any, result: BasicParameters) => {
			Prompt.stop();

			if (!err) err =  validateBasicParameters(result, schema.properties);

			if (err) {
				reject(err);
			} else {
				resolve(result);
			}
		});
	});
}


/**
 * basicParameter 値の妥当性チェック。
 * schema.properties.type と値の型が一致するかチェックする。
 *
 * @param params {object}
 * @param props {object}
 */
function validateBasicParameters(params: any, props: any): string {
	let errMessage = "";
	Object.keys(params).forEach((key) => {
		if (errMessage || !params.hasOwnProperty(key) || !props.hasOwnProperty(key)) return;

		if (props[key].type === "number") {
			// type　が　number　の場合で、値が NaN or null の場合、エラーとする
			if (isNaN(params[key]) || params[key] === null)
				errMessage = props[key].message;
		}
	});
	return errMessage;
}

/**
 * game.json に BasicParameters の内容をセットする。
 */
function setBasicParameters(conf: GameConfiguration, basicParams: BasicParameters): void {
	conf.width = basicParams.width;
	conf.height = basicParams.height;
	conf.fps = basicParams.fps;
}

/**
 * 指定した game.json の基本パラメータを更新する
 */
export async function updateConfigurationFile(confPath: string, logger: Logger, skipAsk: boolean): Promise<void> {
	let conf = {} as GameConfiguration;
	try {
		conf = await readJSON<GameConfiguration>(confPath);
	} catch (_e) {
		logger.info("No game.json found. Create a new one.");
	}
	const basicParams = await promptGetBasicParameters({
		width: conf.width,
		height: conf.height,
		fps: conf.fps
	}, skipAsk);

	setBasicParameters(conf, basicParams);
	return await writeJSON(confPath, conf);
}

import type { InitCommonOptions} from "../common/InitCommonOptions.js";
import { completeInitCommonOptions, confirmAccessToUrl } from "../common/InitCommonOptions.js";
import { createGitUri, parseCloneTargetInfo } from "./cloneTemplate.js";

export type GitProtocol = "https" | "ssh";

export interface InitParameterObject extends InitCommonOptions {
	/**
	 * 作業ディレクトリ。
	 * 省略された場合、 `process.cwd()` 。
	 */
	cwd?: string;

	/**
	 * 出力するテンプレートの種別。大文字小文字は区別されない。
	 * 省略された場合、`akashic-config` の設定値を利用。
	 */
	type?: string;

	/**
	 * コピー先に既にファイルが存在していてもコピーするかどうか
	 */
	forceCopy?: boolean;

	/**
	 * ユーザー入力無しでプロジェクトの作成を行うかどうか
	 */
	skipAsk?: boolean;

	/**
	 * git コマンドのパス。
	 */
	gitBinPath?: string;

	/**
	 * GitHub のホスト。
	 * 省略された場合 `github.com` 。
	 */
	githubHost?: string;

	/**
	 * GitHub からクローンする際のプロトコル。
	 * 省略された場合 `https` 。
	 */
	githubProtocol?: GitProtocol;

	/**
	 * GitHub Enterprise のホスト。
	 * 省略された場合 `null` 。
	 */
	gheHost?: string | null;

	/**
	 * GitHub Enterprise からクローンする際のプロトコル。
	 * 省略された場合 `https` 。
	 */
	gheProtocol?: GitProtocol;
}

export type NormalizedInitParameterObject = Required<InitParameterObject>;

/**
 * 未代入のパラメータを補完する
 */
export async function completeInitParameterObject(param: InitParameterObject): Promise<NormalizedInitParameterObject> {
	const {
		logger,
		configFile,
		repository,
		templateListJsonPath,
		localTemplateDirectory
	} = await completeInitCommonOptions(param);

	const cwd = param.cwd || process.cwd();
	const gitBinPath = param.gitBinPath || process.env.GIT_BIN_PATH || "git";

	const type = await _complete(param.type, configFile.getItem("init.defaultTemplateType"), "javascript");
	const githubHost = await _complete(param.githubHost, configFile.getItem("init.github.host"), "github.com");
	const githubProtocol = await _complete(param.githubProtocol, configFile.getItem("init.github.protocol"), "https");
	const gheHost = await _complete(param.gheHost, configFile.getItem("init.ghe.host"), "");
	const gheProtocol = await _complete(param.gheProtocol, configFile.getItem("init.ghe.protocol"), "https");

	if (!isGitProtocol(githubProtocol))
		throw new Error(`invalid option githubProtocol: ${githubProtocol}`);
	if (!isGitProtocol(gheProtocol))
		throw new Error(`invalid option gheProtocol: ${gheProtocol}`);

	const { gitType, owner, repo } = parseCloneTargetInfo(type);
	if (gitType === "github" && owner !== "akashic-games" ) {
		const url = createGitUri(githubHost, githubProtocol, owner, repo);
		const accepted = await confirmAccessToUrl(url);
		if (!accepted) process.exit(1);

	} else if (gitType === "ghe") {
		if (!gheHost) {
			throw new Error(
				`Type '${param.type}' requires GHE host configuraton. ` +
				"Run akashic config set init.ghe.host <url>"
			);
		}
		const url = createGitUri(gheHost, gheProtocol, owner, repo);
		const accepted = await confirmAccessToUrl(url);
		if (!accepted) process.exit(1);
	}

	return {
		logger,
		configFile,
		cwd,
		templateListJsonPath,
		gitBinPath,
		repository,
		localTemplateDirectory,
		forceCopy: !!param.forceCopy,
		skipAsk: !!param.skipAsk,
		type: type.toLowerCase(),
		githubHost,
		githubProtocol,
		gheHost,
		gheProtocol
	};
}

function isGitProtocol(s: string): s is GitProtocol {
	return s === "https" || s === "ssh";
}

async function _complete<T>(val: T | undefined, altVal: Promise<T | undefined>, defaultVal: NonNullable<T>): Promise<NonNullable<T>> {
	if (val != null) {
		return val;
	} else {
		const resolved = await altVal;
		if (resolved != null) {
			return resolved;
		} else {
			return defaultVal;
		}
	}
}

import { createRequire } from "module";
import * as path from "path";
import { readdir } from "@akashic/akashic-cli-commons/lib/FileSystem.js";
import type { Logger } from "@akashic/akashic-cli-commons/lib/Logger.js";
import { glob } from "glob";

// FIXME: ignore@6.0.2 において型に齟齬があるため暫定的に require() を用いている
const require = createRequire(import.meta.url);
const ignore = require("ignore");

export interface TemplateFileEntry {
	src: string;
	dst?: string;
}

export interface TemplateExtensionEntry {
	/**
	 * モジュールの名前。
	 */
	module: string;
	/**
	 * モジュールのバージョン。
	 * 省略された場合、 `latest` 。
	 */
	version?: string;
}

export interface TemplateConfig {
	/**
	 * このテンプレートのフォーマット。現在 "0" のみがサポートされている。
	 * 省略された場合、 `"0"` 。
	 */
	formatVersion?: "0";

	/**
	 * コピーするファイルの指定。
	 * 省略された場合、直下の全て (ただし template.json を除く) がコピーされる。
	 * 省略された場合、直下に game.json がなければならない。
	 */
	files?: TemplateFileEntry[];

	/**
	 * コピーから除外するファイルの指定。glob 形式のワイルドカードがサポートされる。
	 * 省略した場合は files で指定されたすべてのファイルがコピーさせる。
	 */
	exclude?: string[];

	/**
	 * 中に含まれる game.json のパス。
	 * 省略された場合、 "game.json" 。
	 */
	gameJson?: string;

	/**
	 * テンプレートからのゲーム生成の後に表示する説明文。
	 * `null` なら何も表示しない。
	 * 省略された場合、 `null` 。
	 */
	guideMessage?: string | null;

	/**
	 * このテンプレートで利用する拡張機能。
	 * 省略された場合、空配列。
	 */
	extensions?: TemplateExtensionEntry[];
}

// ref. https://off.tokyo/blog/typescript-saiki-utility-types/#DeepRequired
type IsPrimitive<T> = T extends Array<any> ? never : T extends { [key: string]: any } ? never : T;
type DeepRequired<T> = {
	[P in keyof T]-?: T[P] extends IsPrimitive<T[P]> ? T[P] : DeepRequired<T[P]>;
};

export type NormalizedTemplateConfig = DeepRequired<Omit<TemplateConfig, "exclude">>;

export async function completeTemplateConfig(
	templateConfig: TemplateConfig,
	baseDir: string,
	logger?: Logger
): Promise<NormalizedTemplateConfig> {
	const { formatVersion, files, exclude, gameJson, guideMessage, extensions } = templateConfig;

	if (formatVersion != null && formatVersion !== "0") {
		throw new Error(
			`Unsupported formatVersion: "${formatVersion}". ` +
			"The only valid value for this version is \"0\". " +
			"Newer version of akashic-cli may support this formatVersion."
		);
	}

	if (logger && (files && files.length > 0) && (exclude && exclude.length > 0)) {
		logger.warn("Both \"files\" and \"exclude\" are found in template.json, \"exclude\" is ignored.");
	}

	let normalizedFiles: Required<TemplateFileEntry>[];
	if (files) {
		normalizedFiles = files.map(({ src, dst }) => {
			if (/\.\./.test(src) || (dst && /\.\./.test(dst)))
				throw new Error("template.json has an invalid file name:");
			return { src, dst: dst ?? "" };
		});
	} else if (exclude && exclude.length > 0) {
		const filter = ignore().add(exclude).createFilter();
		const filepaths = (await glob("**", { cwd: baseDir, nodir: true, dot: true, posix: true })).filter(filter);
		normalizedFiles = filepaths
			.filter(filepath => path.basename(filepath) !== "template.json")
			.map(filepath => ({ src: filepath, dst: "" } as Required<TemplateFileEntry>));
	} else {
		// files を省略した際の既存挙動
		const fileNames = await readdir(baseDir);
		normalizedFiles = fileNames
			.filter(fileName => fileName !== "template.json")
			.map(fileName => ({ src: fileName, dst: "" } as Required<TemplateFileEntry>));
	}

	const normalizedExtensions = (extensions ?? []).map(({ module, version }) => ({ module, version: version ?? "latest" }));

	return {
		formatVersion: formatVersion ?? "0",
		files: normalizedFiles,
		gameJson: gameJson ?? "game.json",
		guideMessage: guideMessage ?? null,
		extensions: normalizedExtensions,
	};
}

import * as childProcess from "child_process";
import * as fs from "fs/promises";
import * as path from "path";
import * as util from "util";
import type { GitProtocol, InitParameterObject } from "./InitParameterObject.js";
const exec = util.promisify(childProcess.exec);

interface GitCloneParameterObject {
	owner: string | null;
	repo: string | null;
	branch: string | null;
	targetPath: string;
	preserveGitDirectory?: boolean;
	shallow?: boolean;
}

export interface CloneTargetInfo {
	gitType: string | null;
	owner: string | null;
	repo: string | null;
	branch: string | null;
}

/**
 * GitHub または GitHub Enterprise から リポジトリを clone する。
 */
export async function cloneTemplate(
	host: string,
	protocol: GitProtocol,
	o: GitCloneParameterObject,
	param: InitParameterObject
): Promise<void> {
	const opts = completeParameter(o);
	const { owner, repo, targetPath } = opts;
	const uri = createGitUri(host, protocol, owner, repo);
	const gitBinPath = process.env.GIT_BIN_PATH ?? param.gitBinPath ?? "git";
	const command = createGitCloneCommand(gitBinPath, uri, targetPath, opts);

	try {
		param.logger?.info(`clone git repository from "${host}/${owner}/${repo}".`);
		await exec(`${command}`, { encoding: "utf-8" });
	} catch (e) {
		throw new Error(e.stderr);
	}

	if (!opts.preserveGitDirectory) {
		await fs.rm(path.join(targetPath, ".git"), { recursive: true, force: true });
	}
}

function completeParameter(opts: GitCloneParameterObject): Required<GitCloneParameterObject> {
	return {
		...opts,
		preserveGitDirectory: opts.preserveGitDirectory ?? false,
		shallow: opts.shallow ?? !opts.preserveGitDirectory
	};
}

export function createGitUri(host: string, protocol: GitProtocol, owner: string | null, repo: string | null): string {
	if (protocol === "https") {
		return `${protocol}://${host}/${owner}/${repo}.git`;
	} else if (protocol === "ssh") {
		return `git@${host}:${owner}/${repo}.git`;
	}
	throw new Error(`unknown protocol: ${protocol}`);
}

function createGitCloneCommand(gitBinPath: string, uri: string, targetPath: string, opts: GitCloneParameterObject): string {
	const args: string[] = [];
	if (opts.shallow) {
		args.push("--depth 1");
	}
	if (opts.branch) {
		args.push(`--branch ${opts.branch}`);
	}

	return `${gitBinPath} clone ${args.join(" ")} ${uri} ${targetPath}`;
}

/**
 * type オプションの値をパースする。
 * @param type -t オプションの値
 */
export function parseCloneTargetInfo(type: string): CloneTargetInfo {
	const m = type.match(/(.+):(.+)\/([^#]+)(?:#(.*))?/) ?? [];
	const gitType = m[1] ?? null;
	const owner = m[2] ?? null;
	const repo = m[3] ?? null;
	const branch = m[4] ?? null;
	return {
		gitType,
		owner,
		repo,
		branch
	};
}

import { existsSync } from "fs";
import * as fs from "fs/promises";
import { spawn } from "node:child_process";
import * as path from "path";
import { readJSON } from "@akashic/akashic-cli-commons/lib/FileSystem.js";
import type { Logger } from "@akashic/akashic-cli-commons/lib/Logger.js";
import checkbox from "@inquirer/checkbox";
import fsx from "fs-extra";
import {
	collectLocalTemplatesMetadata,
	digestOfTemplateMetadata,
	fetchRemoteTemplatesMetadata,
	fetchTemplate
} from "../common/TemplateMetadata.js";
import { updateConfigurationFile } from "./BasicParameters.js";
import { cloneTemplate, parseCloneTargetInfo } from "./cloneTemplate.js";
import type { InitParameterObject} from "./InitParameterObject.js";
import { completeInitParameterObject } from "./InitParameterObject.js";
import type { TemplateConfig, NormalizedTemplateConfig } from "./TemplateConfig.js";
import { completeTemplateConfig } from "./TemplateConfig.js";

export async function promiseInit(p: InitParameterObject): Promise<void> {
	const param = await completeInitParameterObject(p);
	const { type, cwd, logger, skipAsk, forceCopy, repository, templateListJsonPath, localTemplateDirectory } = param;
	const { gitType, owner, repo, branch } = parseCloneTargetInfo(type);
	let templatePath: string | null = null;

	try {
		if (gitType === "github" || gitType === "ghe") {
			// completeInitParameterObject() で gitType が "ghe" の場合は gheHost が非 null であることは保証されている。
			const host = gitType === "github" ? param.githubHost : param.gheHost!;
			const protocol = gitType === "github" ? param.githubProtocol : param.gheProtocol;
			templatePath = await fs.mkdtemp("init-");
			await cloneTemplate(
				host,
				protocol,
				{
					owner,
					repo,
					branch,
					targetPath: templatePath
				},
				param
			);
		} else {
			// テンプレート決定
			const templateListJsonUri = new URL(templateListJsonPath, repository).toString();
			const allMetadataList = [
				...(await fetchRemoteTemplatesMetadata(templateListJsonUri)),
				...(await collectLocalTemplatesMetadata(localTemplateDirectory))
			];
			const metadataList = allMetadataList.filter(metadata => metadata.name === type);
			if (metadataList.length === 0)
				throw new Error(`Unknown template name: ${type}`);
			const metadata = metadataList[0];
			if (metadataList.length > 1)
				logger.warn(`Found multiple templates named ${type}. Using ${digestOfTemplateMetadata(metadata)}`);

			// テンプレート取得
			templatePath = await fetchTemplate(metadata);
		}

		// template.json を元にファイルを抽出
		const rawConf = await _readJSONWithDefault<TemplateConfig>(path.join(templatePath, "template.json"), {});
		const conf = await completeTemplateConfig(rawConf, templatePath, logger);
		await _extractFromTemplate(conf, templatePath, cwd, { forceCopy, logger });

		// GitHub 経由以外の場合はユーザ入力でゲーム設定を更新
		if (!(gitType === "github" || gitType === "ghe")) {
			const gameJsonPath = path.join(cwd, conf.gameJson);
			await updateConfigurationFile(gameJsonPath, logger, skipAsk);
		}

		if (conf.extensions.length > 0) {
			logger.warn("⚠️ Installing extensions from untrusted templates or modules may be risky.");

			const extensions = await checkbox({
				message: "Select the extensions you want to install for this template:",
				choices: conf.extensions.map(({ module, version }) => ({ name: module, value: { module, version } })),
			});

			if (extensions.length > 0) {
				for (const { module, version } of extensions) {
					await _addExtensionToPackageJSON(module, version);
				}
				logger.info("The selected extensions have been added to your package.json. To actually install them, run `npm install`.");
			}
		}

		if (conf.guideMessage)
			logger.print(conf.guideMessage);
	} finally {
		if (templatePath && existsSync(templatePath)) {
			await fs.rm(templatePath, { recursive: true });
		}
	}

	param.logger.info("Done!");
}

export function init(param: InitParameterObject, cb: (err?: any) => void): Promise<void> | void {
	return promiseInit(param).then<void>(cb);
}

interface ExtractFromTemplateOptions {
	forceCopy?: boolean;
	logger?: Logger;
}

async function _extractFromTemplate(
	conf: NormalizedTemplateConfig,
	src: string,
	dest: string,
	opts: ExtractFromTemplateOptions
): Promise<void> {
	const { forceCopy, logger } = opts;
	const copyReqs = conf.files.map(entry => ({
		srcRelative: entry.src,
		destRelative: entry.dst || entry.src,
		src: path.join(src, entry.src),
		dest: path.join(dest, entry.dst || entry.src)
	}));
	if (!forceCopy) {
		const existings = copyReqs.filter(req => existsSync(req.dest)).map(req => req.destRelative);
		if (existings.length > 0)
			throw new Error(`aborted to copy files, because followings already exist. [${existings.join(", ")}]`);
	}
	copyReqs.forEach(req => {
		fsx.copySync(req.src, req.dest, { overwrite: forceCopy });
		logger?.info(`copied ${req.srcRelative}.`);
	});
}

async function _readJSONWithDefault<T>(filepath: string, defaultValue: T): Promise<T> {
	try {
		return await readJSON(filepath);
	} catch (e) {
		if (e.code === "ENOENT")
			return defaultValue;
		throw e;
	}
}

let spawnFn: typeof spawn = spawn;

function _setSpawnFn(mockSpawnFn: typeof spawn | undefined): void {
	spawnFn = mockSpawnFn ?? spawn;
}

/**
 * 与えられた拡張機能をパッケージとして package.json に追加する。
 * インストールはしない。
 */
function _addExtensionToPackageJSON(module: string, version: string): Promise<void> {
	return new Promise((resolve, reject) => {
		// 与えられた値をコマンドの引数として直接渡すことでコマンドインジェクションのリスクを低減
		const options = ["--save", "--package-lock-only", "--no-package-lock", "--save-prefix", _extractVersionPrefix(version)];
		const p = spawnFn("npm", ["install", ...options, `${module}@${version}`], { stdio: "inherit" });
		p.on("close", (code) => {
			if (code === 0) {
				resolve();
			} else {
				reject(new Error(`npm install failed with code ${code}`));
			}
		});
	});
}

/**
 * バージョン文字列から接頭辞 (^, ~, なし) を抽出する。
 * 例外として "latest" の場合は "^" を付与。
 */
function _extractVersionPrefix(version: string): string {
	if (version === "latest") return "^";
	const match = version.match(/^(\^|~)/);
	return match?.[1] ?? "";
}

export const internals = {
	_extractFromTemplate,
	_addExtensionToPackageJSON,
	_extractVersionPrefix,
	_setSpawnFn,
};

import * as os from "os";
import * as path from "path";
import { ConsoleLogger } from "@akashic/akashic-cli-commons/lib/ConsoleLogger.js";
import type { Logger } from "@akashic/akashic-cli-commons/lib/Logger.js";
import * as config from "@akashic/akashic-cli-extra/lib/config/config.js";
import Prompt from "prompt";

export interface InitCommonOptions {
	/**
	 * コマンドの出力を受け取るロガー。
	 * 省略された場合、akashic-cli-commons の `new ConsoleLogger()` 。
	 */
	logger?: Logger;

	/**
	 * 利用する設定ファイル
	 * 省略された場合、`akashic-config` のデフォルトディレクトリから読み込む。
	 */
	configFile?: config.AkashicConfigFile;

	/**
	 * テンプレートをダウンロード可能なサーバURL。
	 * 省略された場合、`akashic-config` の設定値を利用。
	 */
	repository?: string;

	/**
	 * サーバ上でテンプレート一覧を保持するJSONのパス。
	 * 省略された場合、 "template-list.json" を利用。
	 */
	templateListJsonPath?: string;

	/**
	 * ローカルファイルシステムでテンプレートを保存している場所。
	 * 省略された場合、`akashic-config` の設定値を利用。
	 */
	localTemplateDirectory?: string;
}

export type NormalizedInitCommonOptions = Required<InitCommonOptions>;

const initConfigValidator: config.StringMap = {
	"init.repository": "",
	"init.localTemplateDirectory": "",
	"init.defaultTemplateType": "",
	"init.github.host": "",
	"init.github.protocol": "",
	"init.ghe.host": "",
	"init.ghe.protocol": ""
};

const DEFAULT_TEMPLATE_REPOSITORY = "https://akashic-contents.github.io/templates/";

/**
 * 未代入のパラメータを補完する。
 * 戻り値の .configFile は .load() が呼ばれた状態で返される点に注意。
 */
export async function completeInitCommonOptions(opts: InitCommonOptions): Promise<NormalizedInitCommonOptions> {
	const logger = opts.logger || new ConsoleLogger();
	await validateRepositoryValue(logger, opts.repository);

	const configFile = opts.configFile || new config.AkashicConfigFile(initConfigValidator);
	const templateListJsonPath = opts.templateListJsonPath || "template-list.json";

	await configFile.load();
	const repository = opts.repository ?? (await configFile.getItem("init.repository")) ?? DEFAULT_TEMPLATE_REPOSITORY;
	const localTemplateDirectory =
		opts.localTemplateDirectory ??
		await configFile.getItem("init.localTemplateDirectory") ??
		path.join(os.homedir(), ".akashic-templates");

	return {
		logger,
		configFile,
		templateListJsonPath,
		repository,
		localTemplateDirectory,
	};
}

async function validateRepositoryValue(logger: Logger, repository: string | undefined): Promise<void> {
	if (repository) {
		if (/(^(github|ghe):)|(\.git$)/.test(repository)) {
			logger.warn("Misused -r, --repository options. Use -t option for Github repository");
		}

		if (repository !== DEFAULT_TEMPLATE_REPOSITORY) {
			const accepted = await confirmAccessToUrl(repository);
			if (!accepted) process.exit(1);
		}
	}
}

export async function confirmAccessToUrl(url: string): Promise<boolean> {
	const akashicConfigFile = new config.AkashicConfigFile(KNOWN_URL_VALIDATOR);
	const exists = await existsKnownUrl(url, akashicConfigFile);
	if (exists) return true;

	return new Promise<boolean>((resolve: (result: boolean) => void, reject: (err: any) => void) => {
		const schema = {
			properties: {
				confirm: {
					pattern: /^(yes|no|y|n)$/gi,
					description: `Attempting to connect to ${url}\n`
						+ "The template obtained here may cause arbitrary command execution"
						+ "(not by this command but by using the template).\n"
						+ "You should not use this URL unless you trust its owners and contents.\n"
						+ "Do you trust the owners and contents of this URL? (y/N)",
					required: true,
					default: "n"
				}
			}
		};
		Prompt.start();
		Prompt.get(schema, async (err: any, result: any) => {
			const value = result.confirm.toLowerCase();
			const ret = value === "y" || value === "yes";
			if (err) {
				reject(err);
			} else {
				if (ret) await saveKnownUrlToAkashicConfig(url, akashicConfigFile);
				resolve(ret);
			}
		});
	});
}

const MAX_NUM_KNOWN_URL = 4;
const KNOWN_URL_VALIDATOR = {
	"cache.initKnownUrl": ""
};

/**
 * アクセス対象の URL が .akashicrc に存在するかどうか。
 */
async function existsKnownUrl(url: string, configFile: config.AkashicConfigFile): Promise<boolean> {
	await configFile.load();
	const itemValue = await configFile.getItem("cache.initKnownUrl");
	const itemArray = itemValue ? JSON.parse(itemValue) : [];
	return itemArray.includes(url);
}

/**
 * アクセス許可した URL を .akashicrc へ保存する。
 */
async function saveKnownUrlToAkashicConfig(url: string, configFile: config.AkashicConfigFile): Promise<void> {
	await configFile.load();
	const itemValue = await configFile.getItem("cache.initKnownUrl");
	const itemArray = itemValue ? JSON.parse(itemValue) : [];

	if (!itemArray.includes(url)) {
		if (itemArray.length >= MAX_NUM_KNOWN_URL) itemArray.shift();
		itemArray.push(url);

		const items = JSON.stringify(itemArray);
		await configFile.setItem("cache.initKnownUrl", items);
		await configFile.save();
	}
}

import * as fs from "fs";
import * as os from "os";
import * as path from "path";
import { readdir } from "@akashic/akashic-cli-commons/lib/FileSystem.js";
import * as unzipper from "unzipper";

// TODO: 適切な場所に移動
interface TemplateList {
	/**
	 * このテンプレートリストのフォーマット。現在 "0" のみがサポートされている。
	 * 省略された場合、 `"0"` 。
	 */
	formatVersion?: "0";

	/**
	 * テンプレート名と URL (またはパス) のテーブル。
	 */
	templates: {[type: string]: string};
}

export type LocalTemplateMetadata = {
	sourceType: "local";
	name: string;
	path: string;
};

export type RemoteTemplateMetadata = {
	sourceType: "remote";
	name: string;
	url: string;
};

export type TemplateMetadata =
	LocalTemplateMetadata |
	RemoteTemplateMetadata;

export function digestOfTemplateMetadata(metadata: TemplateMetadata): string {
	switch (metadata.sourceType) {
		case "local": return metadata.path;
		case "remote": return metadata.url;
	}
}

export async function collectLocalTemplatesMetadata(templateDirectory: string): Promise<LocalTemplateMetadata[]> {
	try {
		const dirnames = await readdir(templateDirectory);
		return dirnames.map(dirname => ({
			sourceType: "local",
			name: dirname,
			path: path.join(templateDirectory, dirname)
		}));
	} catch (err) {
		if (err.code !== "ENOENT") throw err;
		return [];
	}
}

export async function fetchRemoteTemplatesMetadata(templateListJsonUri: string): Promise<RemoteTemplateMetadata[]> {
	const res = await fetch(templateListJsonUri);
	const templateListJson = (await res.json()) as TemplateList;
	const { formatVersion, templates } = templateListJson;

	if (formatVersion != null && formatVersion !== "0") {
		throw new Error(
			`Unsupported formatVersion "${formatVersion}" found in ${templateListJsonUri}. ` +
			"The only valid value for this version is \"0\". " +
			"Newer version of akashic-cli may support this formatVersion."
		);
	}

	return Object.keys(templates).map(name => {
		const rawUrl = templates[name];
		return {
			sourceType: "remote",
			name,
			url: new URL(rawUrl, templateListJsonUri).toString()
		};
	});
}

/**
 * テンプレートを取得する。
 *
 * remote ならテンポラリディレクトリにダウンロードし、local ならテンポラリディレクトリにコピーする。
 *
 * @param metadata 取得するテンプレート
 * @returns 取得したテンプレート(template.jsonがあるディレクトリ)のパス。テンポラリディレクトリでありうる。
 */
export async function fetchTemplate(metadata: TemplateMetadata): Promise<string> {
	switch (metadata.sourceType) {
		case "local": {
			const destDir = fs.mkdtempSync(path.join(os.tmpdir(), metadata.name + "-"));
			fs.cpSync(metadata.path, destDir, { recursive: true });
			return destDir;
		}
		case "remote": {
			const { name, url } = metadata;
			const res = await fetch(url);
			const arrayBuffer = await res.arrayBuffer();
			const zip = Buffer.from(arrayBuffer);
			const dest = fs.mkdtempSync(path.join(os.tmpdir(), name + "-"));
			await _extractZip(zip, dest);
			const templateRoot = await _findTemplateRoot(dest);
			if (!templateRoot)
				throw new Error(`No template root in ${dest} (obtained from ${url})`);
			return templateRoot;
		}
	}
}

async function _extractZip(buf: Buffer, dest: string): Promise<void> {
	const directory = await unzipper.Open.buffer(buf);
	await directory.extract({ path: dest });
}

async function _findTemplateRoot(dirpath: string): Promise<string | null> {
	const fileNames = await readdir(dirpath);
	if (fileNames.includes("template.json") || fileNames.includes("game.json"))
		return dirpath;

	// 中身がフォルダ一つならその中も探す (フォルダごと .zip にされていたり、.zip の展開時にフォルダが作られるケース救済)
	if (fileNames.length === 1) {
		const childDir = path.join(dirpath, fileNames[0]);
		if (fs.statSync(childDir).isDirectory()) // TODO commons に promise 版の stat() を作る
			return _findTemplateRoot(childDir);
	}
	return null;
}

