	commander.parse(argv);
}

import * as path from "path";
import * as cmn from "@akashic/akashic-cli-commons";

export interface ModifyBasicParameterParameterObject {
	/**
	 * 設定する対象。
	 * `"width"`, `"height"`, `"fps"` のいずれか。
	 */
	target: string;

	/**
	 * 設定する値。
	 */
	value: number;

	/**
	 * 作業ディレクトリ。
	 * 省略された場合、 `process.cwd()` 。
	 */
	cwd?: string;

	/**
	 * コマンドの出力を受け取るロガー。
	 * 省略された場合、akashic-cli-commons の `new ConsoleLogger()` 。
	 */
	logger?: cmn.Logger;
}

type NormalizedModifyBasicParameterParameterObject = Required<ModifyBasicParameterParameterObject>;

function _completeModifyBasicParameterParameterObject(
	param: ModifyBasicParameterParameterObject
): NormalizedModifyBasicParameterParameterObject {
	return {
		target: param.target,
		value: param.value,
		cwd: param.cwd || process.cwd(),
		logger: param.logger || new cmn.ConsoleLogger()
	};
}

export async function promiseModifyBasicParameter(param: ModifyBasicParameterParameterObject): Promise<void> {
	const { target, value, cwd, logger } = _completeModifyBasicParameterParameterObject(param);

	if (typeof value !== "number" || isNaN(value) || value <= 0 || Math.round(value) !== value) {
		return Promise.reject(new Error(target + " must be a positive integer but '" + value + "' is given."));
	}

	const restoreDirectory = cmn.Util.chdir(cwd);
	const gameJsonPath = path.join(process.cwd(), "game.json");
	let content = {} as cmn.GameConfiguration;
	try {
		content = await cmn.FileSystem.readJSON<cmn.GameConfiguration>(path.join(process.cwd(), "game.json"));
	} catch (_e) {
		logger.info("No game.json found. Create a new one.");
	}

	switch (target) {
		case "width":
			content.width = value;
			break;
		case "height":
			content.height = value;
			break;
		case "fps":
			content.fps = value;
			break;
		default:
			throw ("unknown target: " + target);
	};

	await cmn.FileSystem.writeJSON<cmn.GameConfiguration>(gameJsonPath, content);
	logger.info("Done!");
	await restoreDirectory();
}

export function modifyBasicParameter(param: ModifyBasicParameterParameterObject, cb: (err?: any) => void): void {
	promiseModifyBasicParameter(param).then(cb, cb);
}

import * as fs from "fs";
import * as os from "os";
import * as path from "path";
import * as cmn from "@akashic/akashic-cli-commons";
import { modifyBasicParameter } from "../modify.js";

describe("modify", () => {
	const nullLogger = new cmn.ConsoleLogger({ quiet: true, debugLogMethod: () => {/* do nothing */} });
	const modifyDirPath = fs.mkdtempSync(path.join(os.tmpdir(), "akashic-cli-modify"));

	const modifyParameterPromisified = (options: any): Promise<void> => {
		return new Promise((resolve, reject) => {
			modifyBasicParameter(options, (err: any) => {
				if (err) reject(err);
				else resolve();
			});
		});
	};

	describe("modifyBasicParameter()", () => {
		it("rejects for negative values", async () => {
			const fixtureDirPath = fs.mkdtempSync(path.join(modifyDirPath, "fixture"));
			fs.writeFileSync(path.join(fixtureDirPath, "game.json"), JSON.stringify({ width: 320, height: 240, fps: 15 }));

			await expect(modifyParameterPromisified({ cwd: fixtureDirPath, target: "height", value: -10, logger: nullLogger }))
				.rejects.toBeTruthy();
			await expect(modifyParameterPromisified({ cwd: fixtureDirPath, target: "height", value: 15.5, logger: nullLogger }))
				.rejects.toBeTruthy();
		});

		it("rejects for invalid target", async () => {
			const fixtureDirPath = fs.mkdtempSync(path.join(modifyDirPath, "fixture"));
			fs.writeFileSync(path.join(fixtureDirPath, "game.json"), JSON.stringify({ width: 320, height: 240, fps: 15 }));

			await expect(modifyParameterPromisified({ cwd: fixtureDirPath, target: "foo", value: 10, logger: nullLogger }))
				.rejects.toBeTruthy();
		});

		it("modify width/height/fps", async () => {
			const fixtureDirPath = fs.mkdtempSync(path.join(modifyDirPath, "fixture"));
			fs.writeFileSync(path.join(fixtureDirPath, "game.json"), JSON.stringify({
				width: 320, height: 240, fps: 15,
				assets: {
					mainScene: { type: "script", path: "script/mainScene.js", global: true }
				}
			}));
			fs.mkdirSync(path.join(fixtureDirPath, "script"));
			fs.writeFileSync(path.join(fixtureDirPath, "script", "mainScene"), "MAINSCENE");

			await modifyParameterPromisified({ cwd: fixtureDirPath, target: "height", value: 80, logger: nullLogger });
			await modifyParameterPromisified({ cwd: fixtureDirPath, target: "width", value: 160, logger: nullLogger });
			await modifyParameterPromisified({ cwd: fixtureDirPath, target: "fps", value: 60, logger: nullLogger });

			const gamejson = JSON.parse(fs.readFileSync(path.join(fixtureDirPath, "game.json")).toString());
			expect(gamejson.width).toBe(160);
			expect(gamejson.height).toBe(80);
			expect(gamejson.fps).toBe(60);
		});
	});
});

import { createRequire } from "module";
import { ConsoleLogger } from "@akashic/akashic-cli-commons";
import { Command } from "commander";
import * as config from "./config.js";

const require = createRequire(import.meta.url);
const { version } = require("../../package.json");

/**
 * akashic cli configを実行する
 *
 * この関数は複数回呼ばれるべきではない
 */
export function run(argv: string[]): void {
	const commander = new Command();
	commander
		.description("List and edit configurations")
		.version(version)
		.usage("<command> [argument]");

	commander
		.command("get [target]")
		.description("get configuration from your .akashicrc")
		.action(async (target: string, opts: any = {}) => {
			const logger = new ConsoleLogger({ quiet: opts.quiet });
			const value = await config.getConfigItem(null, target);
			// 互換性のために "null" の文字列を返している。(config に存在しない場合)
			// 利用者は akashic-cli 内部に限られるはずで、本当は悪影響なくこの仕様は変更できる可能性がある。
			logger.print(value ?? "null");
		});

	commander
		.command("set [target] [value]")
		.description("set configuration to your .akashicrc")
		.action(async (target: string, value: string, _opts: any = {}) => {
			await config.setConfigItem(null, target, value);
		});

	commander
		.command("delete [target]")
		.description("delete configuration from your .akashicrc")
		.action(async (target: string, _opts: any = {}) => {
			await config.deleteConfigItem(null, target);
		});

	commander
		.command("list")
		// akashicrcの仕様を定義する validator が出来るまで --all は実装できない
		// .option("-a, --all", "List all items")
		.description("list configuration from your .akashicrc")
		.action(async (opts: any = {}) => {
			const logger = new ConsoleLogger({ quiet: opts.quiet });
			await config.listConfigItems(logger);
		});


	commander.parse(argv);

	if (!/^(get|set|delete|list)$/.test(argv[2])) {
		commander.help();
	}
}

import * as fs from "fs";
import * as os from "os";
import * as path from "path";
import type { Logger } from "@akashic/akashic-cli-commons";
import * as ini from "ini";
import lodashGet from "lodash/get.js";
import lodashSet from "lodash/set.js";
import lodashUnset from "lodash/unset.js";

export type StringMap = {[key: string]: string};

export class AkashicConfigFile {
	data: StringMap;
	private _validator: StringMap | null;
	private _path: string;

	constructor(validator: StringMap | null, configPath: string = path.join(os.homedir(), ".akashicrc")) {
		this._validator = validator;
		this.data = {};
		this._path = configPath;
	}

	load(): Promise<void> {
		return new Promise<void>((resolve, reject) =>
			fs.readFile(this._path, "utf8", (err, str) => {
				if (err) {
					if (err.code === "ENOENT") {
						resolve(); // 設定ファイル未作成状態
						return;
					}
					reject(err);
					return;
				}
				this.data = ini.decode(str);
				resolve();
			})
		);
	}

	save(): Promise<void> {
		return new Promise<void>((resolve, reject) =>
			fs.writeFile(this._path, ini.encode(this.data), err => {
				if (err) {
					reject(err);
					return;
				}
				resolve();
			})
		);
	}

	isValidKey(key: string): boolean {
		return !this._validator || lodashGet(this._validator, key, null) != null;
	}

	isValidValue(key: string, value: string): boolean {
		if (!this._validator) return true;
		const reStr = lodashGet(this._validator, key, null);
		if (reStr == null) return false;
		return (new RegExp(reStr)).test(value);
	}

	getItem(key: string): Promise<string | null> {
		if (!this.isValidKey(key)) {
			return Promise.reject<string>("invalid key name: " + key);
		}
		return Promise.resolve(lodashGet(this.data, key, null));
	}

	setItem(key: string, value: string): Promise<void> {
		if (!this.isValidKey(key)) {
			return Promise.reject("invalid key name: " + key);
		}
		if (!this.isValidValue(key, value)) {
			return Promise.reject("invalid value: " + value);
		}
		lodashSet(this.data, key, value);
		return Promise.resolve();
	}

	deleteItem(key: string): Promise<void> {
		if (!this.isValidKey(key)) {
			return Promise.reject("invalid key name: " + key);
		}
		lodashUnset(this.data, key);
		return Promise.resolve();
	}
}

export function getConfigItem(validator: StringMap | null, key: string, confPath?: string): Promise<string | null> {
	const config = new AkashicConfigFile(validator, confPath);
	return config.load().then(() => config.getItem(key));
}

export function setConfigItem(validator: StringMap | null, key: string, value: string, confPath?: string): Promise<void> {
	const config = new AkashicConfigFile(validator, confPath);
	return config.load().then(() => config.setItem(key, value)).then(() => config.save());
}

export function deleteConfigItem(validator: StringMap | null, key: string, confPath?: string): Promise<void> {
	const config = new AkashicConfigFile(validator, confPath);
	return config.load().then(() => config.deleteItem(key)).then(() => config.save());
}

export function listConfigItems(logger: Logger, confPath?: string): Promise<void> {
	const config = new AkashicConfigFile({}, confPath);
	return config.load().then(() => {
		function traverse(data: {[key: string]: any}, prefix: string = ""): void {
			Object.keys(data).forEach(key => {
				if (typeof data[key] === "object") {
					traverse(data[key], `${prefix}${key}.`);
				} else {
					logger.print(`${prefix}${key} = ${data[key]}`);
				}
			});
		}
		traverse(config.data);
	});
}

export function listAllConfigItems(logger: Logger, validator: StringMap, confPath?: string): Promise<void> {
	const config = new AkashicConfigFile({}, confPath);

	return config.load().then(() =>
		Object.keys(validator).forEach(key =>
			logger.print(`${key} = ${lodashGet(config.data, key, "")}`)
		)
	);
}

