const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

export interface ExportZipParameterObject {
	bundle?: boolean;
	babel?: boolean;
	minify?: boolean;
	minifyJs?: boolean;
	minifyJson?: boolean;
	terser?: MinifyOptions;
	packImage?: boolean;
	strip?: boolean;
	source?: string;
	dest?: string;
	force?: boolean;
	logger?: cmn.Logger;
	hashLength?: number;
	exportInfo?: cmn.ExportZipInfo;
	omitUnbundledJs?: boolean;
	targetService?: cmn.ServiceType;
	nicolive?: boolean;
	resolveAkashicRuntime?: boolean;
	preservePackageJson?: boolean;
}

function _createExportInfo(param: ExportZipParameterObject): cmn.ExportZipInfo {
	return {
		version: JSON.parse(fs.readFileSync(path.resolve(__dirname, "..", "..", "package.json"), "utf8")).version,
		option: {
			force: !!param.force,
			strip: !!param.strip,
			minify: !!param.minify,
			minifyJs: !!param.minifyJs,
			minifyJson: !!param.minifyJson,
			packImage: !!param.packImage,
			bundle: !!param.bundle,
			babel: !!param.babel,
			targetService: param.targetService || "none"
		}
	};
}

export function _completeExportZipParameterObject(param: ExportZipParameterObject): ExportZipParameterObject {
	const source = param.source || process.cwd();
	const dest = path.resolve(source, (param.dest || "./game.zip"));
	return {
		bundle: !!param.bundle,
		babel: !!param.babel,
		minify: !!param.minify,
		minifyJs: !!param.minifyJs,
		minifyJson: !!param.minifyJson,
		terser: param.terser,
		packImage: !!param.packImage,
		strip: !!param.strip,
		source,
		dest,
		force: !!param.force,
		logger: param.logger || new cmn.ConsoleLogger(),
		hashLength: param.hashLength,
		exportInfo: param.exportInfo || _createExportInfo(param),
		omitUnbundledJs: param.omitUnbundledJs,
		targetService: param.targetService || "none",
		nicolive: !!param.nicolive,
		resolveAkashicRuntime: !!param.resolveAkashicRuntime,
		preservePackageJson: !!param.preservePackageJson
	};
}

// TODO akashic-cli-commons に移して export html と実装を共有する
export function _checkDestinationValidity(dest: string, force: boolean, logger?: cmn.Logger): Promise<void> {
	return new Promise<void>((resolve, reject) => {
		fs.stat(path.resolve(dest), (error: any, _stat: any) => {
			if (error) {
				if (error.code === "ENOENT") {
					resolve();
				} else {
					reject(new Error("Error code " + error.code + " for " + dest));
				}
				return;
			}
			if (!force) {
				reject(new Error(dest + " already exists. Use --force option to overwrite."));
			} else {
				logger?.warn(`${dest} already exists and will be removed due to --force option.`);
				resolve();
			}
		});
	});
}

export function promiseExportZip(param: ExportZipParameterObject): Promise<void> {
	param = _completeExportZipParameterObject(param);
	const outZip = /\.zip$/.test(param.dest);
	const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "akashic-export-zip-"));
	const destDir = param.dest;

	return _checkDestinationValidity(param.dest, param.force, param.logger)
		.then(() => {
			return convertGame({
				bundle: param.bundle,
				babel: param.babel,
				minify: param.minify,
				minifyJs: param.minifyJs,
				minifyJson: param.minifyJson,
				terser: param.terser,
				packImage: param.packImage,
				strip: param.strip,
				source: param.source,
				dest: tmpDir,
				hashLength: param.hashLength,
				logger: param.logger,
				exportInfo: param.exportInfo,
				omitUnbundledJs: param.omitUnbundledJs,
				targetService: param.targetService,
				nicolive: param.nicolive,
				resolveAkashicRuntime: param.resolveAkashicRuntime,
				preservePackageJson: param.preservePackageJson
			});
		})
		.then(() => {
			if (!outZip) {
				fs.rmSync(destDir, { recursive: true, force: true });
				fs.cpSync(tmpDir, destDir, { recursive: true });
				return;
			}
			return new Promise<void>((resolve, reject) => {
				const files = cmn.Util.readdirRecursive(tmpDir).map(p => ({
					src: path.resolve(tmpDir, p),
					entryName: p
				}));
				const ostream = fs.createWriteStream(destDir);
				const archive = archiver("zip");
				ostream.on("close", () => resolve());
				archive.on("error", (err) => reject(err));
				archive.pipe(ostream);
				files.forEach((f) => archive.file(f.src, {name: f.entryName}));
				return archive.finalize();
			});
		})
		.then(() => {
			const gameJson = JSON.parse(fs.readFileSync(path.resolve(tmpDir, "game.json"), "utf8"));
			const params = {
				logger: param.logger,
				basepath: tmpDir,
				game: gameJson,
				raw: false
			};
			return statSize(params);
		})
		.then(() => {
			try {
				fs.rmSync(path.resolve(tmpDir), { recursive: true });
			} catch (_error) {
				// キャッシュ削除の失敗は動作に致命的な影響を与えないため握りつぶす
			}
		});
}

export function exportZip(param: ExportZipParameterObject, callback: (err?: Error) => void): void {
	promiseExportZip(param).then(() => callback(), callback);
}

import type { IRectangle } from "maxrects-packer";

export interface PackTarget<T = void> {
	name: string;
	width: number;
	height: number;
	data: T;
}

export interface PackedRect<T = void> extends PackTarget<T> {
	x: number;
	y: number;
}

export interface PackResult<T = void> {
	width: number;
	height: number;
	rects: PackedRect<T>[];
}

interface MaxRectsPackerTarget<T> extends PackedRect<T>, IRectangle {
	area: number;
	hash: string;
}

/**
 * 与えられた矩形群のうち、小さい矩形をパッキングする。
 *
 * できるだけ矩形の数が減るように、この関数はできるだけ面積の小さい矩形を優先的に詰め込む。
 * ただし実行効率上、必ず小さい方の矩形から順にパッキングされるとは限らない。
 *
 * @param targets 敷き詰めを試みる矩形群。
 * @param width 敷き詰め結果画像の最大幅。
 * @param height 敷き詰め結果画像の最大高さ。
 */
export async function packSmallRects<T = void>(targets: PackTarget<T>[], width: number, height: number): Promise<PackResult<T> | null> {
	// eslint-disable-next-line @typescript-eslint/naming-convention
	const { MaxRectsPacker } = await import("maxrects-packer");

	let tgts: MaxRectsPackerTarget<T>[] = targets.map(t => ({
		...t,
		area: t.width * t.height,
		x: 0, // maxrects-packer の型に合わせるため必要な値 (README を見る限り不要だが IRectangle に必要) 。
		y: 0, // 同上。
		hash: t.name // 不要だが、あると maxrects-packer の packing 結果が安定する値。
	}));

	// サイズ昇順で詰めていって、理論的上限 (width * height) を少し超えるであろう矩形群までを対象にパッキングする。
	tgts.sort((a, b) => a.area - b.area);
	let i = 0;
	for (let areaAcc = 0; i < tgts.length && areaAcc < width * height; ++i) {
		areaAcc += tgts[i].area;
	}
	tgts = tgts.slice(0, i);
	if (tgts.length === 0) return null;

	const packer = new MaxRectsPacker<MaxRectsPackerTarget<T>>(width, height, 2, {
		smart: true,
		pot: false,
		square: false,
		allowRotation: false,
		tag: true
	});
	packer.addArray(tgts);
	const bins = packer.bins;

	// 一枚に収まらない場合があるので、もっとも画像を詰め込まれた bin を敷き詰め結果として返す。
	const bin = bins.reduce((a, b) => ((a.rects.length >= b.rects.length) ? a : b), bins[0]!);

	if (bin.rects.length <= 1) return null;
	return { width: bin.width, height: bin.height, rects: bin.rects };
}

import * as fs from "fs";
import * as path from "path";
import { writeFile, unlink } from "@akashic/akashic-cli-commons/lib/FileSystem.js";
import type { GameConfiguration } from "@akashic/akashic-cli-commons/lib/GameConfiguration.js";
import { mkdirpSync } from "@akashic/akashic-cli-commons/lib/Util.js";
import type { AssetConfiguration, ImageAssetConfigurationBase } from "@akashic/game-configuration";
import type { PNG } from "pngjs";
import { makeUniqueAssetPath } from "./GameConfigurationUtil.js";
import type { PackResult, PackTarget } from "./packRects.js";
import { packSmallRects } from "./packRects.js";

/**
 * コンテンツ内の小さい画像 (PNG ファイル) を、一定サイズに収まる限りでパッキングして一つにまとめる。
 *
 * よりファイル数を削減しやすいよう小さい画像を優先的にまとめるが、
 * (パッキング処理の) 効率のため、必ずしも完全に画像のサイズ順に対象が決まるわけではない。
 * 不可逆圧縮である JPEG ファイルは対象にしない。
 *
 * @param gamejson PNG のパッキングを行うコンテンツの game.json 。破壊的に変更される。
 * @param basepath コンテンツのルートディレクトリのパス。このパス以下のファイルは破壊的に変更される。
 */
export async function transformPackSmallImages(gamejson: GameConfiguration, basepath: string): Promise<void> {
	return flushPackSideEffect(await transformPackSmallImagesImpl(gamejson, basepath));
}

export interface PackingFileOutput {
	path: string;
	width: number;
	height: number;
	content: Buffer | string;
}

/**
 * パッキングによるファイルへの副作用。
 */
export interface PackingFileSideEffect {
	/**
	 * パッキングによって生成された (保存されるべき) 画像データ。
	 */
	outputs: PackingFileOutput[];

	/**
	 * パッキングの結果不要になった (削除されるべき) ファイルのパス。
	 */
	discardables: string[];
}

/**
 * パッキング結果のファイル副作用を実際のファイルに反映する。
 */
export async function flushPackSideEffect(sideEffect: PackingFileSideEffect): Promise<void> {
	for (const output of sideEffect.outputs) {
		mkdirpSync(path.dirname(output.path)); // TODO ほかの利用箇所と合わせて非同期版を作って移行する
		await writeFile(output.path, output.content);
	}
	for (const discardable of sideEffect.discardables) {
		await unlink(discardable);
	}
}

interface ImageAssetPackData {
	path: string;
	assetIds: string[];
}

/**
 * transformPackSmallImages() の実処理。
 * 引数 gamejson を破壊するが、ファイルへの変更は行わずを戻り値で副作用の情報として返す。
 */
export async function transformPackSmallImagesImpl(gamejson: GameConfiguration, basepath: string): Promise<PackingFileSideEffect> {
	// このサイズにおさまる限りで画像を詰め込む。値は「余計に読み込んでも許容できる程度のサイズ」であればよく、調整の余地がある。
	const binWidth = 1024;
	const binHeight = 1024;

	// Akashic Engine が slice 指定をサポートしていないバージョンのコンテンツなら何もしない。
	const sandboxRuntimeVer = gamejson.environment["sandbox-runtime"] ?? "1";
	if (/^[12]$/.test(sandboxRuntimeVer)) return { outputs: [], discardables: [] };

	const rects = extractPackTargets(gamejson, binWidth, binHeight);
	const packResult = await packSmallRects(rects, binWidth, binHeight);
	if (!packResult)
		return { outputs: [], discardables: [] };
	return applyPackResults([packResult], gamejson, basepath);
}

export function extractPackTargets(
	gamejson: GameConfiguration,
	widthLimit: number,
	heightLimit: number
): PackTarget<ImageAssetPackData>[] {
	// NOTE 単純化のため、この関数は元から slice 指定のある画像アセットを無視する。
	// slice をサポートする場合、パスだけでは同じ内容の画像アセットを識別できなくなるため、
	// ImageAssetPackData の定義や applyPackResults() の実装まで含めて見直す必要がある。
	const pathToIdsTable = Object.keys(gamejson.assets).reduce((acc, aid) => {
		const decl = gamejson.assets[aid];
		if (isPackableImage(decl, widthLimit, heightLimit) && !decl.hasOwnProperty("slice")) // 既に slice があるものは単純化のため除外
			(acc[decl.path] ?? (acc[decl.path] = [])).push(aid);
		return acc;
	}, Object.create(null) as { [path: string]: string[] });

	return Object.keys(pathToIdsTable).map(p => {
		const assetIds = pathToIdsTable[p]!;
		const decl = gamejson.assets[assetIds[0]!]! as ImageAssetConfigurationBase;
		return {
			name: decl.path,
			width: decl.width!,
			height: decl.height!,
			data: { assetIds, path: decl.path }
		};
	});
}

function isPackableImage(decl: AssetConfiguration, widthThreshold: number, heightThreshold: number): boolean {
	return (
		decl.type === "image" &&
		decl.path.endsWith(".png") &&
		decl.width < widthThreshold &&
		decl.height < heightThreshold
	);
}

/**
 * パッキング結果をコンテンツに適用する。
 *
 * 引数の gamejson を破壊する。
 * ただしファイルへの変更は行わず、 `PackingFileSideEffect` として戻り値で返す。
 */
export async function applyPackResults(
	packResults: PackResult<ImageAssetPackData>[],
	gamejson: GameConfiguration,
	basepath: string
): Promise<PackingFileSideEffect> {
	const outputs: PackingFileOutput[] = [];
	const discardables: string[] = [];
	for (let i = 0; i < packResults.length; ++i) {
		const packResult = packResults[i];
		const packedPath = makeUniqueAssetPath(gamejson, `assets/aez_packed_image${i}.png`);
		const { width, height, rects } = packResult;

		const absPackedPath = path.join(basepath, packedPath);
		const rendered = await renderPNG(packResult, basepath);
		outputs.push({ path: absPackedPath, width, height, content: rendered });

		rects.forEach(rect => {
			discardables.push(path.join(basepath, rect.data.path));
			rect.data.assetIds.forEach(aid => {
				const orig = gamejson.assets[aid];
				gamejson.assets[aid] = {
					...orig,
					path: packedPath,
					width,
					height,
					virtualPath: orig.virtualPath ?? orig.path,
					slice: [rect.x, rect.y, rect.width, rect.height]
				} as ImageAssetConfigurationBase;
			});
		});
	}
	return { outputs, discardables };
}

async function readPNG(input: string): Promise<PNG> {
	const { PNG } = await import("pngjs");
	return new Promise((resolve, reject) => {
		const stream = fs.createReadStream(input).pipe(new PNG());
		stream.on("parsed", () => void resolve(stream));
		stream.on("error", err => reject(err));
	});
}

async function renderPNG(packResult: PackResult<ImageAssetPackData>, basepath: string): Promise<Buffer> {
	const { PNG } = await import("pngjs");
	const { width, height, rects } = packResult;
	const png = new PNG({ width, height });
	for (let i = 0; i < rects.length; i++) {
		const rect = rects[i];
		const src = await readPNG(path.join(basepath, rect.data.path));
		src.bitblt(png, 0, 0, src.width, src.height, rect.x, rect.y);
	}
	return PNG.sync.write(png);
}

