			sandboxConfig = require(path.join(options.source, "sandbox.config.js"));
		} catch (_error) {
			throw Error("failed read sandbox.config.js.");
		}
		validateSandboxConfigJs(sandboxConfig, options.autoSendEventName, options.autoGivenArgsName);
	}

	const terser = options.minify ? options.terser ?? {} : undefined;
	const nonBinaryAssetNames = extractAssetDefinitions(conf, "script").concat(extractAssetDefinitions(conf, "text"));
	const errorMessages: string[] = [];
	const nonBinaryAssetPaths = await Promise.all(nonBinaryAssetNames.map((assetName: string) => {
		return convertAssetAndOutput(assetName, conf, options.source, options.output, terser, options.esDownpile);
	}));
	assetPaths = assetPaths.concat(nonBinaryAssetPaths);
	const libPaths: string[] = [];
	if (conf._content.globalScripts) {
		const globalScriptPaths = await Promise.all(conf._content.globalScripts.map((scriptName: string) => {
			libPaths.push(scriptName);
			return convertGlobalScriptAndOutput(
				scriptName,
				options.source,
				options.output,
				terser);
		}));
		assetPaths = assetPaths.concat(globalScriptPaths);
	}

	await licenseUtil.writeLicenseTextFile(options.source, options.output, libPaths, content.environment["sandbox-runtime"]);

	if (errorMessages.length > 0) {
		options.logger.warn("The following ES5 syntax errors exist.\n" + errorMessages.join("\n"));
	}
	await writeHtmlFile(assetPaths, options.output, conf, options);
	writeOptionScript(options.output, options, conf);
}

async function convertAssetAndOutput(
	assetName: string,
	conf: cmn.Configuration,
	inputPath: string,
	outputPath: string,
	terser: MinifyOptions | undefined,
	esDownpile: boolean
): Promise<string> {
	const assets = conf._content.assets;
	const asset = assets[assetName];
	const isScript = asset.type === "script";
	const exports = (asset.type === "script" && asset.exports) ?? [];
	const assetString = fs.readFileSync(path.join(inputPath, asset.path), "utf8").replace(/\r\n|\r/g, "\n");
	const assetPath = asset.path;

	const code = (isScript ? wrapScript(assetString, assetName, terser, esDownpile, exports) : wrapText(assetString, assetName));
	const relativePath = "./js/assets/" + path.dirname(assetPath) + "/" +
		path.basename(assetPath, path.extname(assetPath)) + (isScript ? ".js" : ".json.js");
	const filePath = path.resolve(outputPath, relativePath);

	fs.mkdirSync(path.dirname(filePath), { recursive: true });
	fs.writeFileSync(filePath, code);
	return relativePath;
}

async function convertGlobalScriptAndOutput(
	scriptName: string, inputPath: string, outputPath: string,
	terser: MinifyOptions | undefined): Promise<string> {
	const scriptString = fs.readFileSync(path.join(inputPath, scriptName), "utf8").replace(/\r\n|\r/g, "\n");
	const isScript = /\.js$/i.test(scriptName);
	const code = isScript ? wrapScript(scriptString, scriptName, terser, false) : wrapText(scriptString, scriptName);
	const relativePath = "./globalScripts/" + scriptName + (isScript ? "" : ".js");
	const filePath = path.resolve(outputPath, relativePath);
	fs.mkdirSync(path.dirname(filePath), { recursive: true });
	fs.writeFileSync(filePath, code);
	return relativePath;
}

async function writeHtmlFile(
	assetPaths: string[],
	outputPath: string,
	conf: cmn.Configuration,
	options: ConvertTemplateParameterObject
): Promise<void> {
	const injects = options.injects ? options.injects : [];
	const version = conf._content.environment["sandbox-runtime"];
	const filePath = path.resolve(__dirname + "/../template/no-bundle-index.ejs");
	let engineFilePath: string;
	let engineFilesVariable: string;

	if (options.debugOverrideEngineFiles) {
		validateEngineFilesName(options.debugOverrideEngineFiles, version);
		engineFilePath = path.resolve(options.debugOverrideEngineFiles);
		engineFilesVariable = path.basename(options.debugOverrideEngineFiles, ".js");
	} else {
		engineFilePath = resolveEngineFilesPath(version);
		engineFilesVariable = path.basename(engineFilePath, ".js");
	}

	const html = await ejs.renderFile(filePath, {
		assets: assetPaths,
		magnify: !!options.magnify,
		injectedContents: getInjectedContents(options.cwd, injects),
		version: version,
		engineFilesVariable: engineFilesVariable,
		exportVersion: options.exportInfo !== undefined ? options.exportInfo.version : "",
		exportOption: options.exportInfo !== undefined ? options.exportInfo.option : "",
		autoSendEventName: options.autoSendEventName,
		autoGivenArgsName: options.autoGivenArgsName,
		sandboxConfigJsCode: options.sandboxConfigJsCode !== undefined ? options.sandboxConfigJsCode : "",
		hasInstanceStorage: hasInstanceStorageFeature(conf)
	});
	fs.writeFileSync(path.resolve(outputPath, "./index.html"), html);
}

function writeCommonFiles(
	inputPath: string,
	outputPath: string, conf: cmn.Configuration,
	options: ConvertTemplateParameterObject): void {
	if (options.strip) {
		copyAssetFilesStrip(inputPath, outputPath, conf._content.assets, options);
	} else {
		copyAssetFiles(inputPath, outputPath, options);
	}
	let templatePath: string;
	const version = conf._content.environment["sandbox-runtime"];
	switch (version) {
		case "1":
			templatePath = "template/v1";
			break;
		case "2":
			templatePath = "template/v2";
			break;
		case "3":
			templatePath = "template/v3";
			break;
		default:
			throw Error("Unknown engine version: `environment[\"sandbox-runtime\"]` field in game.json should be \"1\", \"2\", or \"3\".");
	}

	fs.cpSync(
		path.resolve(__dirname, "..", "..", "lib", templatePath),
		outputPath,
		{ recursive: true });

	const jsDir = path.join(outputPath, "js");
	const engineFilesPath = options.debugOverrideEngineFiles ?? resolveEngineFilesPath(version);
	fs.cpSync(
		path.resolve(engineFilesPath),
		path.join(jsDir, path.basename(engineFilesPath)),
		{ recursive: true }
	);
}

function writeOptionScript(outputPath: string, options: ConvertTemplateParameterObject, conf: cmn.Configuration): void {
	const script = `
if (! ("optionProps" in window)) {
	window.optionProps = {};
}
window.optionProps.magnify = ${!!options.magnify};
window.optionProps.hasInstanceStorage = ${!!hasInstanceStorageFeature(conf)};
	`;
	fs.writeFileSync(path.resolve(outputPath, "./js/option.js"), script);
}

function wrapScript(code: string, name: string, terser?: MinifyOptions, esDownpile?: boolean, exports: string[] = []): string {
	return "window.gLocalAssetContainer[\"" + name + "\"] = function(g) { " + wrap(code, terser, esDownpile, exports) + "}";
}

function wrapText(code: string, name: string): string {
	const PRE_SCRIPT = "window.gLocalAssetContainer[\"" + name + "\"] = \"";
	const POST_SCRIPT = "\"";
	return PRE_SCRIPT + encodeText(code) + POST_SCRIPT + "\n";
}

import * as fs from "fs";
import { createRequire } from "module";
import * as path from "path";
import { fileURLToPath } from "url";
import * as cmn from "@akashic/akashic-cli-commons";
import type { AssetConfigurationMap, ImageAssetConfigurationBase } from "@akashic/game-configuration";
import type { SandboxConfiguration } from "@akashic/sandbox-configuration";
import * as babel from "@babel/core";
import presetEnv from "@babel/preset-env";
import type { MinifyOptions } from "terser";
import { minify_sync } from "terser";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const require = createRequire(import.meta.url);

export interface ConvertTemplateParameterObject {
	output: string;
	logger: cmn.Logger;
	strip: boolean;
	minify: boolean;
	terser: MinifyOptions;
	magnify: boolean;
	force: boolean;
	source: string;
	cwd: string;
	unbundleText: boolean;
	injects?: string[];
	exportInfo?: {
		version: string;
		option: string;
	};
	autoSendEventName?: string | boolean;
	autoGivenArgsName?: string;
	sandboxConfigJsCode?: string;
	omitUnbundledJs?: boolean;
	esDownpile?: boolean;
	debugOverrideEngineFiles?: string;
}

export function extractAssetDefinitions (conf: cmn.Configuration, type: string): string[] {
	const assets = conf._content.assets;
	const assetNames = Object.keys(assets);
	return assetNames.filter((assetName) => assets[assetName].type === type);
}

export function hasInstanceStorageFeature(conf: cmn.Configuration): boolean {
	const external = conf._content.environment?.external;
	return !!external?.instanceStorage || !!external?.instanceStorageLimited;
}

export function copyAssetFilesStrip(
	inputPath: string, outputPath: string,
	assets: AssetConfigurationMap, options: ConvertTemplateParameterObject): void {
	options.logger.info("copying stripped fileset...");
	const assetNames = Object.keys(assets);
	assetNames.filter((assetName) => {
		return assets[assetName].type !== "script" && (options.unbundleText || assets[assetName].type !== "text");
	}).forEach((assetName) => {
		const assetPath = assets[assetName].path;
		const assetDir = path.dirname(assetPath);
		fs.mkdirSync(path.resolve(outputPath, assetDir), { recursive: true });
		const dst = path.join(outputPath, assetPath);
		if (assets[assetName].type === "audio") {
			cmn.KNOWN_AUDIO_EXTENSIONS.forEach((ext) => {
				try {
					fs.cpSync(
						path.resolve(inputPath, assetPath) + ext,
						dst + ext,
						{ force: !!options.force, recursive: true }
					);
				} catch (e) {
					if (e.code !== "ENOENT") {
						options.logger.error("Error while copying: " + e.message);
					}
				}
			});
		} else {
			fs.cpSync(
				path.resolve(inputPath, assetPath),
				dst,
				{ force: !!options.force, recursive: true }
			);
		}
	});
}

export function copyAssetFiles(inputPath: string, outputPath: string, options: ConvertTemplateParameterObject ): void {
	options.logger.info("copying files...");
	const scriptPath = path.resolve(inputPath, "script");
	const textPath = path.resolve(inputPath, "text");
	const isAssetToBeCopied = (src: string): boolean => {
		return path.relative(scriptPath, src)[0] === "." && (options.unbundleText || path.relative(textPath, src)[0] === ".");
	};
	try {
		const files = cmn.Util.readdirRecursive(inputPath);
		files.forEach(p => {
			cmn.Util.mkdirpSync(path.dirname(path.resolve(outputPath, p)));
			if (isAssetToBeCopied(path.resolve(inputPath, p))) {
				fs.writeFileSync(path.resolve(outputPath, p), fs.readFileSync(path.resolve(inputPath, p)));
			}
		});
	} catch (e) {
		options.logger.error("Error while copying: " + e.message);
	}
}

export function encodeText(text: string): string {
	return text.replace(/[\u2028\u2029'"\\\b\f\n\r\t\v%]/g, encodeURIComponent);
}

const babelOption = {
	presets: [
		babel.createConfigItem([presetEnv, {
			modules: false,
			targets: {
				"chrome": 51
			}
		}],
		{ type: "preset" })
	]
};

export function wrap(code: string, terser?: MinifyOptions, esDownpile?: boolean, exports: string[] = []): string {
	const preScript = "(function(exports, require, module, __filename, __dirname) {";
	let postScript: string = "";
	for (const key of exports) {
		postScript += `exports["${key}"] = typeof ${key} !== "undefined" ? ${key} : undefined;\n`;
	}
	postScript += "})(g.module.exports, g.module.require, g.module, g.filename, g.dirname);";
	// downpile -> minify の順序は入れ替えられない (先に minify すると babel がコードを整形してしまう)
	const downpiled = esDownpile ? babel.transform(code, babelOption).code : code;
	const ret = preScript + "\n" + (terser ? minify_sync(downpiled, terser).code : downpiled) + "\n" + postScript + "\n";
	return ret;
}

export function getDefaultBundleScripts(
	templatePath: string,
	conf: cmn.Configuration,
	options: ConvertTemplateParameterObject,
	bundleText: boolean = true,
	overrideEngineFilesPath?: string
): any {
	const version = conf._content.environment?.["sandbox-runtime"] ?? "1";
	let engineFilePath: string;
	let engineFilesVariable: string;

	if (overrideEngineFilesPath) {
		validateEngineFilesName(overrideEngineFilesPath, version);
		engineFilePath = path.resolve(overrideEngineFilesPath);
		engineFilesVariable = path.basename(overrideEngineFilesPath, ".js");
	} else {
		engineFilePath = resolveEngineFilesPath(version);
		engineFilesVariable = path.basename(engineFilePath, ".js");
	}

	const preloadScript = `
		window.engineFiles = ${engineFilesVariable};
		window.g = engineFiles.akashicEngine;
		(function() {
			var originalRequire = window.require;
			window.require = function(moduleName) {
				switch(moduleName) {
					case "@akashic/akashic-engine":
						return engineFiles.akashicEngine;
					default:
						return this.call(this, moduleName);
				}
			};
		})();
	`;
	const postloadScriptNames =
		["sandbox.js", "initGlobals.js"];
	if (version === "3") {
		postloadScriptNames.push("pdi/LocalScriptAssetV3.cjs");
		if (bundleText) {
			postloadScriptNames.push("pdi/LocalTextAssetV3.cjs");
		}
		if (hasInstanceStorageFeature(conf)) {
			postloadScriptNames.push("plugin-instance-storage.js", "plugin-instance-storage-limited.js");
		}
	} else {
		postloadScriptNames.push("pdi/LocalScriptAsset.cjs");
		if (bundleText) {
			postloadScriptNames.push("pdi/LocalTextAsset.cjs");
		}
	}
	if (version === "1") postloadScriptNames.push("logger.js");

	let preloadScripts = [loadScriptFile(engineFilePath)];
	preloadScripts.push(preloadScript);

	let postloadScripts = postloadScriptNames.map((fileName) => {
		const filePath = path.resolve(__dirname, "..", "..", "lib", templatePath, "js", fileName);
		return loadScriptFile(filePath);
	});

	if (options.minify) {
		// NOTE: エンジン側が提供するコードを mangling されると動作に支障をきたす可能性があるため、この部分はデフォルト設定を与える
		preloadScripts = preloadScripts.map(script => minify_sync(script).code);
		postloadScripts = postloadScripts.map(script => minify_sync(script).code);
	}
	return {
		preloadScripts,
		postloadScripts
	};
}

export function getDefaultBundleStyle(templatePath: string): string {
	const filepath = path.resolve(__dirname, "..", "..", "lib", templatePath, "css", "style.css");
	return fs.readFileSync(filepath, "utf8").replace(/\r\n|\r/g, "\n");
}

export function getInjectedContents(baseDir: string, injects: string[]): string[] {
	let injectedContents: string[] = [];
	for (let i = 0; i < injects.length; i++) {
		const filePath = path.join(baseDir, injects[i]);
		if (fs.statSync(filePath).isDirectory()) {
			injectedContents = injectedContents.concat(getFileContentsFromDirectory(filePath));
		} else {
			injectedContents.push(fs.readFileSync(filePath, "utf8").replace(/\r\n|\r/g, "\n"));
		}
	}
	return injectedContents;
}

export function readSandboxConfigJs(sourceDir: string): string {
	const sandboxConfigJsPath = path.join(sourceDir, "sandbox.config.js");
	return fs.readFileSync(sandboxConfigJsPath, "utf8").replace(/\r\n|\r/g, "\n");
}

/**
 * 指定のgameJson中の全てのImageAssetに untainted:true を付与する
 */
export function addUntaintedToImageAssets(gameJson: cmn.GameConfiguration): void {
	Object.keys(gameJson.assets).forEach(key => {
		if (gameJson.assets[key].type === "image") {
			const asset = gameJson.assets[key] as ImageAssetConfigurationBase;
			if (!asset.hint) {
				asset.hint = {};
			}
			asset.hint.untainted = true;
		}
	});
}

export function removeUntaintedHints(gameJson: cmn.GameConfiguration): void {
	for (const asset of Object.values(gameJson.assets)) {
		if (asset.type === "image" && asset.hint?.untainted) {
			delete asset.hint.untainted;
		}
	}
}

export function validateEngineFilesName(filename: string, expectedMajorVersion: string): void {
	const matches = filename.match(/(\d+)_\d+_\d+/);
	const engineFilesVersion = matches ? matches[1] : null;
	if (expectedMajorVersion !== engineFilesVersion) {
		throw new Error("Versions of environment[\"sandbox-runtime\"] in game.json and the version of engineFiles do not match."
			+ ` environment[\"sandbox-runtime\"]:${expectedMajorVersion}, engineFiles:${engineFilesVersion}`);
	}
}

export function resolveEngineFilesPath(version: string): string {
	// @akashic/headless-driver が依存している engine-files-v* を直接参照
	const headlessDriverPath = require.resolve("@akashic/headless-driver");
	const engineFilesPackageDir = path.dirname(require.resolve(`engine-files-v${version}`, {paths: [headlessDriverPath]}));
	const engineFilesPackageJson = require(`${engineFilesPackageDir}/package.json`);
	const engineFilesName = `engineFilesV${engineFilesPackageJson.version.replace(/[\.-]/g, "_")}.js`;
	return path.join(engineFilesPackageDir, `dist/raw/release/full/${engineFilesName}`);
}

export function validateSandboxConfigJs(
	conf: SandboxConfiguration,
	autoSendEventName: string | boolean,
	autoGivenArgsName: string
): void {
	if (autoSendEventName) {
		if (autoSendEventName === true) {
			autoSendEventName = conf.autoSendEventName || conf.autoSendEvents;
		}
		if (!conf.events[autoSendEventName]){
			throw  Error(`${autoSendEventName} does not exist in events in sandbox.config.js.`);
		}
	}

	if (autoGivenArgsName) {
		if (!conf.arguments[autoGivenArgsName]) {
			throw  Error(`${autoGivenArgsName} does not exist in arguments in sandbox.config.js.`);
		}
	}
}

function getFileContentsFromDirectory(inputDirPath: string): string[] {
	return fs.readdirSync(inputDirPath)
		.map(fileName => fs.readFileSync(path.join(inputDirPath, fileName), "utf8").replace(/\r\n|\r/g, "\n"));
}

function loadScriptFile(filePath: string): string {
	try {
		return fs.readFileSync(filePath, "utf8").replace(/\r\n|\r/g, "\n");
	} catch (e) {
		if (e.code === "ENOENT") {
			throw new Error(path.basename(filePath) + " is not found. Try re-install akashic-cli" + filePath);
		} else {
			throw e;
		}
	}
}

import * as fs from "fs";
import * as os from "os";
import * as path from "path";
import * as cmn from "@akashic/akashic-cli-commons";
import archiver = require("archiver"); // eslint-disable-line @typescript-eslint/no-require-imports
import { promiseConvertBundle } from "./convertBundle.js";
import { promiseConvertNoBundle } from "./convertNoBundle.js";
import type { ConvertTemplateParameterObject } from "./convertUtil.js";
import * as Utils from "./Utils.js";

export interface ExportHTMLParameterObject extends ConvertTemplateParameterObject {
	quiet?: boolean;
	bundle?: boolean;
	hashLength?: number;
	compress?: boolean;
}

export function _completeExportHTMLParameterObject(p: ExportHTMLParameterObject): ExportHTMLParameterObject {
	const param = {...p};
	const source = param.source ? param.source : "./";
	param.source = path.resolve(param.cwd, source);
	param.output = param.output ? path.resolve(param.cwd, param.output) : undefined;
	param.logger = param.logger || new cmn.ConsoleLogger();
	return param;
}

export function promiseExportHtmlRaw(param: ExportHTMLParameterObject): Promise<string> {
	let gamepath: string;

	param.logger.info("exporting content into html...");
	if (!param.strip && param.output != null && !/^\.\./.test(path.relative(param.source, param.output))) {
		param.logger.warn("The output path overlaps with the game directory: files will be exported into the game directory.");
		param.logger.warn("NOTE that after this, exporting this game with --no-strip option may include the files.");
	}
	return new Promise<void>((resolve, reject) => {
		if (!param.output) {
			param.output = fs.mkdtempSync(path.join(os.tmpdir(), "akashic-export-html-tmp-"));
			return resolve();
		}
		fs.stat(path.resolve(param.output), (error: any, stat: any) => {
			if (error) {
				if (error.code !== "ENOENT") {
					return reject("Output directory has bad status. Error code " + error.code);
				}
				fs.mkdir(path.resolve(param.output), (err: any) => {
					if (err) {
						return reject("Create " + param.output + " directory failed.");
					}
					resolve();
				});
			} else if (stat) {
				if (!stat.isDirectory()) {
					return reject(param.output + " is not directory.");
				}
				if (!param.force) {
					return reject("The output directory " + param.output + " already exists. Cannot overwrite without force option.");
				}
				resolve();
			}
		});
	})
		.then(() => {
			if (param.hashLength === 0) return param.source;
			return createRenamedGame(param.source, param.hashLength);
		})
		.then((currentGamepath: string) => {
			gamepath = currentGamepath;
			const convertParam: ConvertTemplateParameterObject = {
				output: param.output,
				logger: param.logger,
				strip: param.strip,
				minify: param.minify,
				esDownpile: param.esDownpile,
				terser: param.terser,
				magnify: param.magnify,
				force: param.force,
				source: gamepath,
				cwd: param.cwd,
				injects: param.injects,
				unbundleText: param.unbundleText,
				exportInfo: param.exportInfo,
				autoSendEventName: param.autoSendEventName,
				autoGivenArgsName: param.autoGivenArgsName,
				debugOverrideEngineFiles: param.debugOverrideEngineFiles
			};
			if (param.bundle) {
				return promiseConvertBundle(convertParam);
			} else {
				return promiseConvertNoBundle(convertParam);
			}
		})
		.then(() => {
			// ハッシュ化した場合一時ファイルが生成されるため削除する
			if (param.hashLength > 0) {
				param.logger.info("removing temp files...");
				fs.rmSync(gamepath, { recursive: true });
			}
		})
		.catch((error) => {
			throw error;
		})
		.then(() => {
			return param.output;
		});
}

export function promiseExportHTML(p: ExportHTMLParameterObject): Promise<string> {
	const param = _completeExportHTMLParameterObject(p);
	const output = param.output;
	if (param.compress) {
		// promiseExportHtmlRaw() で一時ディレクトリを作成させるため、param.output に null を代入
		param.output = null;
	}
	return promiseExportHtmlRaw(param)
		.then((dest: string) => {
			if (param.compress) {
				return new Promise<void>((resolve, reject) => {
					const files = cmn.Util.readdirRecursive(dest).map(p => ({
						src: path.resolve(dest, p),
						entryName: p
					}));
					const ostream = fs.createWriteStream(output);
					const archive = archiver("zip");
					ostream.on("close", () => resolve());
					archive.on("error", (err) => reject(err));
					archive.pipe(ostream);
					files.forEach((f) => archive.file(f.src, { name: f.entryName }));
					return archive.finalize();
				}).finally(() => {
					fs.rmSync(dest, { recursive: true });
				});
			}
		})
		.then(() => {
			return param.compress ? output : param.output;
		});
}

export function exportHTML(param: ExportHTMLParameterObject, cb: (err?: any) => void): void {
	promiseExportHTML(param).then<void>(cb).catch(cb);
}

async function createRenamedGame(sourcePath: string, hashLength: number): Promise<string> {
	const destDirPath = path.resolve(fs.mkdtempSync(path.join(os.tmpdir(), "akashic-export-html-")));
	if (fs.existsSync(path.resolve(sourcePath, "sandbox.config.js"))) {
		fs.copyFileSync(path.resolve(sourcePath, "sandbox.config.js"), path.resolve(destDirPath, "sandbox.config.js"));
	}
	Utils.copyContentFiles(sourcePath, destDirPath);

	const gamejson = await cmn.FileSystem.readJSON<cmn.GameConfiguration>(path.join(destDirPath, "game.json"));
	cmn.Renamer.renameAssetFilenames(gamejson, destDirPath, hashLength);
	await cmn.FileSystem.writeJSON<cmn.GameConfiguration>(path.resolve(path.join(destDirPath, "game.json")), gamejson);
	return destDirPath;
}

import * as apiUtil from "../apiUtil.js";

describe("apiUtil", function () {
	describe("getFromHttps", function () {
		it("can get resource with https-protocol", () => {
			return Promise.resolve()
				.then(function () {
					return apiUtil.getFromHttps(
						"https://raw.githubusercontent.com/akashic-games/akashic-cli-export-html/master/package.json"
					);
				})
				.then(function (data: string): void {
					const jsonData = JSON.parse(data);
					expect(jsonData.name).toBe("@akashic/akashic-cli-export-html");
					expect(jsonData.version).toMatch(/^\d+\.\d+\.\d+$/);
				});
		});
		it("can not get resource with protocol other than https", () => {
			return Promise.resolve()
				.then(function () {
					return apiUtil.getFromHttps("http://akashic-games.github.io/notfound");
				})
				.then(function () {
					return Promise.reject();
				})
				.catch(function (err: any) {
					expect(err.message).toBe("Protocol \"http:\" not supported. Expected \"https:\"");
				});
		});
		it("throw error when http-status-code is over 400", () => {
			return Promise.resolve()
				.then(function () {
					return apiUtil.getFromHttps("https://akashic-games.github.io/notfound");
				})
				.then(function () {
					return Promise.reject();
				})
