import * as fs from "fs";
import { ConsoleLogger } from "./ConsoleLogger.js";
import type { GameConfiguration } from "./GameConfiguration.js";
import type { Logger } from "./Logger.js";

export interface ConfigurationParameterObject {
	content: GameConfiguration;
	logger?: Logger;
}

export class Configuration {
	_content: GameConfiguration;
	_logger: Logger;

	constructor(param: ConfigurationParameterObject) {
		this._content = param.content;
		this._logger = param.logger || new ConsoleLogger();
	}

	getContent(): GameConfiguration {
		return this._content;
	}

	vacuumGlobalScripts(): void {
		this._content.globalScripts = this._content.globalScripts?.filter((filePath) => {
			try {
				// v6.3.0未満のv6系ではfs.constantsが存在していないためfs.F_OKを使えるようにする必要がある。また、fsにF_OKの型定義はないのでanyに変換する必要もある。
				const fOk = fs.constants === undefined ? (fs as any).F_OK : fs.constants.F_OK;
				fs.accessSync(filePath, fOk);
			} catch (err) {
				if (err.code === "ENOENT") {
					return false;
				} else {
					throw err;
				}
			}
			return true;
		});
	}
}

import type { Logger } from "./Logger.js";

/**
 * `ConsoleLogger` のコンストラクタに指定できる引数の型。
 */
export interface ConsoleLoggerParameterObject {
	/**
	 * ログ出力量を抑えるか否か。
	 * 真の場合、 `info()` の呼び出しは無視される。
	 * 省略された場合、偽。
	 */
	quiet?: boolean;

	/**
	 * デバッグ用: ログ出力を行う関数。
	 * 省略された場合、 `console.log.bind(console)` 。
	 */
	debugLogMethod?: (msg: any) => void;
}

/**
 * ログを `console` に出力するロガー。
 */
export class ConsoleLogger implements Logger {
	quiet: boolean;
	_log: (msg: any) => void;

	constructor(param: ConsoleLoggerParameterObject = {}) {
		this.quiet = !!param.quiet;
		this._log = param.debugLogMethod || console.log.bind(console);
	}

	/**
	 * 任意の文字列を記録する。
	 * @param message 記録するメッセージ
	 */
	print(message: string): void {
		this._log(message);
	}

	/**
	 * エラーを記録する。
	 * @param message 記録するメッセージ
	 * @param cause エラーの原因
	 */
	error(message: string, cause?: any): void {
		this.print("ERROR: " + message);
		if (cause)
			this.print(cause);
	}

	/**
	 * 警告を記録する。
	 * @param message 記録するメッセージ
	 * @param cause 警告の原因
	 */
	warn(message: string, cause?: any): void {
		this.print("WARN: " + message);
		if (cause)
			this.print(cause);
	}

	/**
	 * 情報を記録する。
	 * @param message 記録するメッセージ
	 * @param cause 情報の原因
	 */
	info(message: string, cause?: any): void {
		if (this.quiet)
			return;
		this.print("INFO: " + message);
		if (cause)
			this.print(cause);
	}
}

