import * as fs from "fs";
import * as path from "path";
import type { ModuleMainPathsMap, ModuleMainScriptsMap } from "@akashic/game-configuration";
import browserify from "browserify";
import { ConsoleLogger } from "./ConsoleLogger.js";
import type { Logger } from "./Logger.js";
import { StringStream } from "./StringStream.js";
import * as Util from "./Util.js";

interface ModuleMainInfo {
	moduleName: string;
	mainScriptPath: string;
}

export module NodeModules {
	export function listModuleFiles(basepath: string, modules: string|string[], logger: Logger = new ConsoleLogger()): Promise<string[]> {
		if (modules.length === 0) return Promise.resolve([]);
		return Promise.resolve()
			.then(() => NodeModules.listScriptFiles(basepath, modules, logger))
			.then((paths) => paths.concat(NodeModules.listPackageJsonsFromScriptsPath(basepath, paths)));
	}

	export function listPackageJsonsFromScriptsPath(basepath: string, filepaths: string[]): string[] {
		const packageJsonPaths: string[] = [];
		const alreadyProcessed: { [path: string]: boolean } = {};
		filepaths.forEach((filepath: string) => {
			const m = /(.*node_modules\/(?:@.*?\/)?(?:.*?)\/)/.exec(filepath);
			if (!m)
				return;
			const dirPath = m[1];
			if (alreadyProcessed[dirPath])
				return;
			alreadyProcessed[dirPath] = true;

			const packageJsonPath = Util.makeUnixPath(path.join(basepath, dirPath, "package.json"));
			try {
				if (!fs.lstatSync(packageJsonPath).isFile()) return;
				packageJsonPaths.push(Util.makeUnixPath(path.relative(basepath, packageJsonPath)));
			} catch (_e) { /* nothing */ }
		});
		return packageJsonPaths;
	}

	export function listModuleMainScripts(packageJsonFiles: string[]): ModuleMainScriptsMap {
		if (packageJsonFiles.length === 0) return {};
		const moduleMainScripts: ModuleMainScriptsMap = {};

		for (let i = 0; i < packageJsonFiles.length; i++) {
			const packageJsonFile = packageJsonFiles[i];
			try {
				const { mainScriptPath, moduleName } = NodeModules.extractModuleMainInfo(packageJsonFile);
				moduleMainScripts[moduleName] = Util.makeUnixPath(mainScriptPath);
			} catch (_e) {
				// do nothing
			}
		}
		return moduleMainScripts;
	}

	export function listModuleMainPaths(packageJsonFiles: string[]): ModuleMainPathsMap {
		if (packageJsonFiles.length === 0) return {};
		const moduleMainPaths: ModuleMainPathsMap = {};

		for (let i = 0; i < packageJsonFiles.length; i++) {
			const packageJsonFile = packageJsonFiles[i];
			try {
				const { mainScriptPath } = NodeModules.extractModuleMainInfo(packageJsonFile);
				moduleMainPaths[packageJsonFile] = Util.makeUnixPath(mainScriptPath);
			} catch (_e) {
				// do nothing
			}
		}
		return moduleMainPaths;
	}

	export function extractModuleMainInfo(packageJsonPath: string): ModuleMainInfo {
		const packageJsonData = fs.readFileSync(packageJsonPath).toString("utf-8");
		const d = JSON.parse(packageJsonData);
		const paths = [path.join(path.dirname(packageJsonPath))];
		const basedir = packageJsonPath;
		let mainScriptPath = Util.requireResolve(d.name, { paths, basedir });
		if (!mainScriptPath) {
			throw new Error(`No ${d.name} in node_modules`);
		}
		mainScriptPath = mainScriptPath.replace(path.resolve(".") + path.sep, "");
		return { moduleName: d.name, mainScriptPath };
	}

	// TODO: node_modules/ 以下以外でも利用するメソッドのため、NodeModules ではなく別の適切な場所に移動する
	// checkAllModules は実験的なものです。 akashic-cli の外部から利用しないでください
	export function listScriptFiles(
		basepath: string,
		modules: string|string[],
		logger: Logger,
		checkAllModules: boolean = false
	): Promise<string[]> {
		if (modules.length === 0) return Promise.resolve([]);
		const moduleNames = (typeof modules === "string") ? [modules] : modules;

		// moduleNamesをrequireするだけのソースコード文字列を作って依存性解析の基点にする
		// (moduleNamesを直接b.require()してもよいはずだが、そうするとモジュールのエントリポイントの代わりに
		// モジュールの名前(ディレクトリ名であることが多い)が出力されてしまうので避ける)
		const dummyRootName = "__akashic-cli_dummy_require_root.js";
		const dummyRootPath = path.join(basepath, dummyRootName);
		const rootRequirer = moduleNames.map((name: string) => {
			return "require(\"" + Util.makeModuleNameNoVer(name) + "\");";
		}).join("\n");

		// akashicコンテンツが Node.js のコアモジュールを参照するモジュールに依存している場合、
		// akashic-cli-commons/node_modules 以下への依存として表現される。
		// これを検知した場合、そのモジュールへの依存はgame.jsonに追記せず、akashicコマンドユーザには警告を表示する。
		const ignoreModulePaths = ["/akashic-cli-commons/node_modules/"];

		// builtins (コアモジュール) を有効にすると browserify が polyfill したモジュールが b.on("dep", ...) で検出される。
		// したがってここでは false を指定してコアモジュールの読み込みを禁止する。
		const builtins = false;

		const b = browserify({
			entries: new StringStream(rootRequirer, dummyRootPath),
			basedir: basepath,
			preserveSymlinks: true, // npm link で node_modules 以下に置かれたモジュールを symlink パスのまま扱う
			builtins,
		});
		b.external("g");

		return new Promise<string[]>((resolve, reject) => {
			const filePaths: string[] = [];
			b.on("dep", (row: any) => {
				const filePath = Util.makeUnixPath(path.relative(basepath, row.file));
				if (filePath === dummyRootName || (!checkAllModules && !(/^(?:\.\/)?node_modules/.test(filePath)))) {
					return;
				}
				if (/^\.\.\//.test(filePath)) {
					const rawFilePath = Util.makeUnixPath(row.file);
					if (ignoreModulePaths.find((modulePath) => rawFilePath.includes(modulePath))) {
						const detectedModuleName = path.basename(path.dirname(filePath));
						const msg = "Reference to '" + detectedModuleName
							+ "' is detected and skipped listing."
							+ " Akashic content cannot depend on core modules of Node.js."
							+ " You should build your game runnable without '" + detectedModuleName + "'.";
						logger.warn(msg);
						return;
					}
					const msg = "Unsupported module found in " + JSON.stringify(modules)
												+ ". Skipped listing '" + filePath
												+ "' that cannot be dealt with. (This may be a core module of Node.js)";
					reject(new Error(msg));
					return;
				}
				filePaths.push(filePath);
			});
			b.bundle((err: any) => {
				void (err ? reject(err) : resolve(filePaths));
			});
		});
	}
}

import { exec } from "child_process";
import { ConsoleLogger } from "./ConsoleLogger.js";
import type { Logger } from "./Logger.js";

export interface PromisedNpmParameterObject {
	logger?: Logger;
}

export interface NpmLsResultObject {
	dependencies?: {[key: string]: NpmLsResultObject};
}

export class PromisedNpm {
	_logger: Logger;

	constructor(param: PromisedNpmParameterObject) {
		this._logger = param.logger || new ConsoleLogger();
	}

	install(moduleNames: string[] = []): Promise<void> {
		return new Promise<void>((resolve, reject) => {
			this._logger.info("Installing " + moduleNames + "...");
			exec("npm install --save " + moduleNames.join(" "), (err: any) => {
				void (err ? reject(err) : resolve());
			});
		});
	}

	link(moduleNames: string[] = []): Promise<void> {
		return new Promise<void>((resolve, reject) => {
			this._logger.info("Linking " + moduleNames + "...");
			exec("npm link " + moduleNames.join(" "), (err: any) => {
				void (err ? reject(err) : resolve());
			});
		});
	}

	uninstall(moduleNames: string[] = []): Promise<void> {
		return new Promise<void>((resolve, reject) => {
			this._logger.info("Uninstalling " + moduleNames + "...");
			exec("npm uninstall --save " + moduleNames.join(" "), (err: any) => {
				void (err ? reject(err) : resolve());
			});
		});
	}

	unlink(moduleNames: string[] = []): Promise<void> {
		return new Promise<void>((resolve, reject) => {
			this._logger.info("Unlinking " + moduleNames + "...");
			exec("npm unlink " + moduleNames.join(" "), (err: any) => {
				void (err ? reject(err) : resolve());
			});
		});
	}

	shrinkwrap(): Promise<void> {
		return new Promise<void>((resolve, reject) => {
			this._logger.info("Shrinkwrapping...");
			exec("npm shrinkwrap", (err: any) => {
				if (err) {
					reject(err);
				} else {
					this._logger.info("Added npm-shrinkwrap.json");
					resolve();
				}
			});
		});
	}

	ls(silent: boolean = false): Promise<NpmLsResultObject> {
		return new Promise<NpmLsResultObject>((resolve, reject) => {
			this._logger.info("Listing dependencies ...");
			exec("npm ls --json --production" + (silent ? " --silent" : ""), (err: any, stdout: string, stderr: string) => {
				if (err) {
					if (stderr.indexOf("extraneous") !== -1) {
						this._logger.error("Extraneous module found in node_modules. You must install modules using akashic-cli.");
					}
					return reject(err);
				}
				const result = JSON.parse(stdout); // npmから返るstdoutは必ずJSON形式。エラーがある場合はerrとstderrで返される。
				resolve(result);
			});
		});
	}

	update(moduleNames: string[] = []): Promise<void> {
		return new Promise<void>((resolve, reject) => {
			this._logger.info("Update dependencies ...");
			exec("npm update " + moduleNames.join(" "), (err: any) => {
				void (err ? reject(err) : resolve());
			});
		});
	}
}

import * as fs from "fs";
import * as path from "path";
import { sha256 } from "js-sha256";
import type { GameConfiguration } from "./GameConfiguration.js";
import { KNOWN_AUDIO_EXTENSIONS } from "./knownAudioExtensions.js";

export const ERROR_FILENAME_CONFLICT = "ERROR_FILENAME_CONFLICT";
export const ERROR_PATH_INCLUDE_ANCESTOR = "ERROR_PATH_INCLUDE_ANCESTOR";

/**
 * 与えられたファイルパスのファイル名部分を、ファイルパスから計算したハッシュ値で置き換え、 files/ 以下のファイルパスにして返す
 * @param filepath 変換するファイルパス
 * @param nameLength ファイル名の文字数の最大値
 */
export function hashFilepath(filepath: string, nameLength: number): string {
	const hashedFilename = sha256(filepath).slice(0, nameLength);
	const extname = path.extname(filepath);
	return path.posix.join("files", hashedFilename + extname);
}

/**
 * アセット・ globalScripts のファイル名をファイルパスに基づいてハッシュ化し、アセットファイル名をリネームする
 * @param content 読み込む game.json
 * @param basedir 読み込む gamejson が置かれているパス
 * @param maxHashLength ハッシュ化後のファイル名の文字数の最大値。省略された場合、20文字
 */
export function renameAssetFilenames(content: GameConfiguration, basedir: string, maxHashLength: number = 20): void {
	const processedAssetPaths: Map<string, string> = new Map();
	_renameAssets(content, basedir, maxHashLength, processedAssetPaths);
	_renameGlobalScripts(content, processedAssetPaths, basedir, maxHashLength);
}

/**
 * 指定されたファイルをリネームする
 * @param basedir リネームするファイルが置かれているパス
 * @param filePath リネームするファイルのパス
 * @param newFilePath リネームされたファイルのパス
 */
function _renameFilename(basedir: string, filePath: string, newFilePath: string): void {
	try {
		fs.accessSync(path.resolve(basedir, newFilePath));
	} catch (error) {
		if (error.code === "ENOENT") {
			fs.mkdirSync(path.dirname(path.resolve(basedir, newFilePath)), { recursive: true });
			fs.renameSync(path.resolve(basedir, filePath), path.resolve(basedir, newFilePath));
			return;
		}
		throw error;
	}
	throw new Error(ERROR_FILENAME_CONFLICT);
}

function _renameAudioFilename(basedir: string, filePath: string, newFilePath: string): void {
	KNOWN_AUDIO_EXTENSIONS.forEach((ext) => {
		try {
			fs.accessSync(path.resolve(basedir, filePath + ext));
			_renameFilename(basedir, filePath + ext, newFilePath + ext);
		} catch (error) {
			if (error.code === "ENOENT") return; // 全てのオーディオ拡張子が揃っているとは限らない
			throw error;
		}
	});
}

function _renameAssets(content: GameConfiguration, basedir: string, maxHashLength: number, processedAssetPaths: Map<string, string>): void {
	const assetNames = Object.keys(content.assets);
	const dirpaths: string[] = [];
	assetNames.forEach((name) => {
		const filePath = content.assets[name].path;
		dirpaths.push(path.dirname(filePath));
		const hashedFilePath = hashFilepath(filePath, maxHashLength);
		const isRenamedAsset = processedAssetPaths.has(hashedFilePath);

		content.assets[name].path = hashedFilePath;
		content.assets[name].virtualPath = content.assets[name].virtualPath ?? filePath;
		processedAssetPaths.set(hashedFilePath, name);
		if (isRenamedAsset) return; // 同じパスのアセットを既にハッシュ化済みの場合、ファイルはリネーム済み
		if (content.assets[name].type !== "audio") {
			_renameFilename(basedir, filePath, hashedFilePath);
		} else {
			_renameAudioFilename(basedir, filePath, hashedFilePath);
		}
	});
	const assetAncestorDirs = _listAncestorDirNames(dirpaths);
	_removeDirectoryIfEmpty(assetAncestorDirs, basedir);
}

function _renameGlobalScripts(
	content: GameConfiguration,
	processedAssetPaths: Map<string, string>,
	basedir: string,
	maxHashLength: number
): void {
	if (content.globalScripts) {
		content.globalScripts.forEach((name: string, idx: number) => {
			const assetname = "a_e_z_" + idx;
			const hashedFilePath = hashFilepath(name, maxHashLength);
			const isRenamedAsset = processedAssetPaths.has(hashedFilePath);

			if (isRenamedAsset) {
				const assetId = processedAssetPaths.get(hashedFilePath)!;
				if (!content.assets[assetId].global) {
					// 対象 assset が global:true でなければ書き換える
					content.assets[assetId].global = true;
				}
				return; // asset にハッシュ化済みの同パスがある場合はスキップ
			}

			content.assets[assetname] = {
				type: /\.json$/i.test(name) ? "text" : "script",
				virtualPath: name,
				path: hashedFilePath,
				global: true
			};
			processedAssetPaths.set(hashedFilePath, assetname);
			_renameFilename(basedir, name, hashedFilePath);
		});

		const assetDirs = _listAncestorDirNames(content.globalScripts.map((filepath) => path.dirname(filepath)));
		_removeDirectoryIfEmpty(assetDirs, basedir);
	}
	content.globalScripts = [];
}

export function _removeDirectoryIfEmpty(dirpaths: string[], basedir: string): void {
	// パス文字列長でソートすることで、空ディレクトリしかないツリーでも末端から削除できるようにする
	dirpaths.sort((a, b) => (b.length - a.length));
	dirpaths.forEach((dirpath) => {
		const dirFullPath = path.resolve(basedir, dirpath);
		if (/^\.\./.test(path.relative(basedir, dirFullPath))) throw new Error(ERROR_PATH_INCLUDE_ANCESTOR);
		try {
			fs.accessSync(dirFullPath);
			fs.rmdirSync(dirFullPath);
		} catch (error) {
			if (["ENOENT", "EEXIST", "ENOTEMPTY"].indexOf(error.code) !== -1) return;
			throw error;
		}
	});
}

/**
 * ディレクトリの相対パスを受け取り、そのパス内で表現されているもっとも祖先にあたるディレクトリまでの各祖先ディレクトリをリストで返す
 */
export function _listAncestorDirNames(dirpaths: string[]): string[] {
	const result: Set<string> = new Set();
	dirpaths.forEach((dirpath) => {
		let currentDir = path.normalize(dirpath);
		while (currentDir.indexOf(path.sep) !== -1) {
			result.add(currentDir);
			currentDir = path.dirname(currentDir);
		}
		// path.normalizeによって `./` が消えるためwhile中で拾えないrootパスをaddする
		if (currentDir !== "..") result.add(currentDir);
	});
	return  Array.from(new Set(result));
}

import * as stream from "stream";

export class StringStream extends stream.Readable {
	content: string;
	file: string | undefined;;

	constructor (content: string, fileName?: string) {
		super();
		this.content = content;
		this.file = fileName;
	}

	_read(size: number): void {
		if (!this.content) {
			this.push(null);
		} else {
			this.push(this.content.slice(0, size));
			this.content = this.content.slice(size);
		}
	}
}

