		]);
		expect(arr.map((v) => Renamer.hashFilepath(v, 5))).toEqual([
			"files/04ef2.js",
			"files/825a5.js",
			"files/a7084.png"
		]);
	});

	describe(".hashFilePaths()", () => {
		beforeEach(() => {
			mockfs({
				srcDir: {
					"game.json": JSON.stringify({
						main: "./script/mainScene",
						assets: {
							mainScene: {
								type: "script",
